pub(super) async fn feishu_drive_update_comment_reaction(
    client: &reqwest::Client,
    settings: &FeishuSettings,
    payload: &Value,
) -> AppResult<Value> {
    let file_token = required_string_arg(
        payload,
        &["file_token", "fileToken"],
        "feishu_drive_update_comment_reaction",
    )?;
    let reply_id = required_string_arg(
        payload,
        &["reply_id", "replyId"],
        "feishu_drive_update_comment_reaction",
    )?;
    let file_type =
        string_arg(payload, &["file_type", "fileType"]).unwrap_or_else(|| "docx".into());
    let action = string_arg(payload, &["action"])
        .unwrap_or_else(|| "add".into())
        .trim()
        .to_ascii_lowercase();
    if !matches!(action.as_str(), "add" | "delete") {
        return Err(AppError::BadRequest(
            "feishu_drive_update_comment_reaction action must be add or delete".into(),
        ));
    }
    let reaction_type =
        string_arg(payload, &["reaction_type", "reactionType"]).unwrap_or_else(|| "OK".into());
    let body = json!({
        "action": action,
        "reply_id": reply_id,
        "reaction_type": reaction_type,
    });
    feishu_request(
        client,
        settings,
        "POST",
        &format!(
            "/open-apis/drive/v2/files/{}/comments/reaction",
            percent_encode_path_segment(&file_token)
        ),
        &[("file_type".to_string(), file_type)],
        Some(body),
        "Feishu comment reaction update",
    )
    .await
}

