fn messaging_gateway_adapter_autostart_enabled(config: &Value) -> bool {
    let enabled = config
        .get("enabled")
        .and_then(Value::as_bool)
        .or_else(|| matrix_env_bool("HERMES_MESSAGING_GATEWAY_ENABLED"))
        .unwrap_or(false);
    let autostart = config
        .get("autoStart")
        .or_else(|| config.get("auto_start"))
        .and_then(Value::as_bool)
        .or_else(|| matrix_env_bool("HERMES_MESSAGING_GATEWAY_AUTO_START"))
        .unwrap_or(true);
    enabled && autostart && messaging_gateway_receive_configured(config)
}

fn api_server_adapter_autostart_enabled(config: &crate::models::AppConfig) -> bool {
    let api_config = api_server_config(config);
    let enabled = api_config
        .get("enabled")
        .and_then(Value::as_bool)
        .unwrap_or(false);
    let autostart = api_config
        .get("autoStart")
        .or_else(|| api_config.get("auto_start"))
        .and_then(Value::as_bool)
        .unwrap_or(true);
    enabled && autostart
}

