fn webhook_configured(config: &Value) -> bool {
    webhook_settings(config).is_ok()
}

fn webhook_settings(config: &Value) -> AppResult<WebhookSettings> {
    let host = string_arg(config, &["host", "bindHost", "bind_host"])
        .or_else(|| std::env::var("WEBHOOK_HOST").ok())
        .unwrap_or_else(|| "127.0.0.1".into())
        .trim()
        .to_string();
    if host.is_empty() {
        return Err(AppError::BadRequest("Webhook host cannot be empty".into()));
    }
    let port = config
        .get("port")
        .and_then(Value::as_u64)
        .or_else(|| {
            std::env::var("WEBHOOK_PORT")
                .ok()
                .and_then(|value| value.trim().parse::<u64>().ok())
        })
        .unwrap_or(8787)
        .clamp(1, u16::MAX as u64) as u16;
    let mut path = string_arg(config, &["path", "webhookPath", "webhook_path"])
        .or_else(|| std::env::var("WEBHOOK_PATH").ok())
        .unwrap_or_else(|| "/webhooks/synthchat".into())
        .trim()
        .to_string();
    if !path.starts_with('/') {
        path.insert(0, '/');
    }
    let secret = string_arg(config, &["secret", "webhookSecret", "webhook_secret"])
        .or_else(|| std::env::var("WEBHOOK_SECRET").ok())
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty());
    let timeout_seconds = config
        .get("timeoutSeconds")
        .or_else(|| config.get("timeout_seconds"))
        .and_then(Value::as_u64)
        .unwrap_or(30)
        .clamp(1, 300);
    Ok(WebhookSettings {
        host,
        port,
        path,
        secret,
        timeout_seconds,
    })
}

async fn webhook_adapter_loop(
    app: AppHandle,
    store: AppStore,
    settings: WebhookSettings,
    listener: TcpListener,
    listen_url: String,
) {
    if let Ok(state) = store.update_webhook_adapter_state(
        Some("running"),
        Some(json!({"type": "listening", "listenUrl": listen_url})),
        None,
        0,
        0,
    ) {
        emit_platform_adapter_event(&app, "connected", "webhook", &state);
    }
    loop {
        match listener.accept().await {
            Ok((stream, _addr)) => {
                let app_for_task = app.clone();
                let store_for_task = store.clone();
                let settings_for_task = settings.clone();
                tokio::spawn(async move {
                    let _ = webhook_handle_connection(
                        app_for_task,
                        store_for_task,
                        settings_for_task,
                        stream,
                    )
                    .await;
                });
            }
            Err(error) => {
                if let Ok(state) = store.update_webhook_adapter_state(
                    Some("reconnecting"),
                    None,
                    Some(format!("Webhook accept failed: {error}")),
                    0,
                    0,
                ) {
                    emit_platform_adapter_event(&app, "reconnecting", "webhook", &state);
                }
                tokio::time::sleep(Duration::from_secs(1)).await;
            }
        }
    }
}

fn api_server_config(config: &crate::models::AppConfig) -> Value {
    config
        .messaging_gateway
        .get("apiServer")
        .or_else(|| config.messaging_gateway.get("api_server"))
        .cloned()
        .unwrap_or_else(|| json!({}))
}

pub(super) fn api_server_settings(
    config: &crate::models::AppConfig,
) -> AppResult<ApiServerSettings> {
    let api_config = api_server_config(config);
    let host = string_arg(&api_config, &["host", "bindHost", "bind_host"])
        .unwrap_or_else(|| "127.0.0.1".into());
    let port = api_config
        .get("port")
        .or_else(|| api_config.get("bindPort"))
        .or_else(|| api_config.get("bind_port"))
        .and_then(Value::as_u64)
        .unwrap_or(8642);
    let port = u16::try_from(port)
        .map_err(|_| AppError::BadRequest("api_server port must fit in u16".into()))?;
    let api_key = string_arg(&api_config, &["key", "apiKey", "api_key"])
        .filter(|value| !value.trim().is_empty());
    let model_name = string_arg(&api_config, &["modelName", "model_name", "model"])
        .filter(|value| !value.trim().is_empty())
        .unwrap_or_else(|| "synthchat-agent".into());
    let timeout_seconds = api_config
        .get("timeoutSeconds")
        .or_else(|| api_config.get("timeout_seconds"))
        .and_then(Value::as_u64)
        .unwrap_or(30)
        .max(1);
    Ok(ApiServerSettings {
        host,
        port,
        api_key,
        model_name,
        timeout_seconds,
    })
}

async fn api_server_adapter_loop(
    app: AppHandle,
    store: AppStore,
    settings: ApiServerSettings,
    listener: TcpListener,
    listen_url: String,
) {
    if let Ok(state) = store.update_api_server_adapter_state(
        Some("running"),
        Some(json!({"type": "listening", "listenUrl": listen_url, "nativeChatCompletions": true})),
        None,
        0,
        0,
    ) {
        emit_platform_adapter_event(&app, "running", "api_server", &state);
    }
    loop {
        match listener.accept().await {
            Ok((stream, _)) => {
                let app_for_task = app.clone();
                let store_for_task = store.clone();
                let settings_for_task = settings.clone();
                tokio::spawn(async move {
                    if let Err(error) = api_server_handle_connection(
                        app_for_task,
                        store_for_task,
                        settings_for_task,
                        stream,
                    )
                    .await
                    {
                        // Per-request failures are reported in the HTTP response path when possible.
                        eprintln!("api_server request failed: {error}");
                    }
                });
            }
            Err(error) => {
                if let Ok(state) = store.update_api_server_adapter_state(
                    Some("error"),
                    None,
                    Some(error.to_string()),
                    0,
                    0,
                ) {
                    emit_platform_adapter_event(&app, "error", "api_server", &state);
                }
                tokio::time::sleep(Duration::from_secs(1)).await;
            }
        }
    }
}

async fn api_server_handle_connection(
    app: AppHandle,
    store: AppStore,
    settings: ApiServerSettings,
    mut stream: TcpStream,
) -> AppResult<()> {
    let mut buffer = vec![0_u8; 1024 * 1024];
    let read = tokio::time::timeout(
        Duration::from_secs(settings.timeout_seconds),
        stream.read(&mut buffer),
    )
    .await
    .map_err(|_| AppError::BadRequest("API server request read timed out".into()))?
    .map_err(|error| AppError::BadRequest(format!("API server request read failed: {error}")))?;
    let request = String::from_utf8_lossy(&buffer[..read]).to_string();
    let parsed = webhook_parse_request(&request);
    if let Ok(parsed) = parsed.as_ref() {
        if api_server_request_wants_chat_tab_websocket(parsed)? {
            match api_server_write_chat_tab_websocket_boundary(
                &store,
                &settings,
                parsed.clone(),
                &mut stream,
            )
            .await
            {
                Ok(()) => {
                    let state = store.update_api_server_adapter_state(
                        Some("running"),
                        Some(json!({"type": "request", "ok": true, "streaming": true, "surface": "chat_tab_websocket_boundary"})),
                        None,
                        1,
                        0,
                    )?;
                    emit_platform_adapter_event(&app, "request", "api_server", &state);
                    return Ok(());
                }
                Err(error) => {
                    let error_text = error.to_string();
                    let state = store.update_api_server_adapter_state(
                        Some("running"),
                        Some(json!({"type": "request", "ok": false, "streaming": true, "surface": "chat_tab_websocket_boundary", "error": error_text.clone()})),
                        None,
                        1,
                        0,
                    )?;
                    emit_platform_adapter_event(&app, "request_error", "api_server", &state);
                    let response = ApiServerHttpResponse::Json {
                        status: 400,
                        body: api_server_error(&error_text, "invalid_request_error"),
                    }
                    .to_http();
                    stream.write_all(&response).await.map_err(|error| {
                        AppError::BadRequest(format!("API server response write failed: {error}"))
                    })?;
                    return Ok(());
                }
            }
        }
        if api_server_request_wants_kanban_events_websocket(parsed)? {
            match api_server_write_kanban_events_websocket(
                &store,
                &settings,
                parsed.clone(),
                &mut stream,
            )
            .await
            {
                Ok(()) => {
                    let state = store.update_api_server_adapter_state(
                        Some("running"),
                        Some(json!({"type": "request", "ok": true, "streaming": true, "surface": "kanban_events_websocket"})),
                        None,
                        1,
                        0,
                    )?;
                    emit_platform_adapter_event(&app, "request", "api_server", &state);
                    return Ok(());
                }
                Err(error) => {
                    let error_text = error.to_string();
                    let state = store.update_api_server_adapter_state(
                        Some("running"),
                        Some(json!({"type": "request", "ok": false, "streaming": true, "surface": "kanban_events_websocket", "error": error_text.clone()})),
                        None,
                        1,
                        0,
                    )?;
                    emit_platform_adapter_event(&app, "request_error", "api_server", &state);
                    let response = ApiServerHttpResponse::Json {
                        status: 400,
                        body: api_server_error(&error_text, "invalid_request_error"),
                    }
                    .to_http();
                    stream.write_all(&response).await.map_err(|error| {
                        AppError::BadRequest(format!("API server response write failed: {error}"))
                    })?;
                    return Ok(());
                }
            }
        }
        if api_server_request_wants_dashboard_plugin_websocket(parsed) {
            match api_server_write_dashboard_plugin_websocket_boundary(
                &store,
                &settings,
                parsed.clone(),
                &mut stream,
            )
            .await
            {
                Ok(()) => {
                    let state = store.update_api_server_adapter_state(
                        Some("running"),
                        Some(json!({"type": "request", "ok": true, "streaming": true, "surface": "dashboard_plugin_websocket_boundary"})),
                        None,
                        1,
                        0,
                    )?;
                    emit_platform_adapter_event(&app, "request", "api_server", &state);
                    return Ok(());
                }
                Err(error) => {
                    let error_text = error.to_string();
                    let state = store.update_api_server_adapter_state(
                        Some("running"),
                        Some(json!({"type": "request", "ok": false, "streaming": true, "surface": "dashboard_plugin_websocket_boundary", "error": error_text.clone()})),
                        None,
                        1,
                        0,
                    )?;
                    emit_platform_adapter_event(&app, "request_error", "api_server", &state);
                }
            }
        }
        if api_server_request_wants_live_chat_sse(parsed)? {
            match api_server_write_live_chat_completion_sse(
                &store,
                &settings,
                parsed.clone(),
                &mut stream,
            )
            .await
            {
                Ok(()) => {
                    let state = store.update_api_server_adapter_state(
                        Some("running"),
                        Some(json!({"type": "request", "ok": true, "streaming": true})),
                        None,
                        1,
                        0,
                    )?;
                    emit_platform_adapter_event(&app, "request", "api_server", &state);
                    return Ok(());
                }
                Err(error) => {
                    let error_text = error.to_string();
                    let state = store.update_api_server_adapter_state(
                        Some("running"),
                        Some(json!({"type": "request", "ok": false, "streaming": true, "error": error_text.clone()})),
                        None,
                        1,
                        0,
                    )?;
                    emit_platform_adapter_event(&app, "request_error", "api_server", &state);
                    let response = ApiServerHttpResponse::Json {
                        status: 400,
                        body: api_server_error(&error_text, "invalid_request_error"),
                    }
                    .to_http();
                    stream.write_all(&response).await.map_err(|error| {
                        AppError::BadRequest(format!("API server response write failed: {error}"))
                    })?;
                    return Ok(());
                }
            }
        }
        if api_server_request_wants_live_responses_sse(parsed)? {
            match api_server_write_live_responses_sse(
                &store,
                &settings,
                parsed.clone(),
                &mut stream,
            )
            .await
            {
                Ok(()) => {
                    let state = store.update_api_server_adapter_state(
                        Some("running"),
                        Some(json!({"type": "request", "ok": true, "streaming": true, "surface": "responses"})),
                        None,
                        1,
                        0,
                    )?;
                    emit_platform_adapter_event(&app, "request", "api_server", &state);
                    return Ok(());
                }
                Err(error) => {
                    let error_text = error.to_string();
                    let state = store.update_api_server_adapter_state(
                        Some("running"),
                        Some(json!({"type": "request", "ok": false, "streaming": true, "surface": "responses", "error": error_text.clone()})),
                        None,
                        1,
                        0,
                    )?;
                    emit_platform_adapter_event(&app, "request_error", "api_server", &state);
                    let response = ApiServerHttpResponse::Json {
                        status: 400,
                        body: api_server_error(&error_text, "invalid_request_error"),
                    }
                    .to_http();
                    stream.write_all(&response).await.map_err(|error| {
                        AppError::BadRequest(format!("API server response write failed: {error}"))
                    })?;
                    return Ok(());
                }
            }
        }
        if api_server_request_wants_live_session_chat_sse(parsed)? {
            match api_server_write_live_session_chat_sse(
                &store,
                &settings,
                parsed.clone(),
                &mut stream,
            )
            .await
            {
                Ok(()) => {
                    let state = store.update_api_server_adapter_state(
                        Some("running"),
                        Some(json!({"type": "request", "ok": true, "streaming": true, "surface": "session_chat"})),
                        None,
                        1,
                        0,
                    )?;
                    emit_platform_adapter_event(&app, "request", "api_server", &state);
                    return Ok(());
                }
                Err(error) => {
                    let error_text = error.to_string();
                    let state = store.update_api_server_adapter_state(
                        Some("running"),
                        Some(json!({"type": "request", "ok": false, "streaming": true, "surface": "session_chat", "error": error_text.clone()})),
                        None,
                        1,
                        0,
                    )?;
                    emit_platform_adapter_event(&app, "request_error", "api_server", &state);
                    let response = ApiServerHttpResponse::Json {
                        status: 400,
                        body: api_server_error(&error_text, "invalid_request_error"),
                    }
                    .to_http();
                    stream.write_all(&response).await.map_err(|error| {
                        AppError::BadRequest(format!("API server response write failed: {error}"))
                    })?;
                    return Ok(());
                }
            }
        }
        if api_server_request_wants_live_run_events_sse(parsed)? {
            match api_server_write_live_run_events_sse(
                &store,
                &settings,
                parsed.clone(),
                &mut stream,
            )
            .await
            {
                Ok(()) => {
                    let state = store.update_api_server_adapter_state(
                        Some("running"),
                        Some(json!({"type": "request", "ok": true, "streaming": true, "surface": "run_events"})),
                        None,
                        1,
                        0,
                    )?;
                    emit_platform_adapter_event(&app, "request", "api_server", &state);
                    return Ok(());
                }
                Err(error) => {
                    let error_text = error.to_string();
                    let state = store.update_api_server_adapter_state(
                        Some("running"),
                        Some(json!({"type": "request", "ok": false, "streaming": true, "surface": "run_events", "error": error_text.clone()})),
                        None,
                        1,
                        0,
                    )?;
                    emit_platform_adapter_event(&app, "request_error", "api_server", &state);
                    let response = ApiServerHttpResponse::Json {
                        status: 400,
                        body: api_server_error(&error_text, "invalid_request_error"),
                    }
                    .to_http();
                    stream.write_all(&response).await.map_err(|error| {
                        AppError::BadRequest(format!("API server response write failed: {error}"))
                    })?;
                    return Ok(());
                }
            }
        }
    }
    let response = match parsed {
        Ok(parsed) => {
            match api_server_process_http_request_with_app(&app, &store, &settings, parsed).await {
                Ok(response) => {
                    let state = store.update_api_server_adapter_state(
                        Some("running"),
                        Some(json!({"type": "request", "ok": true})),
                        None,
                        1,
                        0,
                    )?;
                    emit_platform_adapter_event(&app, "request", "api_server", &state);
                    response
                }
                Err(error) => {
                    let error_text = error.to_string();
                    let state = store.update_api_server_adapter_state(
                        Some("running"),
                        Some(json!({"type": "request", "ok": false, "error": error_text.clone()})),
                        None,
                        1,
                        0,
                    )?;
                    emit_platform_adapter_event(&app, "request_error", "api_server", &state);
                    ApiServerHttpResponse::Json {
                        status: 400,
                        body: api_server_error(&error_text, "invalid_request_error"),
                    }
                }
            }
        }
        Err(error) => {
            let error_text = error.to_string();
            let state = store.update_api_server_adapter_state(
                Some("running"),
                Some(json!({"type": "request", "ok": false, "error": error_text.clone()})),
                None,
                1,
                0,
            )?;
            emit_platform_adapter_event(&app, "request_error", "api_server", &state);
            ApiServerHttpResponse::Json {
                status: 400,
                body: api_server_error(&error_text, "invalid_request_error"),
            }
        }
    };
    let response = response.to_http();
    stream.write_all(&response).await.map_err(|error| {
        AppError::BadRequest(format!("API server response write failed: {error}"))
    })?;
    Ok(())
}

pub(super) enum ApiServerHttpResponse {
    Json {
        status: u16,
        body: Value,
    },
    Redirect {
        status: u16,
        location: String,
        headers: Vec<(String, String)>,
    },
    Sse {
        body: String,
    },
    Text {
        status: u16,
        content_type: String,
        body: String,
    },
    Bytes {
        status: u16,
        content_type: String,
        body: Vec<u8>,
    },
}

impl ApiServerHttpResponse {
    pub(super) fn to_http(self) -> Vec<u8> {
        match self {
            Self::Json { status, body } => {
                let body_text = body.to_string();
                let reason = match status {
                    200 => "OK",
                    202 => "Accepted",
                    400 => "Bad Request",
                    401 => "Unauthorized",
                    403 => "Forbidden",
                    404 => "Not Found",
                    429 => "Too Many Requests",
                    500 => "Internal Server Error",
                    _ => "OK",
                };
                format!(
                    "HTTP/1.1 {status} {reason}\r\nContent-Type: application/json\r\nAccess-Control-Allow-Origin: *\r\nContent-Length: {}\r\nConnection: close\r\n\r\n{}",
                    body_text.len(),
                    body_text
                )
                .into_bytes()
            }
            Self::Redirect {
                status,
                location,
                headers,
            } => {
                let reason = match status {
                    302 => "Found",
                    303 => "See Other",
                    _ => "Found",
                };
                let mut response = format!(
                    "HTTP/1.1 {status} {reason}\r\nLocation: {location}\r\nAccess-Control-Allow-Origin: *\r\nConnection: close\r\n"
                );
                for (key, value) in headers {
                    response.push_str(&key);
                    response.push_str(": ");
                    response.push_str(&value);
                    response.push_str("\r\n");
                }
                response.push_str("\r\n");
                response.into_bytes()
            }
            Self::Sse { body } => format!(
                "HTTP/1.1 200 OK\r\nContent-Type: text/event-stream\r\nCache-Control: no-cache\r\nX-Accel-Buffering: no\r\nAccess-Control-Allow-Origin: *\r\nContent-Length: {}\r\nConnection: close\r\n\r\n{}",
                body.len(),
                body
            )
            .into_bytes(),
            Self::Text {
                status,
                content_type,
                body,
            } => {
                let reason = match status {
                    200 => "OK",
                    202 => "Accepted",
                    400 => "Bad Request",
                    401 => "Unauthorized",
                    403 => "Forbidden",
                    404 => "Not Found",
                    500 => "Internal Server Error",
                    _ => "OK",
                };
                format!(
                    "HTTP/1.1 {status} {reason}\r\nContent-Type: {content_type}\r\nAccess-Control-Allow-Origin: *\r\nContent-Length: {}\r\nConnection: close\r\n\r\n{}",
                    body.len(),
                    body
                )
                .into_bytes()
            }
            Self::Bytes {
                status,
                content_type,
                body,
            } => {
                let reason = match status {
                    200 => "OK",
                    404 => "Not Found",
                    _ => "OK",
                };
                let mut response = format!(
                    "HTTP/1.1 {status} {reason}\r\nContent-Type: {content_type}\r\nCache-Control: no-store, no-cache, must-revalidate\r\nAccess-Control-Allow-Origin: *\r\nContent-Length: {}\r\nConnection: close\r\n\r\n",
                    body.len()
                )
                .into_bytes();
                response.extend_from_slice(&body);
                response
            }
        }
    }
}

pub(super) fn api_server_process_http_request<'a>(
    store: &'a AppStore,
    settings: &'a ApiServerSettings,
    request: ParsedWebhookRequest,
) -> Pin<Box<dyn Future<Output = AppResult<ApiServerHttpResponse>> + Send + 'a>> {
    api_server_process_http_request_inner(None, store, settings, request)
}

fn api_server_process_http_request_with_app<'a>(
    app: &'a AppHandle,
    store: &'a AppStore,
    settings: &'a ApiServerSettings,
    request: ParsedWebhookRequest,
) -> Pin<Box<dyn Future<Output = AppResult<ApiServerHttpResponse>> + Send + 'a>> {
    api_server_process_http_request_inner(Some(app), store, settings, request)
}

fn api_server_process_http_request_inner<'a>(
    app: Option<&'a AppHandle>,
    store: &'a AppStore,
    settings: &'a ApiServerSettings,
    request: ParsedWebhookRequest,
) -> Pin<Box<dyn Future<Output = AppResult<ApiServerHttpResponse>> + Send + 'a>> {
    Box::pin(async move {
        if api_server_request_wants_sse(&request)? {
            api_server_process_sse_request(store, settings, request)
                .await
                .map(|body| ApiServerHttpResponse::Sse { body })
        } else if api_server_request_wants_media_attachment(&request) {
            api_server_handle_media_attachment(store, &request)
        } else if api_server_request_wants_dashboard_plugin_asset(&request) {
            api_server_handle_dashboard_plugin_asset(store, &request)
        } else if api_server_request_wants_dashboard_auth_html(&request) {
            api_server_handle_dashboard_auth_html(store, &request)
        } else if api_server_request_wants_dashboard_auth_redirect(&request) {
            api_server_handle_dashboard_auth_redirect(store, &request)
        } else if api_server_request_wants_msgraph_webhook_validation(&request) {
            api_server_handle_msgraph_webhook_validation(store, &request).map(|(status, body)| {
                ApiServerHttpResponse::Text {
                    status,
                    content_type: "text/plain; charset=utf-8".into(),
                    body,
                }
            })
        } else {
            api_server_process_request_with_status_inner(app, store, settings, request)
                .await
                .map(|(status, body)| ApiServerHttpResponse::Json { status, body })
        }
    })
}

fn api_server_request_wants_live_chat_sse(request: &ParsedWebhookRequest) -> AppResult<bool> {
    let path = request.path.split('?').next().unwrap_or(&request.path);
    if request.method != "POST" || path != "/v1/chat/completions" {
        return Ok(false);
    }
    if request.body.trim().is_empty() {
        return Ok(false);
    }
    let body: Value = serde_json::from_str(&request.body)
        .map_err(|error| AppError::BadRequest(format!("Invalid JSON in request body: {error}")))?;
    Ok(api_server_value_bool(&body, "stream", false))
}

fn api_server_request_wants_live_responses_sse(request: &ParsedWebhookRequest) -> AppResult<bool> {
    let path = request.path.split('?').next().unwrap_or(&request.path);
    if request.method != "POST" || path != "/v1/responses" {
        return Ok(false);
    }
    if request.body.trim().is_empty() {
        return Ok(false);
    }
    let body: Value = serde_json::from_str(&request.body)
        .map_err(|error| AppError::BadRequest(format!("Invalid JSON in request body: {error}")))?;
    Ok(api_server_value_bool(&body, "stream", false))
}

fn api_server_request_wants_live_session_chat_sse(
    request: &ParsedWebhookRequest,
) -> AppResult<bool> {
    let path = request.path.split('?').next().unwrap_or(&request.path);
    Ok(request.method == "POST"
        && path.starts_with("/api/sessions/")
        && path.ends_with("/chat/stream"))
}

fn api_server_request_wants_live_run_events_sse(request: &ParsedWebhookRequest) -> AppResult<bool> {
    let path = request.path.split('?').next().unwrap_or(&request.path);
    Ok(request.method == "GET" && path.starts_with("/v1/runs/") && path.ends_with("/events"))
}

pub(super) fn api_server_request_wants_kanban_events_websocket(
    request: &ParsedWebhookRequest,
) -> AppResult<bool> {
    let path = request.path.split('?').next().unwrap_or(&request.path);
    let upgrade = request
        .headers
        .get("upgrade")
        .map(|value| value.eq_ignore_ascii_case("websocket"))
        .unwrap_or(false);
    Ok(request.method == "GET" && path == "/api/plugins/kanban/events" && upgrade)
}

pub(super) fn api_server_request_wants_chat_tab_websocket(
    request: &ParsedWebhookRequest,
) -> AppResult<bool> {
    let path = request.path.split('?').next().unwrap_or(&request.path);
    let upgrade = request
        .headers
        .get("upgrade")
        .map(|value| value.eq_ignore_ascii_case("websocket"))
        .unwrap_or(false);
    Ok(request.method == "GET"
        && upgrade
        && matches!(path, "/api/pty" | "/api/ws" | "/api/pub" | "/api/events"))
}

fn api_server_request_wants_dashboard_plugin_websocket(request: &ParsedWebhookRequest) -> bool {
    let path = request.path.split('?').next().unwrap_or(&request.path);
    request.method == "GET"
        && path.starts_with("/api/plugins/")
        && request
            .headers
            .get("upgrade")
            .map(|value| value.eq_ignore_ascii_case("websocket"))
            .unwrap_or(false)
}

fn api_server_write_chat_tab_websocket_boundary<'a>(
    store: &'a AppStore,
    settings: &'a ApiServerSettings,
    request: ParsedWebhookRequest,
    stream: &'a mut TcpStream,
) -> Pin<Box<dyn Future<Output = AppResult<()>> + Send + 'a>> {
    Box::pin(async move {
        let path = request.path.split('?').next().unwrap_or(&request.path);
        if path == "/api/pub" {
            return api_server_write_chat_tab_pub_websocket(settings, request, stream).await;
        }
        if path == "/api/events" {
            return api_server_write_chat_tab_events_websocket(settings, request, stream).await;
        }
        if path == "/api/ws" {
            return api_server_write_chat_tab_gateway_websocket(store, settings, request, stream)
                .await;
        }
        if path == "/api/pty" {
            return api_server_write_chat_tab_pty_websocket(store, settings, request, stream).await;
        }
        api_server_verify_websocket_auth(settings, &request)?;
        let accept = api_server_websocket_accept_key(&request)?;
        let response = format!(
            "HTTP/1.1 101 Switching Protocols\r\nUpgrade: websocket\r\nConnection: Upgrade\r\nSec-WebSocket-Accept: {accept}\r\nAccess-Control-Allow-Origin: *\r\n\r\n"
        );
        stream
            .write_all(response.as_bytes())
            .await
            .map_err(|error| {
                AppError::BadRequest(format!("API server WebSocket handshake failed: {error}"))
            })?;
        let payload = api_server_chat_tab_bridge_status(store, Some(path));
        api_server_write_websocket_text_frame(stream, &payload.to_string()).await?;
        api_server_write_websocket_close_frame(stream, 1011, "chat tab bridge unavailable").await
    })
}

async fn api_server_write_chat_tab_pty_websocket(
    store: &AppStore,
    settings: &ApiServerSettings,
    request: ParsedWebhookRequest,
    stream: &mut TcpStream,
) -> AppResult<()> {
    api_server_verify_websocket_auth(settings, &request)?;
    let accept = api_server_websocket_accept_key(&request)?;
    let response = format!(
        "HTTP/1.1 101 Switching Protocols\r\nUpgrade: websocket\r\nConnection: Upgrade\r\nSec-WebSocket-Accept: {accept}\r\nAccess-Control-Allow-Origin: *\r\n\r\n"
    );
    stream
        .write_all(response.as_bytes())
        .await
        .map_err(|error| {
            AppError::BadRequest(format!("API server WebSocket handshake failed: {error}"))
        })?;

    let query = api_server_query_params(&request.path);
    let ready = api_server_chat_tab_pty_status_payload(store, &query, Some("pty.ready"))?;
    api_server_write_websocket_text_frame(stream, &ready.to_string()).await?;

    loop {
        let Some(frame) = api_server_read_websocket_text_frame(stream).await? else {
            break;
        };
        let line = frame.trim();
        if line.is_empty() {
            continue;
        }
        let payload = api_server_chat_tab_pty_frame_response(store, &query, line)?;
        api_server_write_websocket_text_frame(stream, &payload.to_string()).await?;
    }
    Ok(())
}

async fn api_server_write_chat_tab_gateway_websocket(
    store: &AppStore,
    settings: &ApiServerSettings,
    request: ParsedWebhookRequest,
    stream: &mut TcpStream,
) -> AppResult<()> {
    api_server_verify_websocket_auth(settings, &request)?;
    let accept = api_server_websocket_accept_key(&request)?;
    let response = format!(
        "HTTP/1.1 101 Switching Protocols\r\nUpgrade: websocket\r\nConnection: Upgrade\r\nSec-WebSocket-Accept: {accept}\r\nAccess-Control-Allow-Origin: *\r\n\r\n"
    );
    stream
        .write_all(response.as_bytes())
        .await
        .map_err(|error| {
            AppError::BadRequest(format!("API server WebSocket handshake failed: {error}"))
        })?;
    let ready = json!({
        "jsonrpc": "2.0",
        "method": "event",
        "params": {
            "type": "gateway.ready",
            "payload": api_server_chat_tab_gateway_ready_payload(store)
        }
    });
    api_server_write_websocket_text_frame(stream, &ready.to_string()).await?;
    loop {
        let Some(frame) = api_server_read_websocket_text_frame(stream).await? else {
            break;
        };
        let line = frame.trim();
        if line.is_empty() {
            continue;
        }
        let response = match serde_json::from_str::<Value>(line) {
            Ok(request)
                if request
                    .get("method")
                    .and_then(Value::as_str)
                    .is_some_and(api_server_chat_tab_gateway_method_requires_async_control) =>
            {
                api_server_chat_tab_gateway_dispatch_prompt_submit_websocket(
                    store, settings, &request, stream,
                )
                .await?
            }
            Ok(request) => api_server_chat_tab_gateway_dispatch(store, settings, &request),
            Err(_) => api_server_json_rpc_error(Value::Null, -32700, "parse error"),
        };
        if !response.is_null() {
            api_server_write_websocket_text_frame(stream, &response.to_string()).await?;
        }
    }
    Ok(())
}

pub(super) fn api_server_chat_tab_gateway_method_requires_async_control(method: &str) -> bool {
    matches!(
        method,
        "prompt.submit"
            | "slash.exec"
            | "command.dispatch"
            | "session.compress"
            | "approval.respond"
            | "sudo.respond"
            | "secret.respond"
            | "clarify.respond"
            | "voice.record"
            | "voice.tts"
            | "rollback.restore"
    )
}

fn api_server_chat_tab_gateway_ready_payload(store: &AppStore) -> Value {
    json!({
        "skin": {
            "name": "synthchat-desktop",
            "tool_prefix": "tool",
            "statusbar": "bottom",
            "desktopAdaptation": true
        },
        "schema": "hermes_tui_gateway_ready_desktop_v1",
        "nativeApiServerRoute": "/api/ws",
        "supportedMethods": api_server_chat_tab_gateway_supported_methods(),
        "methodParity": {
            "hermesMethodCount": 74,
            "allHermesMethodsAdvertised": true,
            "extraDesktopMethods": ["ping", "gateway.status"]
        },
        "boundary": "SynthChat implements the Hermes tui_gateway.dispatch method table as a desktop-native JSON-RPC compatibility surface over /api/ws. Remaining chat-tab runtime boundaries are Hermes' Python slash-worker subprocess semantics and POSIX PTY child ownership.",
        "sessionCount": store.conversations().map(|items| items.len()).unwrap_or(0)
    })
}

