fn api_server_chat_tab_gateway_session_status(
    store: &AppStore,
    params: &Value,
) -> AppResult<Value> {
    let session_id = params
        .get("session_id")
        .or_else(|| params.get("sessionId"))
        .and_then(Value::as_str)
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .ok_or_else(|| AppError::BadRequest("session_id required".into()))?;
    let conversation = api_server_existing_session(store, session_id)?;
    let active_run = store
        .agent_runs()?
        .into_iter()
        .filter(|run| run.conversation_id == conversation.id)
        .max_by(|left, right| left.updated_at.cmp(&right.updated_at));
    Ok(json!({
        "session_id": api_server_session_id(&conversation),
        "stored_session_id": conversation.id,
        "status": active_run
            .as_ref()
            .map(|run| run.state.as_str())
            .unwrap_or("idle"),
        "running": active_run
            .as_ref()
            .map(|run| matches!(run.state.as_str(), "queued" | "started" | "running"))
            .unwrap_or(false),
        "message_count": store.messages(&conversation.id, None)?.len(),
        "info": api_server_chat_tab_gateway_session_info(store, &conversation)?
    }))
}

