fn api_server_chat_tab_gateway_session_title(store: &AppStore, params: &Value) -> AppResult<Value> {
    let conversation = api_server_chat_tab_gateway_session_from_params(store, params)?;
    if !params.get("title").is_some() {
        return Ok(json!({
            "title": conversation.title,
            "session_key": api_server_session_id(&conversation),
            "session_id": api_server_session_id(&conversation),
            "pending": false
        }));
    }
    let title = params
        .get("title")
        .and_then(Value::as_str)
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .ok_or_else(|| AppError::BadRequest("title required".into()))?;
    store.rename_conversation(&conversation.id, title.to_string())?;
    Ok(json!({
        "pending": false,
        "title": title,
        "session_key": api_server_session_id(&conversation),
        "session_id": api_server_session_id(&conversation)
    }))
}

fn api_server_chat_tab_gateway_session_usage(store: &AppStore, params: &Value) -> AppResult<Value> {
    let conversation = api_server_chat_tab_gateway_session_from_params(store, params)?;
    let messages = store.messages(&conversation.id, None)?;
    let input = messages
        .iter()
        .filter(|message| message.role == "user" || message.role == "system")
        .map(|message| message.content.split_whitespace().count() as u64)
        .sum::<u64>();
    let output = messages
        .iter()
        .filter(|message| message.role == "assistant" || message.role == "tool")
        .map(|message| message.content.split_whitespace().count() as u64)
        .sum::<u64>();
    let calls = store
        .agent_runs()?
        .into_iter()
        .filter(|run| run.conversation_id == conversation.id)
        .count() as u64;
    Ok(json!({
        "calls": calls,
        "input": input,
        "output": output,
        "total": input + output,
        "session_id": api_server_session_id(&conversation),
        "desktopEstimate": true
    }))
}

fn api_server_chat_tab_gateway_session_interrupt(
    store: &AppStore,
    params: &Value,
) -> AppResult<Value> {
    let conversation = api_server_chat_tab_gateway_session_from_params(store, params)?;
    let Some(active) = api_server_chat_tab_gateway_latest_active_run(store, &conversation.id)?
    else {
        return Ok(json!({
            "status": "idle",
            "interrupted": false,
            "session_id": api_server_session_id(&conversation)
        }));
    };
    let run = store.abort_agent_run(
        &active.run_id,
        Some("Interrupted by Hermes chat-tab JSON-RPC session.interrupt.".into()),
    )?;
    Ok(json!({
        "status": "interrupted",
        "interrupted": true,
        "session_id": api_server_session_id(&conversation),
        "run_id": run.run_id,
        "run_state": run.state
    }))
}

fn api_server_chat_tab_gateway_session_close(store: &AppStore, params: &Value) -> AppResult<Value> {
    let conversation = api_server_chat_tab_gateway_session_from_params(store, params)?;
    let active = api_server_chat_tab_gateway_latest_active_run(store, &conversation.id)?;
    let aborted_run = if let Some(active) = active {
        Some(
            store
                .abort_agent_run(
                    &active.run_id,
                    Some("Closed by Hermes chat-tab JSON-RPC session.close.".into()),
                )?
                .run_id,
        )
    } else {
        None
    };
    store.set_conversation_metadata_value(&conversation.id, "endedAt", json!(now_iso()))?;
    store.set_conversation_metadata_value(&conversation.id, "endReason", json!("closed"))?;
    store.set_conversation_metadata_value(&conversation.id, "chatTabClosed", json!(true))?;
    Ok(json!({
        "closed": true,
        "session_id": api_server_session_id(&conversation),
        "stored_session_id": conversation.id,
        "aborted_run_id": aborted_run,
        "desktopAdaptation": "conversation retained; live run aborted if present"
    }))
}

fn api_server_chat_tab_gateway_session_steer(store: &AppStore, params: &Value) -> AppResult<Value> {
    let text = params
        .get("text")
        .or_else(|| params.get("message"))
        .and_then(Value::as_str)
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .ok_or_else(|| AppError::BadRequest("text is required".into()))?;
    let conversation = api_server_chat_tab_gateway_session_from_params(store, params)?;
    let Some(active) = api_server_chat_tab_gateway_latest_active_run(store, &conversation.id)?
    else {
        return Err(AppError::BadRequest(
            "agent does not support steer without an active run".into(),
        ));
    };
    let run = store.append_agent_run_steer(&active.run_id, text.to_string())?;
    Ok(json!({
        "status": "queued",
        "text": text,
        "session_id": api_server_session_id(&conversation),
        "run_id": run.run_id,
        "pending_steers": run.pending_steers
    }))
}

