fn api_server_chat_tab_gateway_complete_path(params: &Value) -> AppResult<Value> {
    let word = params
        .get("word")
        .and_then(Value::as_str)
        .unwrap_or_default();
    if word.is_empty() {
        return Ok(json!({"items": []}));
    }
    let cwd = params
        .get("cwd")
        .and_then(Value::as_str)
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(PathBuf::from)
        .unwrap_or_else(|| std::env::current_dir().unwrap_or_else(|_| PathBuf::from(".")));
    let is_context = word.starts_with('@');
    let query = if is_context { &word[1..] } else { word };
    if is_context && query.is_empty() {
        return Ok(json!({
            "items": [
                {"text": "@diff", "display": "@diff", "meta": "git diff"},
                {"text": "@staged", "display": "@staged", "meta": "staged diff"},
                {"text": "@file:", "display": "@file:", "meta": "attach file"},
                {"text": "@folder:", "display": "@folder:", "meta": "attach folder"},
                {"text": "@url:", "display": "@url:", "meta": "fetch url"},
                {"text": "@git:", "display": "@git:", "meta": "git log"}
            ],
            "desktopAdaptation": true
        }));
    }
    let (prefix_tag, path_part) = if is_context && query.starts_with("folder:") {
        ("folder", query.trim_start_matches("folder:"))
    } else if is_context && query.starts_with("file:") {
        ("file", query.trim_start_matches("file:"))
    } else {
        ("", query)
    };
    let expanded = if path_part.is_empty() { "." } else { path_part };
    let expanded_path = PathBuf::from(expanded);
    let (search_dir, match_prefix) = if expanded.ends_with('/') || expanded.ends_with('\\') {
        (expanded_path, String::new())
    } else {
        (
            expanded_path
                .parent()
                .map(Path::to_path_buf)
                .unwrap_or_else(|| PathBuf::from(".")),
            expanded_path
                .file_name()
                .and_then(|value| value.to_str())
                .unwrap_or_default()
                .to_ascii_lowercase(),
        )
    };
    let search_dir = if search_dir.is_absolute() {
        search_dir
    } else {
        cwd.join(search_dir)
    };
    if !search_dir.is_dir() {
        return Ok(json!({"items": []}));
    }
    let mut items = Vec::new();
    for entry in fs::read_dir(&search_dir)?.filter_map(Result::ok) {
        let path = entry.path();
        let name = entry.file_name().to_string_lossy().to_string();
        if !match_prefix.is_empty() && !name.to_ascii_lowercase().starts_with(&match_prefix) {
            continue;
        }
        if is_context && name.starts_with('.') {
            continue;
        }
        let is_dir = path.is_dir();
        if prefix_tag == "folder" && !is_dir {
            continue;
        }
        if prefix_tag == "file" && is_dir {
            continue;
        }
        let rel = path
            .strip_prefix(&cwd)
            .unwrap_or(path.as_path())
            .to_string_lossy()
            .replace('\\', "/");
        let suffix = if is_dir { "/" } else { "" };
        let text = if is_context {
            let tag = if prefix_tag.is_empty() {
                if is_dir {
                    "folder"
                } else {
                    "file"
                }
            } else {
                prefix_tag
            };
            format!("@{tag}:{rel}{suffix}")
        } else {
            format!("{rel}{suffix}")
        };
        items.push(json!({
            "text": text,
            "display": format!("{name}{suffix}"),
            "meta": if is_dir { "dir" } else { "" }
        }));
        if items.len() >= 30 {
            break;
        }
    }
    Ok(json!({
        "items": items,
        "schema": "hermes_tui_complete_path_desktop_v1",
        "desktopAdaptation": true
    }))
}

fn api_server_chat_tab_gateway_complete_slash(params: &Value) -> Value {
    let text = params
        .get("text")
        .and_then(Value::as_str)
        .unwrap_or_default();
    if !text.starts_with('/') {
        return json!({"items": []});
    }
    let needle = text
        .trim_start_matches('/')
        .split_whitespace()
        .next()
        .unwrap_or_default()
        .to_ascii_lowercase();
    let mut items = Vec::new();
    for command in list_agent_control_commands() {
        let mut names = vec![command.name.clone()];
        names.extend(command.aliases.clone());
        if names
            .iter()
            .any(|name| name.to_ascii_lowercase().starts_with(&needle))
        {
            items.push(json!({
                "text": format!("/{}", command.name),
                "display": format!("/{}", command.name),
                "meta": command.description
            }));
        }
        if items.len() >= 30 {
            break;
        }
    }
    json!({
        "items": items,
        "replace_from": if text.contains(' ') { text.rfind(' ').unwrap_or(0) + 1 } else { 1 },
        "schema": "hermes_tui_complete_slash_desktop_v1",
        "desktopAdaptation": true
    })
}

fn api_server_chat_tab_gateway_browser_manage(
    store: &AppStore,
    params: &Value,
) -> AppResult<Value> {
    let action = params
        .get("action")
        .and_then(Value::as_str)
        .unwrap_or("status");
    let config = store.config()?;
    let configured_url = config
        .messaging_gateway
        .get("browserCdpUrl")
        .and_then(Value::as_str)
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(str::to_string);
    match action {
        "status" => Ok(json!({
            "connected": configured_url.is_some(),
            "url": configured_url.unwrap_or_default(),
            "desktopAdaptation": true,
            "schema": "hermes_tui_browser_manage_desktop_v1"
        })),
        "connect" => {
            let url = params
                .get("url")
                .and_then(Value::as_str)
                .map(str::trim)
                .filter(|value| !value.is_empty())
                .unwrap_or("http://127.0.0.1:9222");
            if !(url.starts_with("http://")
                || url.starts_with("https://")
                || url.starts_with("ws://")
                || url.starts_with("wss://"))
            {
                return Err(AppError::BadRequest(format!(
                    "unsupported browser url: {url}"
                )));
            }
            let mut config = config;
            if !config.messaging_gateway.is_object() {
                config.messaging_gateway = json!({});
            }
            config.messaging_gateway["browserCdpUrl"] = json!(url);
            store.set_config(config)?;
            Ok(json!({
                "connected": true,
                "url": url,
                "messages": ["Browser CDP URL recorded for SynthChat desktop browser tools."],
                "desktopAdaptation": true,
                "boundary": "Hermes probes and may launch Chromium; SynthChat records the CDP URL for native browser tools without launching host processes."
            }))
        }
        "disconnect" => {
            let mut config = config;
            if !config.messaging_gateway.is_object() {
                config.messaging_gateway = json!({});
            }
            config.messaging_gateway["browserCdpUrl"] = Value::Null;
            store.set_config(config)?;
            Ok(json!({
                "connected": false,
                "desktopAdaptation": true
            }))
        }
        _ => Err(AppError::BadRequest(format!(
            "unknown browser action: {action}"
        ))),
    }
}

fn api_server_chat_tab_gateway_insights_get(store: &AppStore, params: &Value) -> AppResult<Value> {
    let days = params.get("days").and_then(Value::as_u64).unwrap_or(30);
    let cutoff = Utc::now()
        .checked_sub_signed(chrono::Duration::days(days as i64))
        .unwrap_or_else(Utc::now);
    let conversations = store.conversations()?;
    let mut sessions = 0_u64;
    let mut messages = 0_u64;
    for conversation in conversations {
        let include = DateTime::parse_from_rfc3339(&conversation.created_at)
            .map(|created| created.with_timezone(&Utc) >= cutoff)
            .unwrap_or(true);
        if include {
            sessions += 1;
            messages += store.messages(&conversation.id, None)?.len() as u64;
        }
    }
    Ok(json!({
        "days": days,
        "sessions": sessions,
        "messages": messages,
        "schema": "hermes_tui_insights_get_desktop_v1",
        "desktopAdaptation": true
    }))
}

fn api_server_chat_tab_gateway_rollback_list(store: &AppStore, params: &Value) -> AppResult<Value> {
    let conversation = api_server_chat_tab_gateway_session_from_params(store, params)?;
    let run_id = params
        .get("run_id")
        .or_else(|| params.get("runId"))
        .and_then(Value::as_str)
        .map(str::trim)
        .filter(|value| !value.is_empty());
    let run = api_server_chat_tab_gateway_select_run(store, &conversation.id, run_id)?;
    let checkpoints = run
        .checkpoints
        .iter()
        .map(|checkpoint| {
            json!({
                "hash": checkpoint.checkpoint_id,
                "timestamp": checkpoint.created_at,
                "message": checkpoint.summary,
                "state": checkpoint.state,
                "iteration": checkpoint.iteration,
                "run_id": checkpoint.run_id
            })
        })
        .collect::<Vec<_>>();
    Ok(json!({
        "enabled": true,
        "run_id": run.run_id,
        "checkpoints": checkpoints,
        "schema": "hermes_tui_rollback_list_desktop_v1",
        "desktopAdaptation": true
    }))
}

fn api_server_chat_tab_gateway_rollback_diff(store: &AppStore, params: &Value) -> AppResult<Value> {
    let conversation = api_server_chat_tab_gateway_session_from_params(store, params)?;
    let run_id = params
        .get("run_id")
        .or_else(|| params.get("runId"))
        .and_then(Value::as_str)
        .map(str::trim)
        .filter(|value| !value.is_empty());
    let hash = params
        .get("hash")
        .or_else(|| params.get("checkpoint_id"))
        .or_else(|| params.get("checkpointId"))
        .and_then(Value::as_str)
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .ok_or_else(|| AppError::BadRequest("hash required".into()))?;
    let run = api_server_chat_tab_gateway_select_run(store, &conversation.id, run_id)?;
    let checkpoint = api_server_chat_tab_gateway_select_checkpoint(&run, hash)?;
    let stat = format!(
        "checkpoint {} #{} [{}]",
        checkpoint.checkpoint_id, checkpoint.iteration, checkpoint.state
    );
    let diff = format!(
        "SynthChat desktop checkpoint summary:\n{}\n\ncompleted_call_ids: {}\nevent_refs: {}",
        checkpoint.summary,
        checkpoint.completed_call_ids.join(", "),
        checkpoint.event_refs.join(", ")
    );
    Ok(json!({
        "stat": stat,
        "diff": diff,
        "rendered": diff,
        "run_id": run.run_id,
        "schema": "hermes_tui_rollback_diff_desktop_v1",
        "desktopAdaptation": true,
        "boundary": "Hermes rollback.diff renders filesystem checkpoint diffs; SynthChat renders the native AgentCheckpointRecord summary and event references."
    }))
}

fn api_server_chat_tab_gateway_select_run(
    store: &AppStore,
    conversation_id: &str,
    selector: Option<&str>,
) -> AppResult<AgentRunRecord> {
    let mut runs = store
        .agent_runs()?
        .into_iter()
        .filter(|run| run.conversation_id == conversation_id)
        .collect::<Vec<_>>();
    runs.sort_by(|left, right| right.updated_at.cmp(&left.updated_at));
    if let Some(selector) = selector {
        runs.into_iter()
            .find(|run| run.run_id == selector || run.run_id.starts_with(selector))
            .ok_or_else(|| AppError::BadRequest(format!("agent run not found: {selector}")))
    } else {
        runs.into_iter()
            .next()
            .ok_or_else(|| AppError::BadRequest("current session has no agent run".into()))
    }
}

fn api_server_chat_tab_gateway_select_checkpoint(
    run: &AgentRunRecord,
    selector: &str,
) -> AppResult<crate::models::AgentCheckpointRecord> {
    run.checkpoints
        .iter()
        .find(|checkpoint| {
            checkpoint.checkpoint_id == selector || checkpoint.checkpoint_id.starts_with(selector)
        })
        .cloned()
        .ok_or_else(|| AppError::BadRequest(format!("checkpoint not found: {selector}")))
}

