fn api_server_dashboard_plugin_asset_content_type(path: &Path) -> Option<&'static str> {
    match path
        .extension()
        .and_then(|value| value.to_str())?
        .to_ascii_lowercase()
        .as_str()
    {
        "js" | "mjs" => Some("application/javascript"),
        "css" => Some("text/css"),
        "json" | "map" => Some("application/json"),
        "html" => Some("text/html"),
        "svg" => Some("image/svg+xml"),
        "png" => Some("image/png"),
        "jpg" | "jpeg" => Some("image/jpeg"),
        "gif" => Some("image/gif"),
        "webp" => Some("image/webp"),
        "ico" => Some("image/x-icon"),
        "woff2" => Some("font/woff2"),
        "woff" => Some("font/woff"),
        "ttf" => Some("font/ttf"),
        "otf" => Some("font/otf"),
        _ => None,
    }
}

fn api_server_dashboard_plugin_dir(plugin_name: &str) -> AppResult<PathBuf> {
    for root in api_server_dashboard_plugin_search_roots() {
        let Ok(entries) = fs::read_dir(&root) else {
            continue;
        };
        for entry in entries.flatten() {
            let plugin_dir = entry.path();
            if !plugin_dir.is_dir() {
                continue;
            }
            let dashboard_dir = plugin_dir.join("dashboard");
            let manifest_path = dashboard_dir.join("manifest.json");
            let manifest = fs::read_to_string(&manifest_path)
                .ok()
                .and_then(|text| serde_json::from_str::<Value>(&text).ok());
            let manifest_name = manifest
                .as_ref()
                .and_then(|value| value.get("name"))
                .and_then(Value::as_str)
                .unwrap_or_else(|| {
                    plugin_dir
                        .file_name()
                        .and_then(|value| value.to_str())
                        .unwrap_or_default()
                });
            if manifest_name == plugin_name {
                return Ok(dashboard_dir);
            }
        }
    }
    Err(AppError::BadRequest(format!(
        "dashboard plugin not found: {plugin_name}"
    )))
}

fn api_server_dashboard_plugin_search_roots() -> Vec<PathBuf> {
    let mut roots = Vec::new();
    if let Some(home) = std::env::var_os("HERMES_HOME").filter(|value| !value.is_empty()) {
        roots.push(PathBuf::from(home).join("plugins"));
    }
    if let Some(repo) = std::env::var_os("HERMES_AGENT_REPO").filter(|value| !value.is_empty()) {
        roots.push(PathBuf::from(repo).join("plugins"));
    }
    let default_repo = PathBuf::from(r"D:\pro_sunner\demo_vscode\hermes-agent");
    if default_repo.is_dir() {
        roots.push(default_repo.join("plugins"));
    }
    roots
}

pub(super) fn api_server_process_sse_request<'a>(
    store: &'a AppStore,
    settings: &'a ApiServerSettings,
    request: ParsedWebhookRequest,
) -> Pin<Box<dyn Future<Output = AppResult<String>> + Send + 'a>> {
    Box::pin(async move {
        let request_path = request
            .path
            .split('?')
            .next()
            .unwrap_or(&request.path)
            .to_string();
        let protected = !matches!(request_path.as_str(), "/health" | "/health/detailed");
        if protected {
            api_server_verify_auth(store, settings, &request)?;
        }
        match (request.method.as_str(), request_path.as_str()) {
            ("POST", "/v1/chat/completions") => {
                let request = api_server_request_with_stream_disabled(request)?;
                let delta_parts = Arc::new(Mutex::new(Vec::<String>::new()));
                let callback_parts = Arc::clone(&delta_parts);
                let callback: crate::llm::LlmDeltaCallback = Arc::new(move |kind, delta| {
                    if kind != crate::llm::LlmStreamDeltaKind::Answer {
                        return Ok(());
                    }
                    if !delta.is_empty() {
                        if let Ok(mut parts) = callback_parts.lock() {
                            parts.push(delta.to_string());
                        }
                    }
                    Ok(())
                });
                let completion = api_server_handle_chat_completions_with_delta_callback(
                    store,
                    settings,
                    &request,
                    Some(callback),
                )
                .await?;
                let deltas = delta_parts
                    .lock()
                    .map(|parts| parts.clone())
                    .unwrap_or_default();
                Ok(api_server_sse_chat_completion(&completion, &deltas))
            }
            ("POST", "/v1/responses") => {
                let request = api_server_request_with_stream_disabled(request)?;
                let response = api_server_handle_responses(store, settings, &request).await?;
                Ok(api_server_sse_responses(&response))
            }
            ("POST", path)
                if path.starts_with("/api/sessions/") && path.ends_with("/chat/stream") =>
            {
                let chat_path = path.trim_end_matches("/stream").to_string();
                let mut request = request;
                request.path = chat_path;
                let response =
                    api_server_handle_session_chat(store, &request.path, &request).await?;
                Ok(api_server_sse_session_chat(&response))
            }
            ("GET", path) if path.starts_with("/v1/runs/") && path.ends_with("/events") => {
                let events = api_server_handle_run_events(store, path)?;
                Ok(api_server_sse_run_events(&events))
            }
            ("GET", "/api/plugins/kanban/runtime-events/stream") => {
                let events = api_server_handle_kanban_runtime_events(store, &request.path)?;
                Ok(api_server_sse_kanban_runtime_events(&events))
            }
            _ => Err(AppError::BadRequest(format!(
                "unsupported API server SSE endpoint: {} {}",
                request.method, request_path
            ))),
        }
    })
}

fn api_server_request_with_stream_disabled(
    mut request: ParsedWebhookRequest,
) -> AppResult<ParsedWebhookRequest> {
    let mut body = api_server_json_body_object(&request)?;
    if let Some(object) = body.as_object_mut() {
        object.insert("stream".into(), json!(false));
    }
    request.body = body.to_string();
    Ok(request)
}

fn api_server_handle_cron_jobs_list(
    store: &AppStore,
    request: &ParsedWebhookRequest,
) -> AppResult<Value> {
    let query = api_server_query_params(&request.path);
    let profile = query
        .get("profile")
        .map(|value| value.trim())
        .filter(|value| !value.is_empty())
        .unwrap_or("all");
    let mut jobs = store.scheduled_agent_jobs()?;
    if !profile.eq_ignore_ascii_case("all") {
        let profile = profile.to_string();
        jobs.retain(|job| api_server_cron_job_matches_profile(job, &profile));
    }
    jobs.sort_by(|left, right| {
        right
            .updated_at
            .cmp(&left.updated_at)
            .then_with(|| left.name.cmp(&right.name))
    });
    Ok(Value::Array(
        jobs.iter().map(api_server_cron_job_value).collect(),
    ))
}

fn api_server_handle_cron_job_get(
    store: &AppStore,
    selector: &str,
    request: &ParsedWebhookRequest,
) -> AppResult<Value> {
    let profile = api_server_cron_query_profile(request);
    let job = api_server_find_cron_job(store, selector, profile.as_deref())?;
    Ok(api_server_cron_job_value(&job))
}

fn api_server_handle_cron_job_create(
    store: &AppStore,
    request: &ParsedWebhookRequest,
) -> AppResult<Value> {
    let body = api_server_json_body_object(request)?;
    let prompt = string_arg(&body, &["prompt", "task", "content"])
        .ok_or_else(|| AppError::BadRequest("POST /api/cron/jobs requires prompt".into()))?;
    let schedule = string_arg(&body, &["schedule"])
        .ok_or_else(|| AppError::BadRequest("POST /api/cron/jobs requires schedule".into()))?;
    let query = api_server_query_params(&request.path);
    let body_profile = string_arg(&body, &["profile", "persona", "personaId", "persona_id"]);
    let profile = query
        .get("profile")
        .cloned()
        .or(body_profile)
        .as_deref()
        .unwrap_or("default")
        .trim()
        .to_string();
    let persona = api_server_cron_profile_persona(store, &profile)?;
    let mut job = ScheduledAgentJob {
        id: String::new(),
        name: string_arg(&body, &["name", "title"]).unwrap_or_default(),
        conversation_id: None,
        persona_id: persona.id.clone(),
        profile: Some(profile.clone()).filter(|value| !value.eq_ignore_ascii_case("all")),
        agent_id: string_arg(&body, &["agentId", "agent_id", "agent"]),
        prompt,
        deliver: string_arg(&body, &["deliver"]).or_else(|| Some("local".into())),
        origin: Some(json!({
            "platform": "api_server",
            "surface": "hermes_dashboard_cron",
            "profile": profile,
        })),
        ..ScheduledAgentJob::default()
    };
    apply_cron_schedule_input(&mut job, &schedule)?;
    if job.schedule_display.trim().is_empty() {
        job.schedule_display = schedule;
    }
    let saved = store.save_scheduled_agent_job(job)?;
    Ok(api_server_cron_job_value(&saved))
}

fn api_server_handle_cron_job_update(
    store: &AppStore,
    selector: &str,
    request: &ParsedWebhookRequest,
) -> AppResult<Value> {
    let body = api_server_json_body_object(request)?;
    let updates = body.get("updates").cloned().unwrap_or(body);
    if !updates.is_object() {
        return Err(AppError::BadRequest(
            "PUT /api/cron/jobs/{job_id} requires an updates object".into(),
        ));
    }
    let profile = api_server_cron_query_profile(request);
    let mut job = api_server_find_cron_job(store, selector, profile.as_deref())?;
    if let Some(name) = string_arg(&updates, &["name", "title"]) {
        job.name = name;
    }
    if let Some(prompt) = string_arg(&updates, &["prompt", "task", "content"]) {
        job.prompt = prompt;
    }
    if let Some(deliver) = string_arg(&updates, &["deliver"]) {
        job.deliver = Some(deliver);
    }
    if let Some(profile) = string_arg(&updates, &["profile", "persona", "personaId", "persona_id"])
    {
        let persona = api_server_cron_profile_persona(store, &profile)?;
        job.persona_id = persona.id;
        job.profile = Some(profile);
    }
    if let Some(agent_id) = string_arg(&updates, &["agentId", "agent_id", "agent"]) {
        job.agent_id = Some(agent_id);
    }
    if let Some(enabled) = updates.get("enabled").and_then(Value::as_bool) {
        job.enabled = enabled;
    }
    if let Some(schedule) =
        string_arg(&updates, &["schedule"]).filter(|value| !value.trim().is_empty())
    {
        apply_cron_schedule_input(&mut job, &schedule)?;
    } else {
        if let Some(kind) = string_arg(&updates, &["scheduleKind", "schedule_kind"]) {
            job.schedule_kind = kind.trim().to_ascii_lowercase();
        }
        if let Some(cron_expr) = string_arg(&updates, &["cronExpr", "cron_expr"]) {
            job.cron_expr = Some(cron_expr);
        }
        if let Some(run_at) = string_arg(&updates, &["runAt", "run_at"]) {
            job.run_at = Some(run_at);
        }
        if let Some(interval_minutes) = updates
            .get("intervalMinutes")
            .or_else(|| updates.get("interval_minutes"))
            .and_then(Value::as_u64)
        {
            job.interval_minutes = Some(interval_minutes);
        }
    }
    let saved = store.save_scheduled_agent_job(job)?;
    Ok(api_server_cron_job_value(&saved))
}

fn api_server_handle_cron_job_enabled(
    store: &AppStore,
    selector: &str,
    enabled: bool,
) -> AppResult<Value> {
    let job = api_server_find_cron_job(store, selector, None)?;
    let saved = store.set_scheduled_agent_job_enabled(&job.id, enabled)?;
    Ok(api_server_cron_job_value(&saved))
}

fn api_server_handle_cron_job_trigger(store: &AppStore, selector: &str) -> AppResult<Value> {
    let job = api_server_find_cron_job(store, selector, None)?;
    let saved = store.trigger_scheduled_agent_job(&job.id)?;
    let mut value = api_server_cron_job_value(&saved);
    if let Some(object) = value.as_object_mut() {
        object.insert("started".into(), json!(false));
        object.insert("queued".into(), json!(true));
        object.insert(
            "note".into(),
            json!("Manual trigger queued the job for the next desktop scheduler tick."),
        );
    }
    Ok(value)
}

fn api_server_handle_cron_job_delete(store: &AppStore, selector: &str) -> AppResult<Value> {
    let job = api_server_find_cron_job(store, selector, None)?;
    store.delete_scheduled_agent_job(&job.id)?;
    Ok(json!({
        "ok": true,
        "deleted": true,
        "id": job.id,
        "name": job.name,
        "nativeApiServerRoute": "/api/cron/jobs/{job_id}",
        "desktopAdaptation": true
    }))
}

fn api_server_cron_job_value(job: &ScheduledAgentJob) -> Value {
    let mut value = serde_json::to_value(job).unwrap_or_else(|_| json!({}));
    if let Some(object) = value.as_object_mut() {
        object.insert("schedule".into(), json!(job.schedule_display.clone()));
        object.insert("schedule_kind".into(), json!(job.schedule_kind.clone()));
        object.insert("cron_expr".into(), json!(job.cron_expr.clone()));
        object.insert("run_at".into(), json!(job.run_at.clone()));
        object.insert("interval_minutes".into(), json!(job.interval_minutes));
        object.insert(
            "profile".into(),
            json!(job
                .profile
                .clone()
                .unwrap_or_else(|| job.persona_id.clone())),
        );
        object.insert("persona_id".into(), json!(job.persona_id.clone()));
        object.insert("agent_id".into(), json!(job.agent_id.clone()));
        object.insert("next_run_at".into(), json!(job.next_run_at.clone()));
        object.insert("last_run_at".into(), json!(job.last_run_at.clone()));
        object.insert(
            "last_completed_at".into(),
            json!(job.last_completed_at.clone()),
        );
        object.insert("last_run_status".into(), json!(job.last_run_status.clone()));
        object.insert("last_output".into(), json!(job.last_output.clone()));
        object.insert("last_error".into(), json!(job.last_error.clone()));
        object.insert("run_count".into(), json!(job.run_count));
        object.insert("created_at".into(), json!(job.created_at.clone()));
        object.insert("updated_at".into(), json!(job.updated_at.clone()));
        object.insert(
            "job".into(),
            serde_json::to_value(job).unwrap_or(Value::Null),
        );
        object.insert(
            "schema".into(),
            json!("hermes_dashboard_cron_job_desktop_v1"),
        );
        object.insert("nativeApiServerRoute".into(), json!("/api/cron/jobs"));
        object.insert("desktopAdaptation".into(), json!(true));
    }
    value
}

fn api_server_find_cron_job(
    store: &AppStore,
    selector: &str,
    profile: Option<&str>,
) -> AppResult<ScheduledAgentJob> {
    let selector = selector.trim();
    if selector.is_empty() {
        return Err(AppError::BadRequest(
            "cron job selector cannot be empty".into(),
        ));
    }
    let jobs = store.scheduled_agent_jobs()?;
    let mut matches = jobs
        .into_iter()
        .filter(|job| {
            profile.map_or(true, |profile| {
                api_server_cron_job_matches_profile(job, profile)
            })
        })
        .filter(|job| job.id == selector || job.name == selector || job.id.starts_with(selector))
        .collect::<Vec<_>>();
    match matches.len() {
        0 => Err(AppError::NotFound(format!("Job not found: {selector}"))),
        1 => Ok(matches.remove(0)),
        _ => Err(AppError::BadRequest(format!(
            "cron job selector '{selector}' matched multiple jobs; use a full id"
        ))),
    }
}

fn api_server_cron_query_profile(request: &ParsedWebhookRequest) -> Option<String> {
    api_server_query_params(&request.path)
        .get("profile")
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty() && !value.eq_ignore_ascii_case("all"))
}

fn api_server_cron_job_matches_profile(job: &ScheduledAgentJob, profile: &str) -> bool {
    let profile = profile.trim();
    profile.eq_ignore_ascii_case("all")
        || job.profile.as_deref() == Some(profile)
        || job.persona_id == profile
}

fn api_server_cron_profile_persona(
    store: &AppStore,
    profile: &str,
) -> AppResult<crate::models::Persona> {
    let profile = profile.trim();
    if profile.eq_ignore_ascii_case("all") {
        return Err(AppError::BadRequest(
            "cron job creation cannot target profile=all".into(),
        ));
    }
    let personas = store.personas()?;
    personas
        .iter()
        .find(|persona| persona.id == profile || persona.name.eq_ignore_ascii_case(profile))
        .cloned()
        .or_else(|| {
            if profile.eq_ignore_ascii_case("default") {
                personas.first().cloned()
            } else {
                None
            }
        })
        .ok_or_else(|| AppError::NotFound(format!("profile/persona not found: {profile}")))
}

fn api_server_cron_job_path_id(path: &str, suffix: &str) -> AppResult<String> {
    let mut value = path
        .trim_start_matches("/api/cron/jobs/")
        .split('?')
        .next()
        .unwrap_or_default()
        .to_string();
    if !suffix.is_empty() {
        value = value.trim_end_matches(suffix).to_string();
    }
    let value = value.trim_matches('/').to_string();
    api_server_validate_response_id(&value)?;
    Ok(value)
}

fn api_server_handle_logs(store: &AppStore, request: &ParsedWebhookRequest) -> AppResult<Value> {
    let query = api_server_query_params(&request.path);
    let file = query
        .get("file")
        .map(|value| value.trim())
        .filter(|value| !value.is_empty())
        .unwrap_or("agent");
    let line_limit = api_server_query_usize(&query, "lines", 100, 500);
    let level = query
        .get("level")
        .map(|value| value.trim().to_ascii_uppercase())
        .filter(|value| !value.is_empty() && value != "ALL");
    let component = query
        .get("component")
        .map(|value| value.trim().to_ascii_lowercase())
        .filter(|value| !value.is_empty() && value != "all");
    let search = query
        .get("search")
        .map(|value| value.trim().to_ascii_lowercase())
        .filter(|value| !value.is_empty());
    let mut lines = api_server_log_file_candidates(store, file)
        .into_iter()
        .find_map(|path| {
            api_server_read_log_tail(&path, line_limit.saturating_mul(4).max(line_limit)).ok()
        })
        .unwrap_or_default();
    if lines.is_empty() {
        lines = api_server_synthetic_log_lines(store)?;
    }
    lines = lines
        .into_iter()
        .filter(|line| {
            level
                .as_ref()
                .map_or(true, |level| line.to_ascii_uppercase().contains(level))
        })
        .filter(|line| {
            component.as_ref().map_or(true, |component| {
                line.to_ascii_lowercase().contains(component)
            })
        })
        .filter(|line| {
            search
                .as_ref()
                .map_or(true, |search| line.to_ascii_lowercase().contains(search))
        })
        .collect::<Vec<_>>();
    if lines.len() > line_limit {
        lines = lines.split_off(lines.len() - line_limit);
    }
    Ok(json!({
        "file": file,
        "lines": lines,
        "schema": "hermes_dashboard_logs_desktop_v1",
        "nativeApiServerRoute": "/api/logs",
        "desktopAdaptation": true
    }))
}

fn api_server_handle_analytics_usage(
    store: &AppStore,
    request: &ParsedWebhookRequest,
) -> AppResult<Value> {
    let query = api_server_query_params(&request.path);
    let days = api_server_query_u64(&query, "days", 30).clamp(1, 365);
    let usage = store.token_usage()?;
    let recent_calls = usage
        .get("recentCalls")
        .and_then(Value::as_array)
        .cloned()
        .unwrap_or_default();
    let cutoff = Utc::now() - chrono::Duration::days(days as i64);
    let calls = recent_calls
        .into_iter()
        .filter(|call| {
            api_server_value_created_at(call)
                .map(|created| created >= cutoff)
                .unwrap_or(true)
        })
        .collect::<Vec<_>>();
    let daily = api_server_usage_daily(&calls);
    let by_model = api_server_usage_by_model(&calls);
    let runs = store.agent_runs()?;
    let tool_traces = store.tool_traces()?;
    let totals = json!({
        "total_input": usage.get("promptTokens").and_then(Value::as_u64).unwrap_or(0),
        "total_output": usage.get("completionTokens").and_then(Value::as_u64).unwrap_or(0),
        "total_cache_read": usage.get("cacheReadTokens").and_then(Value::as_u64).unwrap_or(0),
        "total_reasoning": usage.get("reasoningTokens").and_then(Value::as_u64).unwrap_or(0),
        "total_estimated_cost": usage.get("estimatedCostUsd").and_then(Value::as_f64).unwrap_or(0.0),
        "total_actual_cost": 0.0,
        "total_sessions": store.conversations()?.len(),
        "total_api_calls": usage.get("callCount").and_then(Value::as_u64).unwrap_or(calls.len() as u64),
        "total_agent_runs": runs.len(),
        "total_tool_calls": tool_traces.len()
    });
    Ok(json!({
        "daily": daily,
        "by_model": by_model,
        "totals": totals,
        "period_days": days,
        "skills": {
            "summary": {
                "total_skill_loads": 0,
                "total_skill_edits": tool_traces.iter().filter(|trace| trace.tool_name == "skill_manage").count(),
                "total_skill_actions": tool_traces.iter().filter(|trace| trace.tool_name.contains("skill")).count(),
                "distinct_skills_used": 0
            },
            "top_skills": []
        },
        "schema": "hermes_dashboard_usage_analytics_desktop_v1",
        "nativeApiServerRoute": "/api/analytics/usage",
        "desktopAdaptation": true
    }))
}

fn api_server_handle_analytics_models(
    store: &AppStore,
    request: &ParsedWebhookRequest,
) -> AppResult<Value> {
    let query = api_server_query_params(&request.path);
    let days = api_server_query_u64(&query, "days", 30).clamp(1, 365);
    let cutoff = Utc::now() - chrono::Duration::days(days as i64);
    let usage = store.token_usage()?;
    let recent_calls = usage
        .get("recentCalls")
        .and_then(Value::as_array)
        .cloned()
        .unwrap_or_default()
        .into_iter()
        .filter(|call| {
            api_server_value_created_at(call)
                .map(|created| created >= cutoff)
                .unwrap_or(true)
        })
        .collect::<Vec<_>>();
    let mut models = api_server_usage_by_model(&recent_calls);
    let providers = store.providers()?;
    if models.is_empty() {
        for provider in &providers {
            models.push(json!({
                "model": provider.model,
                "provider": provider.provider_type,
                "input_tokens": 0,
                "output_tokens": 0,
                "cache_read_tokens": 0,
                "reasoning_tokens": 0,
                "estimated_cost": 0.0,
                "actual_cost": 0.0,
                "sessions": 0,
                "api_calls": 0,
                "tool_calls": 0,
                "last_used_at": Value::Null,
                "avg_tokens_per_session": 0.0,
                "capabilities": api_server_model_capabilities_value(provider)
            }));
        }
    } else {
        for model in &mut models {
            let model_name = model
                .get("model")
                .and_then(Value::as_str)
                .unwrap_or_default();
            let provider = model
                .get("provider")
                .and_then(Value::as_str)
                .unwrap_or_default();
            let caps = providers
                .iter()
                .find(|item| item.model == model_name || item.provider_type == provider)
                .map(api_server_model_capabilities_value)
                .unwrap_or_else(|| json!({}));
            model["capabilities"] = caps;
        }
    }
    let totals = json!({
        "distinct_models": models.len(),
        "total_input": usage.get("promptTokens").and_then(Value::as_u64).unwrap_or(0),
        "total_output": usage.get("completionTokens").and_then(Value::as_u64).unwrap_or(0),
        "total_cache_read": usage.get("cacheReadTokens").and_then(Value::as_u64).unwrap_or(0),
        "total_reasoning": usage.get("reasoningTokens").and_then(Value::as_u64).unwrap_or(0),
        "total_estimated_cost": usage.get("estimatedCostUsd").and_then(Value::as_f64).unwrap_or(0.0),
        "total_actual_cost": 0.0,
        "total_sessions": store.conversations()?.len(),
        "total_api_calls": usage.get("callCount").and_then(Value::as_u64).unwrap_or(0)
    });
    Ok(json!({
        "models": models,
        "totals": totals,
        "period_days": days,
        "schema": "hermes_dashboard_models_analytics_desktop_v1",
        "nativeApiServerRoute": "/api/analytics/models",
        "desktopAdaptation": true
    }))
}

pub(super) fn api_server_chat_tab_pty_status_payload(
    store: &AppStore,
    query: &HashMap<String, String>,
    event_type: Option<&str>,
) -> AppResult<Value> {
    let managed_processes = store.managed_processes().unwrap_or_default();
    let queue = store.agent_queue().unwrap_or_default();
    let runs = store.agent_runs().unwrap_or_default();
    let active_runs: Vec<Value> = runs
        .iter()
        .filter(|run| matches!(run.state.as_str(), "queued" | "started" | "running"))
        .take(20)
        .map(|run| {
            json!({
                "run_id": run.run_id,
                "conversation_id": run.conversation_id,
                "queue_item_id": run.queue_item_id,
                "state": run.state,
                "updated_at": run.updated_at,
                "last_activity": run.last_activity_desc
            })
        })
        .collect();
    let pending_queue: Vec<Value> = queue
        .iter()
        .filter(|item| matches!(item.status.as_str(), "pending" | "running"))
        .take(20)
        .map(|item| {
            json!({
                "queue_item_id": item.id,
                "conversation_id": item.conversation_id,
                "status": item.status,
                "created_at": item.created_at,
                "updated_at": item.updated_at
            })
        })
        .collect();
    let active_run_count = active_runs.len();
    let pending_queue_count = pending_queue.len();
    let managed_process_count = managed_processes.len();
    let mut queue_counts: HashMap<String, usize> = HashMap::new();
    for item in &queue {
        *queue_counts.entry(item.status.clone()).or_insert(0) += 1;
    }
    let cols = query
        .get("cols")
        .and_then(|value| value.parse::<u64>().ok())
        .unwrap_or(80)
        .clamp(20, 400);
    let rows = query
        .get("rows")
        .and_then(|value| value.parse::<u64>().ok())
        .unwrap_or(24)
        .clamp(5, 200);
    Ok(json!({
        "type": event_type.unwrap_or("pty.status"),
        "schema": "hermes_chat_tab_pty_desktop_boundary_v1",
        "ok": true,
        "available": true,
        "native": false,
        "desktopAdaptation": true,
        "posixPtyAvailable": false,
        "posix_pty_available": false,
        "terminalSessionBridge": true,
        "terminal_session_bridge": true,
        "inputPassthrough": false,
        "input_passthrough": false,
        "resizeSupported": true,
        "resize_supported": true,
        "runDirectlySupported": false,
        "run_directly_supported": false,
        "channel": query.get("channel").cloned(),
        "resume": query.get("resume").cloned(),
        "session_id": query
            .get("session_id")
            .or_else(|| query.get("sessionId"))
            .or_else(|| query.get("resume"))
            .cloned(),
        "terminal": {
            "cols": cols,
            "rows": rows,
            "renderer": "xterm.js-compatible-status",
            "transport": "/api/pty"
        },
        "runtime": {
            "active_runs": active_runs,
            "active_run_count": active_run_count,
            "queue": pending_queue,
            "queue_count": pending_queue_count,
            "queue_counts": queue_counts,
            "managed_processes": managed_processes,
            "managed_process_count": managed_process_count
        },
        "nativeAlternatives": {
            "gateway": {"method": "WebSocket", "path": "/api/ws"},
            "sessionChat": {"method": "POST", "path": "/api/sessions/{session_id}/chat"},
            "sessionChatStream": {"method": "POST", "path": "/api/sessions/{session_id}/chat/stream", "sse": true},
            "runs": {"method": "POST", "path": "/v1/runs"},
            "runEvents": {"method": "GET", "path": "/v1/runs/{run_id}/events", "sse": true},
            "processTool": "agent process tool with approvals and tool UI",
            "terminalTool": "agent terminal tool with approvals and tool UI"
        },
        "boundary": "Hermes /api/pty owns a POSIX child PTY and forwards raw terminal bytes. SynthChat desktop keeps /api/pty open as a status/resize bridge, but command execution must use the native agent terminal/process tool path so approvals and tool UI transitions are preserved.",
        "message": "SynthChat desktop does not embed Hermes' POSIX PTY child. Use /api/ws prompt.submit or native agent terminal/process tools for executable work."
    }))
}

pub(super) fn api_server_chat_tab_pty_frame_response(
    store: &AppStore,
    query: &HashMap<String, String>,
    frame: &str,
) -> AppResult<Value> {
    if let Some((cols, rows)) = api_server_chat_tab_pty_resize_escape(frame) {
        return Ok(json!({
            "type": "pty.resize",
            "schema": "hermes_chat_tab_pty_resize_desktop_v1",
            "ok": true,
            "cols": cols,
            "rows": rows,
            "desktopAdaptation": true
        }));
    }
    let parsed = serde_json::from_str::<Value>(frame).unwrap_or_else(|_| {
        json!({
            "type": "input",
            "data": frame
        })
    });
    let frame_type =
        string_arg(&parsed, &["type", "event", "op"]).unwrap_or_else(|| "input".into());
    match frame_type.as_str() {
        "status" | "pty.status" => api_server_chat_tab_pty_status_payload(store, query, None),
        "resize" | "pty.resize" => {
            let cols = parsed
                .get("cols")
                .and_then(Value::as_u64)
                .unwrap_or(80)
                .clamp(20, 400);
            let rows = parsed
                .get("rows")
                .and_then(Value::as_u64)
                .unwrap_or(24)
                .clamp(5, 200);
            Ok(json!({
                "type": "pty.resize",
                "schema": "hermes_chat_tab_pty_resize_desktop_v1",
                "ok": true,
                "cols": cols,
                "rows": rows,
                "desktopAdaptation": true
            }))
        }
        "run" | "input" | "stdin" | "write" | "pty.input" => Ok(json!({
            "type": "pty.boundary",
            "schema": "hermes_chat_tab_pty_input_boundary_desktop_v1",
            "ok": false,
            "status": "blocked",
            "desktopAdaptation": true,
            "requiresNativeAgentToolPath": true,
            "requires_native_agent_tool_path": true,
            "boundary": "Raw PTY input is not executed from /api/pty in SynthChat desktop. Route commands through the agent terminal/process tools or /api/ws prompt.submit so approvals, sandbox policy, and tool UI transitions are preserved.",
            "nativeAlternatives": {
                "gateway": {"method": "WebSocket", "path": "/api/ws", "rpc": "prompt.submit"},
                "sessionChat": {"method": "POST", "path": "/api/sessions/{session_id}/chat"},
                "sessionChatStream": {"method": "POST", "path": "/api/sessions/{session_id}/chat/stream", "sse": true}
            }
        })),
        _ => Ok(json!({
            "type": "pty.unknown",
            "schema": "hermes_chat_tab_pty_unknown_desktop_v1",
            "ok": false,
            "status": "ignored",
            "frameType": frame_type,
            "desktopAdaptation": true
        })),
    }
}

fn api_server_chat_tab_pty_resize_escape(frame: &str) -> Option<(u64, u64)> {
    let body = frame
        .strip_prefix("\u{1b}[RESIZE:")
        .and_then(|value| value.strip_suffix(']'))?;
    let (cols, rows) = body.split_once(';')?;
    let cols = cols.parse::<u64>().ok()?.clamp(20, 400);
    let rows = rows.parse::<u64>().ok()?.clamp(5, 200);
    Some((cols, rows))
}

