pub(crate) async fn text_to_speech_payload_for_desktop(
    store: &AppStore,
    body: &Value,
) -> AppResult<Value> {
    use base64::Engine;

    let text = string_arg(body, &["text", "input", "content"])
        .ok_or_else(|| AppError::BadRequest("Text is required".into()))?;
    if text.trim().is_empty() {
        return Err(AppError::BadRequest("Text is required".into()));
    }
    let mut payload = body.clone();
    payload["text"] = json!(text);
    if payload.get("format").is_none() && payload.get("response_format").is_none() {
        payload["format"] = json!("wav");
    }
    let explicit_provider = payload
        .get("providerId")
        .or_else(|| payload.get("provider_id"))
        .and_then(Value::as_str)
        .map(str::trim)
        .is_some_and(|value| !value.is_empty());
    let result_text = if explicit_provider {
        text_to_speech_tool(store, "desktop-chat-tts", &payload).await?
    } else {
        match desktop_text_to_speech(store, "desktop-chat-tts", &text, &payload) {
            Ok(value) => value,
            Err(local_error) => match text_to_speech_tool(store, "desktop-chat-tts", &payload).await {
                Ok(value) => value,
                Err(provider_error) => {
                    return Err(AppError::BadRequest(format!(
                        "Local TTS failed: {local_error}; configured TTS provider failed: {provider_error}. Install edge-tts, configure ChatTTS model dir, set SYNTHCHAT_LOCAL_TTS_COMMAND, or configure an audio-capable provider."
                    )));
                }
            },
        }
    };
    let result = serde_json::from_str::<Value>(&result_text)
        .map_err(|error| AppError::BadRequest(format!("Invalid TTS response: {error}")))?;
    let artifact_path = result
        .get("artifact")
        .and_then(|artifact| artifact.get("path"))
        .and_then(Value::as_str)
        .ok_or_else(|| AppError::BadRequest("Audio file missing".into()))?;
    let audio_bytes = fs::read(artifact_path)
        .map_err(|error| AppError::BadRequest(format!("Could not read audio: {error}")))?;
    let format = result
        .get("actualFormat")
        .and_then(Value::as_str)
        .or_else(|| result.get("format").and_then(Value::as_str))
        .unwrap_or_else(|| {
            Path::new(artifact_path)
                .extension()
                .and_then(|value| value.to_str())
                .unwrap_or("mp3")
        });
    let mime_type = audio_mime_from_extension(format);
    let encoded = base64::engine::general_purpose::STANDARD.encode(audio_bytes);
    Ok(json!({
        "ok": true,
        "data_url": format!("data:{mime_type};base64,{encoded}"),
        "dataUrl": format!("data:{mime_type};base64,{encoded}"),
        "mime_type": mime_type,
        "mimeType": mime_type,
        "provider": result.get("provider").cloned().unwrap_or(Value::Null),
        "providerId": result.get("providerId").cloned().unwrap_or(Value::Null),
        "voice": result.get("voice").cloned().unwrap_or(Value::Null),
        "format": result.get("format").cloned().unwrap_or(Value::Null),
        "actualFormat": result.get("actualFormat").cloned().unwrap_or_else(|| json!(format)),
        "voiceCompatible": result.get("voiceCompatible").cloned().unwrap_or(Value::Bool(false)),
        "voice_compatible": result.get("voice_compatible").cloned().unwrap_or(Value::Bool(false)),
        "mediaTag": result.get("mediaTag").cloned().unwrap_or(Value::Null),
        "media_tag": result.get("media_tag").cloned().unwrap_or(Value::Null),
        "conversion": result.get("conversion").cloned().unwrap_or(Value::Null),
        "artifact": result.get("artifact").cloned().unwrap_or(Value::Null),
        "schema": "synthchat_desktop_chat_tts_v1",
        "desktopAdaptation": true
    }))
}

async fn api_server_transcribe_audio_payload(store: &AppStore, body: &Value) -> AppResult<Value> {
    use base64::Engine;

    let data_url = string_arg(body, &["data_url", "dataUrl", "audio", "source"])
        .or_else(|| {
            let encoded = string_arg(body, &["base64", "audioBase64", "audio_base64"])?;
            let mime = string_arg(body, &["mime_type", "mimeType"]).unwrap_or_else(|| {
                if encoded.trim_start().starts_with("data:") {
                    String::new()
                } else {
                    "audio/webm".into()
                }
            });
            if encoded.trim_start().starts_with("data:") {
                Some(encoded)
            } else {
                Some(format!("data:{mime};base64,{encoded}"))
            }
        })
        .ok_or_else(|| AppError::BadRequest("Invalid audio payload".into()))?;
    let (header, encoded) = data_url
        .split_once(',')
        .ok_or_else(|| AppError::BadRequest("Invalid audio payload".into()))?;
    if !header.starts_with("data:") {
        return Err(AppError::BadRequest("Invalid audio payload".into()));
    }
    if !header.contains(";base64") {
        return Err(AppError::BadRequest(
            "Audio payload must be base64 encoded".into(),
        ));
    }
    let mime_type = string_arg(&body, &["mime_type", "mimeType"])
        .or_else(|| {
            header
                .trim_start_matches("data:")
                .split(';')
                .next()
                .map(str::to_string)
        })
        .unwrap_or_else(|| "audio/webm".into());
    let normalized_mime = mime_type
        .split(';')
        .next()
        .unwrap_or("audio/webm")
        .trim()
        .to_ascii_lowercase();
    if !(normalized_mime.starts_with("audio/") || normalized_mime == "video/webm") {
        return Err(AppError::BadRequest(
            "Payload must be an audio recording".into(),
        ));
    }
    let audio_bytes = base64::engine::general_purpose::STANDARD
        .decode(encoded)
        .map_err(|_| AppError::BadRequest("Audio payload is not valid base64".into()))?;
    if audio_bytes.is_empty() {
        return Err(AppError::BadRequest("Audio recording is empty".into()));
    }

    let source = if normalized_mime == "video/webm" {
        format!("data:audio/webm;base64,{encoded}")
    } else {
        data_url
    };
    let mut payload = body.clone();
    payload["source"] = json!(source);
    let mut agent = AgentDefinition::default();
    agent.workspace_dir = std::env::current_dir()
        .unwrap_or_else(|_| PathBuf::from("."))
        .to_string_lossy()
        .to_string();
    let explicit_provider = payload
        .get("providerId")
        .or_else(|| payload.get("provider_id"))
        .and_then(Value::as_str)
        .map(str::trim)
        .is_some_and(|value| !value.is_empty());
    let prefer_local = payload
        .get("preferLocal")
        .or_else(|| payload.get("prefer_local"))
        .and_then(Value::as_bool)
        .unwrap_or(true);
    let local_result = if !explicit_provider && prefer_local {
        match desktop_local_command_transcribe_audio(store, "dashboard-audio", &source, &payload) {
            Ok(Some(value)) => Some(Ok(value)),
            Ok(None) => None,
            Err(error) => Some(Err(error)),
        }
    } else {
        None
    };
    let result_text = match local_result {
        Some(Ok(value)) => value,
        Some(Err(local_error)) => match transcribe_audio_tool(store, &agent, "dashboard-audio", &payload).await {
            Ok(value) => value,
            Err(provider_error) => {
                return Err(AppError::BadRequest(format!(
                    "Local STT failed: {local_error}; configured STT provider failed: {provider_error}. Configure SYNTHCHAT_LOCAL_STT_COMMAND or an audio-capable provider."
                )));
            }
        },
        None => transcribe_audio_tool(store, &agent, "dashboard-audio", &payload).await?,
    };
    let result = serde_json::from_str::<Value>(&result_text).map_err(|error| {
        AppError::BadRequest(format!("Invalid transcription response: {error}"))
    })?;
    if result.get("success").and_then(Value::as_bool) == Some(false) {
        return Err(AppError::BadRequest(
            result
                .get("error")
                .and_then(Value::as_str)
                .unwrap_or("Transcription failed")
                .into(),
        ));
    }
    Ok(json!({
        "ok": true,
        "transcript": result.get("transcript").and_then(Value::as_str).unwrap_or("").trim(),
        "provider": result.get("provider").cloned().unwrap_or(Value::Null),
        "providerId": result.get("providerId").cloned().unwrap_or(Value::Null),
        "mime_type": normalized_mime,
        "mimeType": normalized_mime,
        "schema": "hermes_dashboard_audio_transcribe_desktop_v1",
        "nativeApiServerRoute": "/api/audio/transcribe",
        "desktopAdaptation": true
    }))
}

async fn api_server_handle_elevenlabs_voices() -> AppResult<Value> {
    let api_key = provider_api_key(&None, "ELEVENLABS_API_KEY");
    let Some(api_key) = api_key else {
        return Ok(json!({
            "available": false,
            "voices": [],
            "schema": "hermes_dashboard_elevenlabs_voices_desktop_v1",
            "nativeApiServerRoute": "/api/audio/elevenlabs/voices",
            "desktopAdaptation": true
        }));
    };
    let client = reqwest::Client::builder()
        .timeout(Duration::from_secs(10))
        .user_agent("SynthChat-agent/1.0")
        .build()
        .map_err(|error| {
            AppError::BadRequest(format!("failed to build ElevenLabs client: {error}"))
        })?;
    let response = client
        .get("https://api.elevenlabs.io/v1/voices")
        .header(reqwest::header::ACCEPT, "application/json")
        .header("xi-api-key", api_key)
        .send()
        .await
        .map_err(|error| {
            AppError::BadRequest(format!("Could not load ElevenLabs voices: {error}"))
        })?;
    let status = response.status();
    let payload = response.json::<Value>().await.map_err(|error| {
        AppError::BadRequest(format!("Invalid ElevenLabs voices response: {error}"))
    })?;
    if !status.is_success() {
        return Err(AppError::BadRequest(format!(
            "Could not load ElevenLabs voices: HTTP {}",
            status.as_u16()
        )));
    }
    let mut voices = payload
        .get("voices")
        .and_then(Value::as_array)
        .cloned()
        .unwrap_or_default()
        .into_iter()
        .filter_map(|voice| {
            let voice_id = voice
                .get("voice_id")
                .and_then(Value::as_str)
                .map(str::trim)
                .filter(|value| !value.is_empty())?
                .to_string();
            let name = voice
                .get("name")
                .and_then(Value::as_str)
                .map(str::trim)
                .filter(|value| !value.is_empty())
                .unwrap_or(&voice_id)
                .to_string();
            let category = voice
                .get("category")
                .and_then(Value::as_str)
                .map(str::trim)
                .filter(|value| !value.is_empty())
                .unwrap_or("");
            let label = if category.is_empty() {
                name.clone()
            } else {
                format!("{name} ({category})")
            };
            Some(json!({
                "voice_id": voice_id,
                "name": name,
                "label": label
            }))
        })
        .collect::<Vec<_>>();
    voices.sort_by_key(|voice| {
        voice
            .get("label")
            .and_then(Value::as_str)
            .unwrap_or("")
            .to_ascii_lowercase()
    });
    Ok(json!({
        "available": true,
        "voices": voices,
        "schema": "hermes_dashboard_elevenlabs_voices_desktop_v1",
        "nativeApiServerRoute": "/api/audio/elevenlabs/voices",
        "desktopAdaptation": true
    }))
}

async fn api_server_handle_audio_speak(
    store: &AppStore,
    request: &ParsedWebhookRequest,
) -> AppResult<Value> {
    use base64::Engine;

    let body = api_server_json_body_object(request)?;
    let text = string_arg(&body, &["text"])
        .ok_or_else(|| AppError::BadRequest("Text is required".into()))?;
    let mut payload = body.clone();
    payload["text"] = json!(text);
    let result_text = text_to_speech_tool(store, "dashboard-audio", &payload).await?;
    let result = serde_json::from_str::<Value>(&result_text)
        .map_err(|error| AppError::BadRequest(format!("Invalid TTS response: {error}")))?;
    let artifact_path = result
        .get("artifact")
        .and_then(|artifact| artifact.get("path"))
        .and_then(Value::as_str)
        .ok_or_else(|| AppError::BadRequest("Audio file missing".into()))?;
    let audio_bytes = fs::read(artifact_path)
        .map_err(|error| AppError::BadRequest(format!("Could not read audio: {error}")))?;
    let format = result
        .get("format")
        .and_then(Value::as_str)
        .unwrap_or_else(|| {
            Path::new(artifact_path)
                .extension()
                .and_then(|value| value.to_str())
                .unwrap_or("mp3")
        });
    let mime_type = audio_mime_from_extension(format);
    let encoded = base64::engine::general_purpose::STANDARD.encode(audio_bytes);
    Ok(json!({
        "ok": true,
        "data_url": format!("data:{mime_type};base64,{encoded}"),
        "dataUrl": format!("data:{mime_type};base64,{encoded}"),
        "mime_type": mime_type,
        "mimeType": mime_type,
        "provider": result.get("provider").cloned().unwrap_or(Value::Null),
        "providerId": result.get("providerId").cloned().unwrap_or(Value::Null),
        "voice": result.get("voice").cloned().unwrap_or(Value::Null),
        "schema": "hermes_dashboard_audio_speak_desktop_v1",
        "nativeApiServerRoute": "/api/audio/speak",
        "desktopAdaptation": true
    }))
}

fn api_server_handle_messaging_platforms_list(store: &AppStore) -> AppResult<Value> {
    let config = store.config()?;
    let status = platform_adapter_status(store, None)?;
    let adapters = status
        .get("adapters")
        .and_then(Value::as_array)
        .cloned()
        .unwrap_or_default();
    let platforms = api_server_messaging_platform_catalog()
        .iter()
        .map(|entry| {
            let adapter = adapters
                .iter()
                .find(|adapter| adapter.get("platform").and_then(Value::as_str) == Some(entry.id))
                .cloned()
                .unwrap_or_else(|| json!({}));
            api_server_messaging_platform_payload(&config, entry, adapter)
        })
        .collect::<Vec<_>>();
    Ok(json!({
        "platforms": platforms,
        "schema": "hermes_dashboard_messaging_platforms_desktop_v1",
        "nativeApiServerRoute": "/api/messaging/platforms",
        "desktopAdaptation": true,
        "configSource": "SynthChat AppConfig platform JSON fields and messaging_gateway.platforms"
    }))
}

fn api_server_handle_oauth_providers_list() -> AppResult<Value> {
    let mut value = crate::hermes_auth::list_hermes_oauth_provider_statuses()?;
    if let Some(object) = value.as_object_mut() {
        object.insert("nativeApiServerRoute".into(), json!("/api/providers/oauth"));
    }
    Ok(value)
}

fn api_server_handle_oauth_provider_disconnect(provider: &str) -> AppResult<Value> {
    let cleared = crate::hermes_auth::clear_hermes_oauth_provider_auth(provider)?;
    Ok(json!({
        "ok": cleared > 0,
        "provider": provider,
        "cleared": cleared,
        "schema": "hermes_dashboard_oauth_provider_disconnect_desktop_v1",
        "nativeApiServerRoute": "/api/providers/oauth/{provider_id}",
        "desktopAdaptation": true,
        "boundary": "Clears Hermes/SynthChat auth-store entries and Hermes-managed Anthropic PKCE files; third-party CLI-owned credentials are not modified."
    }))
}

async fn api_server_handle_oauth_provider_start(provider: &str) -> AppResult<Value> {
    api_server_oauth_gc_sessions();
    let provider = api_server_normalize_oauth_provider(provider);
    if api_server_oauth_provider_flow(&provider) == Some("external") {
        return Err(AppError::BadRequest(format!(
            "{provider} uses an external CLI; run `{}` manually",
            api_server_oauth_provider_cli_command(&provider)
        )));
    }
    let session_id = new_id("oauth");
    let now = Utc::now();
    let expires_at = now + chrono::Duration::minutes(15);
    let mut session = json!({
        "session_id": session_id,
        "provider": provider,
        "created_at": now.to_rfc3339(),
        "expires_at": expires_at.to_rfc3339(),
        "status": "pending",
        "error_message": Value::Null
    });
    let response = match provider.as_str() {
        "google-gemini-cli" => {
            let start = crate::hermes_auth::start_google_gemini_oauth_login()?;
            session["flow"] = json!("pkce");
            session["state"] = json!(start.state.clone());
            session["code_verifier"] = json!(start.code_verifier.clone());
            api_server_oauth_store_session(&session_id, session.clone());
            json!({
                "session_id": session_id,
                "flow": "pkce",
                "auth_url": start.authorize_url,
                "authorize_url": start.authorize_url,
                "redirect_uri": start.redirect_uri,
                "state": start.state,
                "expires_in": 15 * 60,
                "schema": "hermes_dashboard_oauth_start_desktop_v1",
                "nativeApiServerRoute": "/api/providers/oauth/{provider_id}/start",
                "desktopAdaptation": true
            })
        }
        "xai-oauth" => {
            let start = crate::hermes_auth::start_xai_oauth_login().await?;
            session["flow"] = json!("pkce");
            session["state"] = json!(start.state.clone());
            session["code_verifier"] = json!(start.code_verifier.clone());
            session["code_challenge"] = json!(start.code_challenge.clone());
            api_server_oauth_store_session(&session_id, session.clone());
            json!({
                "session_id": session_id,
                "flow": "pkce",
                "auth_url": start.authorize_url,
                "authorize_url": start.authorize_url,
                "redirect_uri": start.redirect_uri,
                "state": start.state,
                "expires_in": 15 * 60,
                "schema": "hermes_dashboard_oauth_start_desktop_v1",
                "nativeApiServerRoute": "/api/providers/oauth/{provider_id}/start",
                "desktopAdaptation": true
            })
        }
        "nous" => {
            let start = crate::hermes_auth::start_nous_device_code_login().await?;
            session["flow"] = json!("device_code");
            session["device_code"] = json!(start.device_code.clone());
            api_server_oauth_store_session(&session_id, session.clone());
            json!({
                "session_id": session_id,
                "flow": "device_code",
                "user_code": start.user_code,
                "verification_url": start.verification_uri_complete,
                "verification_uri": start.verification_uri,
                "expires_in": start.expires_in,
                "poll_interval": start.interval_seconds,
                "schema": "hermes_dashboard_oauth_start_desktop_v1",
                "nativeApiServerRoute": "/api/providers/oauth/{provider_id}/start",
                "desktopAdaptation": true
            })
        }
        "openai-codex" => {
            let start = crate::hermes_auth::start_codex_device_code_login().await?;
            session["flow"] = json!("device_code");
            session["device_auth_id"] = json!(start.device_auth_id.clone());
            session["user_code"] = json!(start.user_code.clone());
            api_server_oauth_store_session(&session_id, session.clone());
            json!({
                "session_id": session_id,
                "flow": "device_code",
                "user_code": start.user_code,
                "verification_url": start.verification_uri,
                "expires_in": 15 * 60,
                "poll_interval": start.interval_seconds,
                "schema": "hermes_dashboard_oauth_start_desktop_v1",
                "nativeApiServerRoute": "/api/providers/oauth/{provider_id}/start",
                "desktopAdaptation": true
            })
        }
        "minimax-oauth" => {
            let start = crate::hermes_auth::start_minimax_oauth_login().await?;
            session["flow"] = json!("device_code");
            session["user_code"] = json!(start.user_code.clone());
            session["code_verifier"] = json!(start.code_verifier.clone());
            api_server_oauth_store_session(&session_id, session.clone());
            json!({
                "session_id": session_id,
                "flow": "device_code",
                "user_code": start.user_code,
                "verification_url": start.verification_uri,
                "expires_in": start.expired_in.max(0),
                "poll_interval": start.interval_ms.unwrap_or(2000).max(1000) / 1000,
                "schema": "hermes_dashboard_oauth_start_desktop_v1",
                "nativeApiServerRoute": "/api/providers/oauth/{provider_id}/start",
                "desktopAdaptation": true
            })
        }
        "anthropic" => {
            let start = crate::hermes_auth::start_anthropic_oauth_login()?;
            session["flow"] = json!("pkce");
            session["state"] = json!(start.state.clone());
            session["code_verifier"] = json!(start.code_verifier.clone());
            session["code_challenge"] = json!(start.code_challenge.clone());
            api_server_oauth_store_session(&session_id, session.clone());
            json!({
                "session_id": session_id,
                "flow": "pkce",
                "auth_url": start.authorize_url,
                "authorize_url": start.authorize_url,
                "redirect_uri": start.redirect_uri,
                "state": start.state,
                "expires_in": 15 * 60,
                "schema": "hermes_dashboard_oauth_start_desktop_v1",
                "nativeApiServerRoute": "/api/providers/oauth/{provider_id}/start",
                "desktopAdaptation": true
            })
        }
        "spotify" => {
            let start = crate::hermes_auth::start_spotify_oauth_login()?;
            session["flow"] = json!("pkce");
            session["state"] = json!(start.state.clone());
            session["code_verifier"] = json!(start.code_verifier.clone());
            session["code_challenge"] = json!(start.code_challenge.clone());
            session["client_id"] = json!(start.client_id.clone());
            session["scope"] = json!(start.scope.clone());
            api_server_oauth_store_session(&session_id, session.clone());
            json!({
                "session_id": session_id,
                "flow": "pkce",
                "auth_url": start.authorize_url,
                "authorize_url": start.authorize_url,
                "redirect_uri": start.redirect_uri,
                "state": start.state,
                "scope": start.scope,
                "expires_in": 15 * 60,
                "schema": "hermes_dashboard_oauth_start_desktop_v1",
                "nativeApiServerRoute": "/api/providers/oauth/{provider_id}/start",
                "desktopAdaptation": true
            })
        }
        _ => {
            return Err(AppError::BadRequest(format!(
                "Unknown or unsupported OAuth provider: {provider}"
            )));
        }
    };
    Ok(response)
}

async fn api_server_handle_oauth_provider_submit(
    provider: &str,
    request: &ParsedWebhookRequest,
) -> AppResult<Value> {
    let provider = api_server_normalize_oauth_provider(provider);
    let body = api_server_json_body_object(request)?;
    let session_id = string_arg(&body, &["session_id", "sessionId"])
        .ok_or_else(|| AppError::BadRequest("OAuth submit requires session_id".into()))?;
    let code = string_arg(&body, &["code", "callback", "callback_url", "callbackUrl"])
        .ok_or_else(|| AppError::BadRequest("OAuth submit requires code/callback".into()))?;
    let mut session = api_server_oauth_session(&session_id)?;
    api_server_oauth_validate_session(&session, &provider)?;
    let credential = match provider.as_str() {
        "google-gemini-cli" => {
            let state = session
                .get("state")
                .and_then(Value::as_str)
                .ok_or_else(|| AppError::BadRequest("OAuth session missing state".into()))?;
            let verifier = session
                .get("code_verifier")
                .and_then(Value::as_str)
                .ok_or_else(|| {
                    AppError::BadRequest("OAuth session missing code_verifier".into())
                })?;
            crate::hermes_auth::complete_google_gemini_oauth_login(&code, state, verifier).await?
        }
        "xai-oauth" => {
            let state = session
                .get("state")
                .and_then(Value::as_str)
                .ok_or_else(|| AppError::BadRequest("OAuth session missing state".into()))?;
            let verifier = session
                .get("code_verifier")
                .and_then(Value::as_str)
                .ok_or_else(|| {
                    AppError::BadRequest("OAuth session missing code_verifier".into())
                })?;
            let challenge = session
                .get("code_challenge")
                .and_then(Value::as_str)
                .ok_or_else(|| {
                    AppError::BadRequest("OAuth session missing code_challenge".into())
                })?;
            crate::hermes_auth::complete_xai_oauth_login(&code, state, verifier, challenge).await?
        }
        "anthropic" => {
            let state = session
                .get("state")
                .and_then(Value::as_str)
                .ok_or_else(|| AppError::BadRequest("OAuth session missing state".into()))?;
            let verifier = session
                .get("code_verifier")
                .and_then(Value::as_str)
                .ok_or_else(|| {
                    AppError::BadRequest("OAuth session missing code_verifier".into())
                })?;
            crate::hermes_auth::complete_anthropic_oauth_login(&code, state, verifier).await?
        }
        "spotify" => {
            let state = session
                .get("state")
                .and_then(Value::as_str)
                .ok_or_else(|| AppError::BadRequest("OAuth session missing state".into()))?;
            let verifier = session
                .get("code_verifier")
                .and_then(Value::as_str)
                .ok_or_else(|| {
                    AppError::BadRequest("OAuth session missing code_verifier".into())
                })?;
            crate::hermes_auth::complete_spotify_oauth_login(&code, state, verifier).await?
        }
        _ => {
            return Err(AppError::BadRequest(format!(
                "submit is not supported for OAuth provider {provider}; use poll"
            )));
        }
    };
    session["status"] = json!("approved");
    session["approved_at"] = json!(now_iso());
    api_server_oauth_store_session(&session_id, session);
    Ok(json!({
        "ok": true,
        "status": "approved",
        "session_id": session_id,
        "provider": provider,
        "credential": {
            "provider_id": credential.provider_id,
            "source": credential.source,
            "base_url": credential.base_url,
            "expires_at": credential.expires_at
        },
        "schema": "hermes_dashboard_oauth_submit_desktop_v1",
        "nativeApiServerRoute": "/api/providers/oauth/{provider_id}/submit",
        "desktopAdaptation": true
    }))
}

async fn api_server_handle_oauth_provider_poll(
    provider: &str,
    session_id: &str,
) -> AppResult<Value> {
    let provider = api_server_normalize_oauth_provider(provider);
    let mut session = api_server_oauth_session(session_id)?;
    api_server_oauth_validate_session(&session, &provider)?;
    let flow = session
        .get("flow")
        .and_then(Value::as_str)
        .unwrap_or("unknown");
    if flow == "pkce" {
        return Ok(api_server_oauth_poll_response(&session));
    }
    if session
        .get("status")
        .and_then(Value::as_str)
        .is_some_and(|status| status != "pending")
    {
        return Ok(api_server_oauth_poll_response(&session));
    }
    let result = match provider.as_str() {
        "nous" => {
            let device_code = session
                .get("device_code")
                .and_then(Value::as_str)
                .ok_or_else(|| AppError::BadRequest("OAuth session missing device_code".into()))?;
            crate::hermes_auth::complete_nous_device_code_login(device_code).await
        }
        "openai-codex" => {
            let device_auth_id = session
                .get("device_auth_id")
                .and_then(Value::as_str)
                .ok_or_else(|| {
                    AppError::BadRequest("OAuth session missing device_auth_id".into())
                })?;
            let user_code = session
                .get("user_code")
                .and_then(Value::as_str)
                .ok_or_else(|| AppError::BadRequest("OAuth session missing user_code".into()))?;
            crate::hermes_auth::complete_codex_device_code_login(device_auth_id, user_code).await
        }
        "minimax-oauth" => {
            let user_code = session
                .get("user_code")
                .and_then(Value::as_str)
                .ok_or_else(|| AppError::BadRequest("OAuth session missing user_code".into()))?;
            let verifier = session
                .get("code_verifier")
                .and_then(Value::as_str)
                .ok_or_else(|| {
                    AppError::BadRequest("OAuth session missing code_verifier".into())
                })?;
            crate::hermes_auth::complete_minimax_oauth_login(user_code, verifier).await
        }
        _ => {
            return Err(AppError::BadRequest(format!(
                "poll is not supported for OAuth provider {provider}"
            )));
        }
    };
    match result {
        Ok(credential) => {
            session["status"] = json!("approved");
            session["approved_at"] = json!(now_iso());
            session["credential"] = json!({
                "provider_id": credential.provider_id,
                "source": credential.source,
                "base_url": credential.base_url,
                "expires_at": credential.expires_at
            });
        }
        Err(error) if api_server_oauth_error_is_pending(&error.to_string()) => {
            session["status"] = json!("pending");
            session["error_message"] = Value::Null;
        }
        Err(error) => {
            session["status"] = json!("error");
            session["error_message"] = json!(error.to_string());
        }
    }
    api_server_oauth_store_session(session_id, session.clone());
    Ok(api_server_oauth_poll_response(&session))
}

fn api_server_handle_oauth_provider_session_cancel(session_id: &str) -> AppResult<Value> {
    let removed = api_server_oauth_sessions()
        .lock()
        .map_err(|_| AppError::BadRequest("OAuth session lock poisoned".into()))?
        .remove(session_id);
    Ok(json!({
        "ok": removed.is_some(),
        "session_id": session_id,
        "status": if removed.is_some() { "cancelled" } else { "not_found" },
        "schema": "hermes_dashboard_oauth_session_cancel_desktop_v1",
        "nativeApiServerRoute": "/api/providers/oauth/sessions/{session_id}",
        "desktopAdaptation": true
    }))
}

fn api_server_oauth_provider_path_id(path: &str) -> AppResult<String> {
    let value = path
        .trim_start_matches("/api/providers/oauth/")
        .split('?')
        .next()
        .unwrap_or_default()
        .trim_matches('/')
        .to_ascii_lowercase()
        .replace('_', "-");
    api_server_validate_response_id(&value)?;
    Ok(value)
}

fn api_server_oauth_provider_action_path_id(path: &str, suffix: &str) -> AppResult<String> {
    let mut value = path
        .trim_start_matches("/api/providers/oauth/")
        .split('?')
        .next()
        .unwrap_or_default()
        .to_string();
    if !suffix.is_empty() {
        value = value.trim_end_matches(suffix).to_string();
    }
    let value = api_server_normalize_oauth_provider(value.trim_matches('/'));
    api_server_validate_response_id(&value)?;
    Ok(value)
}

fn api_server_oauth_provider_poll_path(path: &str) -> AppResult<(String, String)> {
    let rest = path
        .trim_start_matches("/api/providers/oauth/")
        .split('?')
        .next()
        .unwrap_or_default();
    let Some((provider, session_id)) = rest.split_once("/poll/") else {
        return Err(AppError::BadRequest("invalid OAuth poll path".into()));
    };
    let provider = api_server_normalize_oauth_provider(provider);
    let session_id = session_id.trim_matches('/').to_string();
    api_server_validate_response_id(&provider)?;
    api_server_validate_response_id(&session_id)?;
    Ok((provider, session_id))
}

fn api_server_oauth_session_path_id(path: &str) -> AppResult<String> {
    let session_id = path
        .trim_start_matches("/api/providers/oauth/sessions/")
        .split('?')
        .next()
        .unwrap_or_default()
        .trim_matches('/')
        .to_string();
    api_server_validate_response_id(&session_id)?;
    Ok(session_id)
}

fn api_server_normalize_oauth_provider(provider: &str) -> String {
    match provider
        .trim()
        .to_ascii_lowercase()
        .replace('_', "-")
        .as_str()
    {
        "codex" | "openai-codex" => "openai-codex".into(),
        "nous-oauth" | "nous-portal" => "nous".into(),
        "minimax" => "minimax-oauth".into(),
        "xai" | "grok-oauth" => "xai-oauth".into(),
        "gemini" | "gemini-cli" | "gemini-oauth" => "google-gemini-cli".into(),
        "spotify-oauth" | "spotify-pkce" => "spotify".into(),
        other => other.to_string(),
    }
}

fn api_server_oauth_provider_flow(provider: &str) -> Option<&'static str> {
    match provider {
        "anthropic" | "xai-oauth" | "google-gemini-cli" | "spotify" => Some("pkce"),
        "nous" | "openai-codex" | "minimax-oauth" => Some("device_code"),
        "claude-code" | "qwen-oauth" => Some("external"),
        _ => None,
    }
}

fn api_server_oauth_provider_cli_command(provider: &str) -> &'static str {
    match provider {
        "anthropic" => "hermes auth add anthropic",
        "claude-code" => "claude setup-token",
        "nous" => "hermes auth add nous",
        "openai-codex" => "hermes auth add openai-codex",
        "qwen-oauth" => "hermes auth add qwen-oauth",
        "minimax-oauth" => "hermes auth add minimax-oauth",
        "xai-oauth" => "hermes auth add xai-oauth",
        "google-gemini-cli" => "hermes auth add google-gemini-cli",
        "spotify" => "hermes auth spotify",
        _ => "hermes auth add <provider>",
    }
}

fn api_server_oauth_sessions() -> &'static Mutex<HashMap<String, Value>> {
    static SESSIONS: std::sync::OnceLock<Mutex<HashMap<String, Value>>> =
        std::sync::OnceLock::new();
    SESSIONS.get_or_init(|| Mutex::new(HashMap::new()))
}

fn api_server_oauth_store_session(session_id: &str, session: Value) {
    if let Ok(mut sessions) = api_server_oauth_sessions().lock() {
        sessions.insert(session_id.to_string(), session);
    }
}

fn api_server_oauth_session(session_id: &str) -> AppResult<Value> {
    api_server_oauth_gc_sessions();
    api_server_oauth_sessions()
        .lock()
        .map_err(|_| AppError::BadRequest("OAuth session lock poisoned".into()))?
        .get(session_id)
        .cloned()
        .ok_or_else(|| AppError::NotFound(format!("OAuth session not found: {session_id}")))
}

fn api_server_oauth_validate_session(session: &Value, provider: &str) -> AppResult<()> {
    if session
        .get("provider")
        .and_then(Value::as_str)
        .map(api_server_normalize_oauth_provider)
        .as_deref()
        != Some(provider)
    {
        return Err(AppError::BadRequest(
            "Provider mismatch for OAuth session".into(),
        ));
    }
    if api_server_oauth_session_expired(session) {
        return Err(AppError::BadRequest("OAuth session has expired".into()));
    }
    Ok(())
}

fn api_server_oauth_gc_sessions() {
    if let Ok(mut sessions) = api_server_oauth_sessions().lock() {
        sessions.retain(|_, session| !api_server_oauth_session_expired(session));
    }
}

fn api_server_oauth_session_expired(session: &Value) -> bool {
    session
        .get("expires_at")
        .and_then(Value::as_str)
        .and_then(|text| DateTime::parse_from_rfc3339(text).ok())
        .map(|expires| expires.with_timezone(&Utc) < Utc::now())
        .unwrap_or(false)
}

fn api_server_oauth_poll_response(session: &Value) -> Value {
    json!({
        "session_id": session.get("session_id").cloned().unwrap_or(Value::Null),
        "provider": session.get("provider").cloned().unwrap_or(Value::Null),
        "flow": session.get("flow").cloned().unwrap_or(Value::Null),
        "status": session.get("status").cloned().unwrap_or_else(|| json!("pending")),
        "error_message": session.get("error_message").cloned().unwrap_or(Value::Null),
        "expires_at": session.get("expires_at").cloned().unwrap_or(Value::Null),
        "credential": session.get("credential").cloned().unwrap_or(Value::Null),
        "schema": "hermes_dashboard_oauth_poll_desktop_v1",
        "nativeApiServerRoute": "/api/providers/oauth/{provider_id}/poll/{session_id}",
        "desktopAdaptation": true
    })
}

fn api_server_oauth_error_is_pending(error: &str) -> bool {
    let lower = error.to_ascii_lowercase();
    lower.contains("authorization is still pending")
        || lower.contains("authorization_pending")
        || lower.contains("slow_down")
        || lower.contains("finish browser login")
}

fn api_server_handle_messaging_platform_update(
    store: &AppStore,
    platform: &str,
    request: &ParsedWebhookRequest,
) -> AppResult<Value> {
    let platform = normalize_platform_name(platform);
    let entry = api_server_messaging_platform_entry(&platform)
        .ok_or_else(|| AppError::NotFound(format!("Unknown messaging platform: {platform}")))?;
    let body = api_server_json_body_object(request)?;
    let mut config = store.config()?;

    if let Some(enabled) = body.get("enabled").and_then(Value::as_bool) {
        api_server_set_messaging_platform_enabled(&mut config, entry.id, enabled)?;
    }

    if let Some(env) = body.get("env").and_then(Value::as_object) {
        for (key, value) in env {
            if !entry.env.iter().any(|item| item.0 == key) {
                return Err(AppError::BadRequest(format!(
                    "{key} is not configurable for {}",
                    entry.name
                )));
            }
            if let Some(field) = api_server_messaging_env_field(entry, key) {
                api_server_update_messaging_platform_field(&mut config, entry.id, field, value)?;
            }
        }
    }

    if let Some(clear_env) = body.get("clear_env").or_else(|| body.get("clearEnv")) {
        let keys = clear_env
            .as_array()
            .ok_or_else(|| AppError::BadRequest("clear_env must be an array".into()))?;
        for key in keys.iter().filter_map(Value::as_str) {
            if !entry.env.iter().any(|item| item.0 == key) {
                return Err(AppError::BadRequest(format!(
                    "{key} is not configurable for {}",
                    entry.name
                )));
            }
            if let Some(field) = api_server_messaging_env_field(entry, key) {
                api_server_update_messaging_platform_field(
                    &mut config,
                    entry.id,
                    field,
                    &Value::String(String::new()),
                )?;
            }
        }
    }

    let updates = body
        .get("config")
        .or_else(|| body.get("settings"))
        .or_else(|| body.get("updates"));
    if let Some(updates) = updates.and_then(Value::as_object) {
        for (key, value) in updates {
            api_server_update_messaging_platform_field(&mut config, entry.id, key, value)?;
        }
    }

    for key in [
        "homeChannel",
        "home_channel",
        "homeRoom",
        "homeRecipient",
        "homeAddress",
        "homeNumber",
        "homeTarget",
        "homeNotifyTarget",
        "homeChatId",
        "homeThreadId",
        "botToken",
        "token",
        "appToken",
        "accessToken",
        "apiBaseUrl",
        "baseUrl",
        "url",
        "server",
        "topic",
        "publishTopic",
        "incomingWebhookUrl",
        "webhookUrl",
    ] {
        if let Some(value) = body.get(key) {
            api_server_update_messaging_platform_field(&mut config, entry.id, key, value)?;
        }
    }

    store.set_config(config)?;
    let updated = store.config()?;
    let adapter = platform_adapter_status(store, Some(entry.id))?;
    Ok(json!({
        "ok": true,
        "platform": entry.id,
        "schema": "hermes_dashboard_messaging_platform_update_desktop_v1",
        "nativeApiServerRoute": "/api/messaging/platforms/{platform_id}",
        "desktopAdaptation": true,
        "payload": api_server_messaging_platform_payload(&updated, entry, adapter)
    }))
}

fn api_server_handle_messaging_platform_test(store: &AppStore, platform: &str) -> AppResult<Value> {
    let platform = normalize_platform_name(platform);
    let entry = api_server_messaging_platform_entry(&platform)
        .ok_or_else(|| AppError::NotFound(format!("Unknown messaging platform: {platform}")))?;
    let config = store.config()?;
    let adapter = platform_adapter_status(store, Some(entry.id))?;
    let payload = api_server_messaging_platform_payload(&config, entry, adapter);
    let enabled = payload
        .get("enabled")
        .and_then(Value::as_bool)
        .unwrap_or(false);
    let configured = payload
        .get("configured")
        .and_then(Value::as_bool)
        .unwrap_or(false);
    let gateway_running = payload
        .get("gateway_running")
        .and_then(Value::as_bool)
        .unwrap_or(false);
    let state = payload
        .get("state")
        .and_then(Value::as_str)
        .unwrap_or("unknown");
    if !enabled {
        return Ok(json!({
            "ok": false,
            "state": state,
            "message": format!("{} is disabled. Enable it, then restart the gateway.", entry.name),
            "platform": entry.id,
            "payload": payload,
            "schema": "hermes_dashboard_messaging_platform_test_desktop_v1",
            "nativeApiServerRoute": "/api/messaging/platforms/{platform_id}/test",
            "desktopAdaptation": true,
            "offlineReadinessProbe": true
        }));
    }
    if !configured {
        let missing = payload
            .get("env_vars")
            .and_then(Value::as_array)
            .map(|vars| {
                vars.iter()
                    .filter(|field| {
                        field
                            .get("required")
                            .and_then(Value::as_bool)
                            .unwrap_or(false)
                            && !field
                                .get("is_set")
                                .and_then(Value::as_bool)
                                .unwrap_or(false)
                    })
                    .filter_map(|field| field.get("key").and_then(Value::as_str))
                    .collect::<Vec<_>>()
            })
            .unwrap_or_default();
        let message = if missing.is_empty() {
            "Platform setup is incomplete.".to_string()
        } else {
            format!("Missing required setup: {}", missing.join(", "))
        };
        return Ok(json!({
            "ok": false,
            "state": state,
            "message": message,
            "platform": entry.id,
            "payload": payload,
            "schema": "hermes_dashboard_messaging_platform_test_desktop_v1",
            "nativeApiServerRoute": "/api/messaging/platforms/{platform_id}/test",
            "desktopAdaptation": true,
            "offlineReadinessProbe": true
        }));
    }
    if !gateway_running {
        return Ok(json!({
            "ok": false,
            "state": state,
            "message": "Gateway is not running. Restart the gateway to connect this platform.",
            "platform": entry.id,
            "payload": payload,
            "schema": "hermes_dashboard_messaging_platform_test_desktop_v1",
            "nativeApiServerRoute": "/api/messaging/platforms/{platform_id}/test",
            "desktopAdaptation": true,
            "offlineReadinessProbe": true
        }));
    }
    Ok(json!({
        "ok": matches!(state, "connected" | "running" | "configured"),
        "state": state,
        "message": if matches!(state, "connected" | "running" | "configured") {
            format!("{} is connected.", entry.name)
        } else {
            "Setup looks complete, but the gateway has not reported a connection yet. Restart the gateway.".into()
        },
        "platform": entry.id,
        "payload": payload,
        "schema": "hermes_dashboard_messaging_platform_test_desktop_v1",
        "nativeApiServerRoute": "/api/messaging/platforms/{platform_id}/test",
        "desktopAdaptation": true,
        "offlineReadinessProbe": true
    }))
}

