fn api_server_handle_kanban_recovery_action(
    store: &AppStore,
    path: &str,
    request: &ParsedWebhookRequest,
    action: &str,
) -> AppResult<Value> {
    let task_id = api_server_kanban_task_path_id(
        path,
        match action {
            "kanban-reclaim" => "/reclaim",
            "kanban-reassign" => "/reassign",
            _ => "",
        },
    )?;
    let query = api_server_query_params(&request.path);
    let mut body = api_server_json_body_object(request)?;
    let Some(object) = body.as_object_mut() else {
        return Err(AppError::BadRequest(
            "Request body must be a JSON object".into(),
        ));
    };
    object.insert("action".into(), json!(action));
    object.insert("taskId".into(), json!(task_id));
    if let Some(board) = query.get("board") {
        object.entry("board").or_insert_with(|| json!(board));
    }
    if action == "kanban-reassign" {
        if let Some(profile) = query.get("profile") {
            object.entry("profile").or_insert_with(|| json!(profile));
        }
        if let Some(reclaim) = query
            .get("reclaimFirst")
            .or_else(|| query.get("reclaim_first"))
        {
            let reclaim_first = matches!(
                reclaim.trim().to_ascii_lowercase().as_str(),
                "1" | "true" | "yes" | "on"
            );
            object
                .entry("reclaimFirst")
                .or_insert_with(|| json!(reclaim_first));
        }
    }
    let mut response: Value = serde_json::from_str(&dashboard_plugins_tool(store, &body)?)?;
    if let Some(object) = response.as_object_mut() {
        object.insert("object".into(), json!("kanban.recovery"));
        object.insert(
            "nativeApiServerRoute".into(),
            json!(format!(
                "/api/plugins/kanban/tasks/{{task_id}}/{}",
                if action == "kanban-reclaim" {
                    "reclaim"
                } else {
                    "reassign"
                }
            )),
        );
        object.insert("task_id".into(), json!(task_id));
    }
    Ok(response)
}

