fn api_server_sse_responses(response: &Value) -> String {
    let response_id = response
        .get("id")
        .and_then(Value::as_str)
        .unwrap_or("resp_synthchat");
    let text = api_server_response_output_text(response).unwrap_or_default();
    let item_id = response
        .get("output")
        .and_then(Value::as_array)
        .and_then(|items| items.first())
        .and_then(|item| item.get("id"))
        .and_then(Value::as_str)
        .unwrap_or("msg_synthchat");
    let mut output = String::new();
    let mut created = response.clone();
    created["status"] = json!("in_progress");
    created["output"] = json!([]);
    api_server_push_sse_event(&mut output, "response.created", &created);
    if !text.is_empty() {
        api_server_push_sse_event(
            &mut output,
            "response.output_text.delta",
            &json!({
                "type": "response.output_text.delta",
                "response_id": response_id,
                "item_id": item_id,
                "output_index": 0,
                "content_index": 0,
                "delta": text,
                "sequence_number": 1,
            }),
        );
        api_server_push_sse_event(
            &mut output,
            "response.output_text.done",
            &json!({
                "type": "response.output_text.done",
                "response_id": response_id,
                "item_id": item_id,
                "output_index": 0,
                "content_index": 0,
                "text": text,
                "sequence_number": 2,
            }),
        );
    }
    api_server_push_sse_event(&mut output, "response.completed", response);
    output.push_str("data: [DONE]\n\n");
    output
}

fn api_server_response_output_text(response: &Value) -> Option<&str> {
    response
        .get("output")
        .and_then(Value::as_array)
        .and_then(|items| items.first())
        .and_then(|item| item.get("content"))
        .and_then(Value::as_array)
        .and_then(|content| content.first())
        .and_then(|part| part.get("text"))
        .and_then(Value::as_str)
}

