fn api_server_toolset_env_value(config: &crate::models::AppConfig, key: &str) -> Option<String> {
    std::env::var(key)
        .ok()
        .filter(|value| !value.trim().is_empty())
        .or_else(|| {
            api_server_dashboard_env_state(config)
                .get(key)
                .and_then(Value::as_str)
                .map(str::to_string)
                .filter(|value| !value.trim().is_empty())
        })
}

fn api_server_apply_tts_provider_selection(
    store: &AppStore,
    config: &crate::models::AppConfig,
    provider_id: &str,
) -> AppResult<()> {
    let Some(defaults) = api_server_tts_runtime_provider_defaults(provider_id) else {
        return Ok(());
    };
    let mut providers = store.providers()?;
    let api_key = defaults
        .api_key_envs
        .iter()
        .find_map(|key| api_server_toolset_env_value(config, key));
    let base_url = defaults
        .base_url_envs
        .iter()
        .find_map(|key| api_server_toolset_env_value(config, key))
        .unwrap_or_else(|| defaults.base_url.into());
    if let Some(provider) = providers
        .iter_mut()
        .find(|provider| provider.id == defaults.id)
    {
        provider.name = defaults.name.into();
        provider.provider_type = defaults.provider_type.into();
        provider.preset = Some(defaults.preset.into());
        provider.base_url = base_url;
        provider.append_chat_path = false;
        provider.api_key_env = defaults.api_key_envs.first().copied().unwrap_or("").into();
        provider.api_key = api_key;
        provider.model = defaults.model.into();
        provider.timeout_seconds = provider.timeout_seconds.max(defaults.timeout_seconds);
        provider.enabled = false;
    } else {
        let mut provider = LlmProvider::default();
        provider.id = defaults.id.into();
        provider.name = defaults.name.into();
        provider.provider_type = defaults.provider_type.into();
        provider.preset = Some(defaults.preset.into());
        provider.base_url = base_url;
        provider.append_chat_path = false;
        provider.api_key_env = defaults.api_key_envs.first().copied().unwrap_or("").into();
        provider.api_key = api_key;
        provider.model = defaults.model.into();
        provider.enabled = false;
        provider.timeout_seconds = defaults.timeout_seconds;
        providers.push(provider);
    }
    store.set_providers(providers)
}

