fn api_server_toolset_provider_template(
    id: &'static str,
    name: &'static str,
    badge: &'static str,
    tag: &'static str,
    env_vars: Vec<ApiServerToolsetEnvTemplate>,
    post_setup: Option<&'static str>,
    requires_nous_auth: bool,
) -> ApiServerToolsetProviderTemplate {
    ApiServerToolsetProviderTemplate {
        id: Some(id),
        name,
        badge,
        tag,
        env_vars,
        post_setup,
        requires_nous_auth,
        runtime_provider_id: match id {
            "openai" | "xai" | "elevenlabs" | "mistral" | "gemini" | "minimax" => {
                api_server_tts_runtime_provider_defaults(id).map(|defaults| defaults.id)
            }
            _ => None,
        },
    }
}

fn api_server_toolset_env_template(
    key: &'static str,
    prompt: &'static str,
    url: Option<&'static str>,
    default: Option<&'static str>,
) -> ApiServerToolsetEnvTemplate {
    ApiServerToolsetEnvTemplate {
        key,
        prompt,
        url,
        default,
    }
}

fn api_server_toolset_provider_row(
    store: &AppStore,
    config: &crate::models::AppConfig,
    template: ApiServerToolsetProviderTemplate,
    selected_provider: Option<&str>,
) -> AppResult<Value> {
    let selected = selected_provider.is_some_and(|selected| {
        let normalized = normalize_toolset_provider_name(selected);
        normalize_toolset_provider_name(template.name) == normalized
            || template
                .id
                .is_some_and(|id| normalize_toolset_provider_name(id) == normalized)
    });
    Ok(json!({
        "id": template.id.map(Value::from).unwrap_or(Value::Null),
        "name": template.name,
        "badge": template.badge,
        "tag": template.tag,
        "env_vars": template.env_vars.iter().map(|env| {
            json!({
                "key": env.key,
                "prompt": env.prompt,
                "url": env.url.map(Value::from).unwrap_or(Value::Null),
                "default": env.default.map(Value::from).unwrap_or(Value::Null),
                "is_set": api_server_toolset_env_is_set(store, config, env.key).unwrap_or(false),
            })
        }).collect::<Vec<_>>(),
        "post_setup": template.post_setup.map(Value::from).unwrap_or(Value::Null),
        "requires_nous_auth": template.requires_nous_auth,
        "selected": selected,
        "runtimeProviderId": template.runtime_provider_id.map(Value::from).unwrap_or(Value::Null),
        "runtime_provider_id": template.runtime_provider_id.map(Value::from).unwrap_or(Value::Null),
    }))
}

fn normalize_toolset_provider_name(value: &str) -> String {
    value.trim().to_ascii_lowercase().replace(['_', ' '], "-")
}

fn api_server_toolset_env_is_set(
    store: &AppStore,
    config: &crate::models::AppConfig,
    key: &str,
) -> AppResult<bool> {
    if std::env::var(key)
        .ok()
        .is_some_and(|value| !value.trim().is_empty())
    {
        return Ok(true);
    }
    if api_server_dashboard_env_state(config)
        .get(key)
        .and_then(Value::as_str)
        .is_some_and(|value| !value.trim().is_empty())
    {
        return Ok(true);
    }
    Ok(store.providers()?.iter().any(|provider| {
        provider.api_key_env == key
            && provider
                .api_key
                .as_deref()
                .is_some_and(|value| !value.trim().is_empty())
    }))
}

fn api_server_toolset_rows(store: &AppStore, state: &Value) -> AppResult<Vec<Value>> {
    let mut groups: HashMap<String, Vec<crate::models::ToolDefinition>> = HashMap::new();
    for tool in store.tool_definitions()? {
        for group in api_server_toolset_groups_for_tool(&tool) {
            groups.entry(group).or_default().push(tool.clone());
        }
    }
    let config = store.config()?;
    let cli_platform_toolsets = api_server_cli_platform_toolsets(&config);
    let mut rows = groups
        .into_iter()
        .map(|(name, mut tools)| {
            tools.sort_by(|a, b| a.name.cmp(&b.name));
            let dashboard_enabled = state
                .get("enabled")
                .and_then(|items| items.get(&name))
                .and_then(Value::as_bool)
                .unwrap_or(true);
            let platform_enabled = cli_platform_toolsets
                .as_ref()
                .map(|items| items.contains(&name))
                .unwrap_or(true);
            let enabled = dashboard_enabled && platform_enabled;
            let provider = state
                .get("providers")
                .and_then(|items| items.get(&name))
                .and_then(Value::as_str)
                .unwrap_or("desktop-native");
            json!({
                "name": name,
                "label": api_server_toolset_label(&name),
                "description": format!("SynthChat desktop toolset {name}"),
                "enabled": enabled,
                "available": enabled,
                "dashboardEnabled": dashboard_enabled,
                "dashboard_enabled": dashboard_enabled,
                "platformEnabled": platform_enabled,
                "platform_enabled": platform_enabled,
                "platform": "cli",
                "platformConfigured": cli_platform_toolsets.is_some(),
                "platform_configured": cli_platform_toolsets.is_some(),
                "configured": true,
                "provider": provider,
                "tools": tools.iter().map(|tool| tool.name.clone()).collect::<Vec<_>>(),
                "desktopToolset": true
            })
        })
        .collect::<Vec<_>>();
    rows.sort_by(|a, b| {
        a.get("name")
            .and_then(Value::as_str)
            .unwrap_or_default()
            .cmp(b.get("name").and_then(Value::as_str).unwrap_or_default())
    });
    Ok(rows)
}

fn api_server_apply_cli_platform_toolset_updates(
    config: &mut crate::models::AppConfig,
    known_rows: &[Value],
    names: &[String],
    enabled: bool,
) {
    if names.is_empty() {
        return;
    }
    let mut current = api_server_cli_platform_toolsets(config).unwrap_or_else(|| {
        known_rows
            .iter()
            .filter_map(|row| row.get("name").and_then(Value::as_str))
            .map(str::to_string)
            .collect()
    });
    for name in names {
        if enabled {
            current.insert(name.clone());
        } else {
            current.remove(name);
        }
    }
    api_server_set_cli_platform_toolsets(config, current);
}

fn api_server_cli_platform_toolsets(
    config: &crate::models::AppConfig,
) -> Option<std::collections::HashSet<String>> {
    let value = config
        .chat
        .auxiliary_task_assignments
        .get("hermesPlatformToolsets")
        .or_else(|| {
            config
                .chat
                .auxiliary_task_assignments
                .get("hermes_platform_toolsets")
        })?
        .get("cli")?;
    let items = value.as_array()?;
    Some(
        items
            .iter()
            .filter_map(Value::as_str)
            .map(normalize_toolset_name)
            .filter(|name| !name.is_empty())
            .collect(),
    )
}

fn api_server_set_cli_platform_toolsets(
    config: &mut crate::models::AppConfig,
    toolsets: std::collections::HashSet<String>,
) {
    if !config.chat.auxiliary_task_assignments.is_object() {
        config.chat.auxiliary_task_assignments = json!({});
    }
    let mut values = toolsets.into_iter().collect::<Vec<_>>();
    values.sort();
    if let Some(object) = config.chat.auxiliary_task_assignments.as_object_mut() {
        let mut platform = object
            .get("hermesPlatformToolsets")
            .cloned()
            .unwrap_or_else(|| json!({}));
        if !platform.is_object() {
            platform = json!({});
        }
        platform["cli"] = json!(values);
        object.insert("hermesPlatformToolsets".into(), platform);
        object.remove("hermes_platform_toolsets");
    }
}

fn api_server_toolset_group_for_tool(tool: &crate::models::ToolDefinition) -> String {
    api_server_toolset_groups_for_tool(tool)
        .into_iter()
        .next()
        .unwrap_or_else(|| "internal".into())
}

fn api_server_toolset_groups_for_tool(tool: &crate::models::ToolDefinition) -> Vec<String> {
    if !tool.server_id.trim().is_empty() && tool.server_id != "__internal" {
        return vec![format!("server:{}", tool.server_id)];
    }
    if !tool.source.trim().is_empty() && tool.source != "internal" {
        return vec![tool.source.clone()];
    }
    let mut groups = tool_toolsets(tool)
        .into_iter()
        .filter(|name| !name.starts_with("server:") && !name.starts_with("tool:"))
        .collect::<std::collections::BTreeSet<_>>();
    if let Some((prefix, _)) = tool.name.split_once('_') {
        groups.insert(prefix.to_string());
    }
    groups.remove("all");
    groups.remove("internal");
    if groups.is_empty() {
        groups.insert("internal".into());
    }
    groups.into_iter().collect()
}

fn api_server_toolset_label(name: &str) -> String {
    name.split(['_', '-', ':'])
        .filter(|part| !part.is_empty())
        .map(|part| {
            let mut chars = part.chars();
            match chars.next() {
                Some(first) => format!("{}{}", first.to_uppercase(), chars.as_str()),
                None => String::new(),
            }
        })
        .collect::<Vec<_>>()
        .join(" ")
}

fn api_server_dashboard_toolsets_state(config: &crate::models::AppConfig) -> Value {
    let mut state = config
        .messaging_gateway
        .get("dashboardToolsets")
        .cloned()
        .unwrap_or_else(|| json!({}));
    if !state.is_object() {
        state = json!({});
    }
    if state.get("enabled").is_none() {
        state["enabled"] = json!({});
    }
    if state.get("providers").is_none() {
        state["providers"] = json!({});
    }
    state
}

fn api_server_set_dashboard_toolsets_state_on_config(
    config: &mut crate::models::AppConfig,
    state: Value,
) {
    if !config.messaging_gateway.is_object() {
        config.messaging_gateway = json!({});
    }
    config.messaging_gateway["dashboardToolsets"] = state;
}

fn api_server_toolset_path_name(path: &str, prefix: &str, suffix: &str) -> AppResult<String> {
    let name = path
        .strip_prefix(prefix)
        .and_then(|rest| {
            if suffix.is_empty() {
                Some(rest)
            } else {
                rest.strip_suffix(suffix)
            }
        })
        .map(|name| name.trim_matches('/').to_string())
        .filter(|name| !name.is_empty())
        .ok_or_else(|| AppError::BadRequest("toolset path mismatch".into()))?;
    if name.contains("..") || name.contains('\\') {
        Err(AppError::BadRequest("invalid toolset name".into()))
    } else {
        Ok(name)
    }
}

const API_SERVER_AUX_MODEL_SLOTS: &[&str] = &[
    "vision",
    "web_extract",
    "compression",
    "skills_hub",
    "approval",
    "mcp",
    "title_generation",
    "triage_specifier",
    "kanban_decomposer",
    "profile_describer",
    "curator",
];

fn api_server_handle_model_info(store: &AppStore) -> AppResult<Value> {
    let provider = store.provider(None).ok();
    let model = provider
        .as_ref()
        .map(|p| p.model.clone())
        .unwrap_or_default();
    let provider_type = provider
        .as_ref()
        .map(|p| p.provider_type.clone())
        .unwrap_or_default();
    let provider_id = provider.as_ref().map(|p| p.id.clone()).unwrap_or_default();
    let config_context_length = provider
        .as_ref()
        .and_then(|p| {
            p.prompt_cache_layout
                .strip_prefix("context:")
                .and_then(|raw| raw.parse::<u64>().ok())
        })
        .unwrap_or(0);
    Ok(json!({
        "model": model,
        "provider": provider_type,
        "provider_id": provider_id,
        "auto_context_length": 0,
        "config_context_length": config_context_length,
        "effective_context_length": config_context_length,
        "capabilities": {
            "supports_tools": provider.as_ref().map(crate::model_catalog::provider_model_capabilities).map(|caps| caps.supports_tools).unwrap_or(true),
            "supports_vision": provider.as_ref().map(crate::model_catalog::provider_model_capabilities).map(|caps| caps.supports_vision).unwrap_or(false),
            "supports_reasoning": provider.as_ref().map(crate::model_catalog::provider_model_capabilities).map(|caps| caps.supports_reasoning).unwrap_or(false),
            "context_window": config_context_length,
            "max_output_tokens": provider.as_ref().map(crate::model_catalog::provider_model_capabilities).and_then(|caps| caps.max_output_tokens).unwrap_or(0),
            "model_family": provider.as_ref().map(crate::model_catalog::provider_model_capabilities).map(|caps| {
                if caps.model_family.trim().is_empty() {
                    provider_type.clone()
                } else {
                    caps.model_family
                }
            }).unwrap_or(provider_type.clone())
        },
        "schema": "hermes_dashboard_model_info_desktop_v1",
        "nativeApiServerRoute": "/api/model/info",
        "desktopAdaptation": true
    }))
}

fn api_server_handle_model_options(store: &AppStore) -> AppResult<Value> {
    let raw_providers = store.providers()?;
    let current = raw_providers
        .iter()
        .find(|provider| provider.enabled)
        .or_else(|| raw_providers.first());
    let current_provider = current
        .map(|provider| provider.provider_type.clone())
        .unwrap_or_default();
    let current_model = current
        .map(|provider| provider.model.clone())
        .unwrap_or_default();
    let current_base_url = current
        .map(|provider| provider.base_url.clone())
        .unwrap_or_default();
    let providers = raw_providers
        .into_iter()
        .map(|provider| {
            let authenticated = provider
                .api_key
                .as_deref()
                .is_some_and(|value| !value.trim().is_empty())
                || !provider.api_key_env.trim().is_empty()
                || provider.provider_type == "echo";
            let configured = authenticated
                || !provider.base_url.trim().is_empty()
                || provider.provider_type == "echo";
            json!({
                "id": provider.id,
                "slug": provider.provider_type,
                "name": provider.name,
                "provider": provider.provider_type,
                "provider_type": provider.provider_type,
                "enabled": provider.enabled,
                "configured": configured,
                "base_url": provider.base_url,
                "models": if provider.model.trim().is_empty() { json!([]) } else { json!([provider.model]) },
                "current_model": provider.model,
                "preset": provider.preset,
                "pricing": Value::Null,
                "authenticated": authenticated,
                "auth_type": if provider.api_key_env.trim().is_empty() && provider.api_key.is_none() { "none" } else { "api_key" },
                "key_env": provider.api_key_env,
                "warning": if configured { Value::Null } else { json!("Provider is not configured in SynthChat desktop settings.") },
                "total_models": if provider.model.trim().is_empty() { 0 } else { 1 },
                "is_current": provider.enabled,
                "desktopProvider": true
            })
        })
        .collect::<Vec<_>>();
    Ok(json!({
        "providers": providers,
        "current_provider": current_provider,
        "current_model": current_model,
        "current_base_url": current_base_url,
        "include_unconfigured": true,
        "canonical_order": false,
        "picker_hints": true,
        "schema": "hermes_dashboard_model_options_desktop_v1",
        "tuiSchema": "hermes_tui_model_options_desktop_v1",
        "nativeApiServerRoute": "/api/model/options",
        "desktopAdaptation": true,
        "boundary": "SynthChat lists configured desktop LLM providers without performing Hermes inventory network/model-catalog refreshes."
    }))
}

fn api_server_handle_model_recommended_default(store: &AppStore, path: &str) -> AppResult<Value> {
    let provider_query = api_server_query_params(path)
        .get("provider")
        .cloned()
        .unwrap_or_default();
    let provider_query_lower = provider_query.to_ascii_lowercase();
    let selected = store.providers()?.into_iter().find(|provider| {
        provider.provider_type.eq_ignore_ascii_case(&provider_query)
            || provider.id.eq_ignore_ascii_case(&provider_query)
            || provider.name.eq_ignore_ascii_case(&provider_query)
    });
    Ok(json!({
        "provider": provider_query_lower,
        "model": selected.map(|provider| provider.model).unwrap_or_default(),
        "free_tier": Value::Null,
        "schema": "hermes_dashboard_model_recommended_default_desktop_v1",
        "nativeApiServerRoute": "/api/model/recommended-default",
        "desktopAdaptation": true
    }))
}

fn api_server_handle_model_auxiliary(store: &AppStore) -> AppResult<Value> {
    let config = store.config()?;
    let aux = config.chat.auxiliary_task_assignments.as_object();
    let tasks = API_SERVER_AUX_MODEL_SLOTS
        .iter()
        .map(|slot| {
            let slot_cfg = aux
                .and_then(|items| items.get(*slot))
                .and_then(Value::as_object);
            json!({
                "task": slot,
                "provider": slot_cfg
                    .and_then(|items| items.get("provider").or_else(|| items.get("providerId")))
                    .and_then(Value::as_str)
                    .unwrap_or("auto"),
                "model": slot_cfg
                    .and_then(|items| items.get("model"))
                    .and_then(Value::as_str)
                    .unwrap_or(""),
                "base_url": slot_cfg
                    .and_then(|items| items.get("base_url").or_else(|| items.get("baseUrl")))
                    .and_then(Value::as_str)
                    .unwrap_or("")
            })
        })
        .collect::<Vec<_>>();
    let provider = store.provider(None).ok();
    Ok(json!({
        "tasks": tasks,
        "main": {
            "provider": provider.as_ref().map(|p| p.provider_type.clone()).unwrap_or_default(),
            "provider_id": provider.as_ref().map(|p| p.id.clone()).unwrap_or_default(),
            "model": provider.as_ref().map(|p| p.model.clone()).unwrap_or_default()
        },
        "schema": "hermes_dashboard_model_auxiliary_desktop_v1",
        "nativeApiServerRoute": "/api/model/auxiliary",
        "desktopAdaptation": true
    }))
}

fn api_server_handle_model_set(
    store: &AppStore,
    request: &ParsedWebhookRequest,
) -> AppResult<Value> {
    let body = api_server_json_body_object(request)?;
    let scope = string_arg(&body, &["scope"])
        .unwrap_or_else(|| "main".into())
        .trim()
        .to_ascii_lowercase();
    let provider =
        string_arg(&body, &["provider", "providerId", "provider_id"]).unwrap_or_default();
    let model = string_arg(&body, &["model"]).unwrap_or_default();
    match scope.as_str() {
        "main" => api_server_set_main_model(store, &provider, &model),
        "auxiliary" => {
            let task = string_arg(&body, &["task"]).unwrap_or_default();
            api_server_set_auxiliary_model(store, &task, &provider, &model)
        }
        _ => Err(AppError::BadRequest(
            "scope must be 'main' or 'auxiliary'".into(),
        )),
    }
}

fn api_server_set_main_model(store: &AppStore, provider: &str, model: &str) -> AppResult<Value> {
    let provider = provider.trim();
    let model = model.trim();
    if provider.is_empty() || model.is_empty() {
        return Err(AppError::BadRequest(
            "provider and model required for main model assignment".into(),
        ));
    }
    let mut providers = store.providers()?;
    let mut matched = false;
    for item in providers.iter_mut() {
        let is_match = item.id.eq_ignore_ascii_case(provider)
            || item.provider_type.eq_ignore_ascii_case(provider)
            || item.name.eq_ignore_ascii_case(provider);
        item.enabled = is_match;
        if is_match {
            item.model = model.to_string();
            matched = true;
        }
    }
    if !matched {
        return Err(AppError::NotFound(format!(
            "llm provider not found for model assignment: {provider}"
        )));
    }
    store.set_providers(providers)?;
    Ok(json!({
        "ok": true,
        "scope": "main",
        "provider": provider,
        "model": model,
        "gateway_tools": [],
        "schema": "hermes_dashboard_model_set_desktop_v1",
        "nativeApiServerRoute": "/api/model/set",
        "desktopAdaptation": true
    }))
}

fn api_server_set_auxiliary_model(
    store: &AppStore,
    task: &str,
    provider: &str,
    model: &str,
) -> AppResult<Value> {
    let task = task.trim().to_ascii_lowercase();
    let provider = provider.trim();
    if task == "__reset__" {
        let mut config = store.config()?;
        let mut assignments = config
            .chat
            .auxiliary_task_assignments
            .as_object()
            .cloned()
            .unwrap_or_default();
        for slot in API_SERVER_AUX_MODEL_SLOTS {
            assignments.insert((*slot).into(), json!({"provider": "auto", "model": ""}));
        }
        config.chat.auxiliary_task_assignments = Value::Object(assignments);
        store.set_config(config)?;
        return Ok(json!({
            "ok": true,
            "scope": "auxiliary",
            "reset": true,
            "schema": "hermes_dashboard_model_set_desktop_v1",
            "nativeApiServerRoute": "/api/model/set",
            "desktopAdaptation": true
        }));
    }
    if provider.is_empty() {
        return Err(AppError::BadRequest(
            "provider required for auxiliary model assignment".into(),
        ));
    }
    let targets = if task.is_empty() {
        API_SERVER_AUX_MODEL_SLOTS
            .iter()
            .map(|slot| (*slot).to_string())
            .collect::<Vec<_>>()
    } else {
        if !API_SERVER_AUX_MODEL_SLOTS.iter().any(|slot| *slot == task) {
            return Err(AppError::BadRequest(format!(
                "unknown auxiliary task: {task}"
            )));
        }
        vec![task]
    };
    let mut config = store.config()?;
    let mut assignments = config
        .chat
        .auxiliary_task_assignments
        .as_object()
        .cloned()
        .unwrap_or_default();
    for slot in &targets {
        assignments.insert(
            slot.clone(),
            json!({
                "provider": provider,
                "model": model,
            }),
        );
    }
    config.chat.auxiliary_task_assignments = Value::Object(assignments);
    store.set_config(config)?;
    Ok(json!({
        "ok": true,
        "scope": "auxiliary",
        "tasks": targets,
        "provider": provider,
        "model": model,
        "schema": "hermes_dashboard_model_set_desktop_v1",
        "nativeApiServerRoute": "/api/model/set",
        "desktopAdaptation": true
    }))
}

fn api_server_validate_session_id(session_id: &str) -> AppResult<()> {
    if session_id.trim().is_empty()
        || session_id
            .chars()
            .any(|ch| matches!(ch, '\r' | '\n' | '\0'))
        || session_id.len() > 256
    {
        Err(AppError::BadRequest("Invalid session ID".into()))
    } else {
        Ok(())
    }
}

fn api_server_validate_response_id(response_id: &str) -> AppResult<()> {
    if response_id.trim().is_empty()
        || response_id
            .chars()
            .any(|ch| matches!(ch, '\r' | '\n' | '\0' | '/'))
        || response_id.len() > 256
    {
        Err(AppError::BadRequest("Invalid response ID".into()))
    } else {
        Ok(())
    }
}

