fn api_server_kanban_home_subscribe_path_ids(path: &str) -> AppResult<(String, String)> {
    let value = path
        .trim_start_matches("/api/plugins/kanban/tasks/")
        .split('?')
        .next()
        .unwrap_or_default()
        .trim_matches('/');
    let Some((task_id, platform)) = value.split_once("/home-subscribe/") else {
        return Err(AppError::BadRequest(
            "Invalid Kanban home subscription route".into(),
        ));
    };
    let task_id = task_id.trim_matches('/').to_string();
    let platform = platform.trim_matches('/').to_ascii_lowercase();
    if task_id.trim().is_empty()
        || task_id
            .chars()
            .any(|ch| matches!(ch, '\r' | '\n' | '\0' | '/'))
        || task_id.len() > 256
    {
        return Err(AppError::BadRequest("Invalid Kanban task ID".into()));
    }
    if platform.trim().is_empty()
        || platform
            .chars()
            .any(|ch| matches!(ch, '\r' | '\n' | '\0' | '/'))
        || platform.len() > 128
    {
        return Err(AppError::BadRequest(
            "Invalid Kanban home subscription platform".into(),
        ));
    }
    Ok((task_id, platform))
}

