fn api_server_query_scalar_value(value: &str) -> Value {
    let trimmed = value.trim();
    if matches!(trimmed.to_ascii_lowercase().as_str(), "true" | "yes" | "on") {
        return json!(true);
    }
    if matches!(
        trimmed.to_ascii_lowercase().as_str(),
        "false" | "no" | "off"
    ) {
        return json!(false);
    }
    if let Ok(number) = trimmed.parse::<i64>() {
        return json!(number);
    }
    json!(value)
}

fn api_server_response_input_messages(input: &Value) -> AppResult<Vec<(String, String)>> {
    match input {
        Value::String(text) => Ok(vec![("user".into(), text.clone())]),
        Value::Array(items) => {
            let mut messages = Vec::new();
            for (index, item) in items.iter().enumerate() {
                match item {
                    Value::String(text) => messages.push(("user".into(), text.clone())),
                    Value::Object(_) => {
                        let role = item
                            .get("role")
                            .and_then(Value::as_str)
                            .unwrap_or("user")
                            .to_string();
                        let content = api_server_normalize_openai_content(
                            item.get("content").unwrap_or(&Value::Null),
                            &format!("input[{index}].content"),
                        )?;
                        messages.push((role, content));
                    }
                    _ => {
                        return Err(AppError::BadRequest(
                            "'input' array items must be strings or message objects".into(),
                        ));
                    }
                }
            }
            Ok(messages)
        }
        _ => Err(AppError::BadRequest(
            "'input' must be a string or array".into(),
        )),
    }
}

