async fn webhook_handle_connection(
    app: AppHandle,
    store: AppStore,
    settings: WebhookSettings,
    mut stream: TcpStream,
) -> AppResult<()> {
    let mut buffer = vec![0_u8; 64 * 1024];
    let read = tokio::time::timeout(
        Duration::from_secs(settings.timeout_seconds),
        stream.read(&mut buffer),
    )
    .await
    .map_err(|_| AppError::BadRequest("Webhook request read timed out".into()))?
    .map_err(|error| AppError::BadRequest(format!("Webhook request read failed: {error}")))?;
    let request = String::from_utf8_lossy(&buffer[..read]).to_string();
    let parsed = webhook_parse_request(&request);
    let status = match parsed {
        Ok(parsed) => webhook_process_request(&app, &store, &settings, parsed).await,
        Err(error) => Err(error),
    };
    let (code, body) = match status {
        Ok(value) => (200, value),
        Err(error) => (400, json!({"ok": false, "error": error.to_string()})),
    };
    let body_text = body.to_string();
    let response = format!(
        "HTTP/1.1 {code} {}\r\nContent-Type: application/json\r\nContent-Length: {}\r\nConnection: close\r\n\r\n{}",
        if code == 200 { "OK" } else { "Bad Request" },
        body_text.as_bytes().len(),
        body_text
    );
    stream
        .write_all(response.as_bytes())
        .await
        .map_err(|error| AppError::BadRequest(format!("Webhook response write failed: {error}")))?;
    Ok(())
}

#[derive(Clone)]
pub(super) struct ParsedWebhookRequest {
    pub(super) method: String,
    pub(super) path: String,
    pub(super) headers: HashMap<String, String>,
    pub(super) body: String,
}

fn webhook_parse_request(request: &str) -> AppResult<ParsedWebhookRequest> {
    let (head, body) = request
        .split_once("\r\n\r\n")
        .ok_or_else(|| AppError::BadRequest("Malformed webhook HTTP request".into()))?;
    let mut lines = head.lines();
    let start = lines
        .next()
        .ok_or_else(|| AppError::BadRequest("Webhook request missing start line".into()))?;
    let mut parts = start.split_whitespace();
    let method = parts.next().unwrap_or_default().to_ascii_uppercase();
    let path = parts.next().unwrap_or_default().to_string();
    let mut headers = HashMap::new();
    for line in lines {
        if let Some((key, value)) = line.split_once(':') {
            headers.insert(key.trim().to_ascii_lowercase(), value.trim().to_string());
        }
    }
    Ok(ParsedWebhookRequest {
        method,
        path,
        headers,
        body: body.to_string(),
    })
}

async fn webhook_process_request(
    app: &AppHandle,
    store: &AppStore,
    settings: &WebhookSettings,
    request: ParsedWebhookRequest,
) -> AppResult<Value> {
    if request.method != "POST" {
        return Err(AppError::BadRequest("Webhook only accepts POST".into()));
    }
    let request_path = request.path.split('?').next().unwrap_or(&request.path);
    if request_path != settings.path {
        return Err(AppError::BadRequest(format!(
            "Webhook path mismatch: expected {}, got {}",
            settings.path, request_path
        )));
    }
    if let Some(secret) = settings.secret.as_deref() {
        let provided = request
            .headers
            .get("x-synthchat-webhook-secret")
            .or_else(|| request.headers.get("x-hermes-webhook-secret"))
            .or_else(|| request.headers.get("x-webhook-secret"))
            .map(String::as_str)
            .unwrap_or_default();
        if provided != secret {
            return Err(AppError::BadRequest("Webhook secret mismatch".into()));
        }
    }
    let payload = serde_json::from_str::<Value>(&request.body)
        .unwrap_or_else(|_| json!({"body": request.body}));
    if webhook_delivery_type(&payload).as_deref() == Some("github_comment") {
        return webhook_deliver_github_comment(&payload).await;
    }
    let config = store.config()?.webhook;
    let conversation_id = webhook_inbound_conversation_id(store, &config)?;
    let persona_id = webhook_inbound_persona_id(store, &config)?;
    let event_id = new_id("webhook");
    let inbound = json!({
        "platform": "webhook",
        "eventId": event_id,
        "event_id": event_id,
        "path": request_path,
        "payload": payload,
        "source": {
            "platform": "webhook",
            "chatId": request_path,
            "chat_id": request_path,
            "userId": "webhook",
            "user_id": "webhook",
            "chatType": "webhook",
            "chat_type": "webhook",
        }
    });
    let prompt = webhook_inbound_prompt(&inbound);
    let Some(prompt) = apply_pre_gateway_dispatch_hooks(store, "webhook", &inbound, prompt).await
    else {
        let state =
            store.update_webhook_adapter_state(Some("running"), Some(inbound), None, 1, 0)?;
        emit_platform_adapter_event(app, "inbound_ignored", "webhook", &state);
        return Ok(json!({"ok": true, "eventId": event_id, "skipped": true}));
    };
    let state = store.update_webhook_adapter_state(Some("running"), Some(inbound), None, 1, 1)?;
    emit_platform_adapter_event(app, "inbound_triggered", "webhook", &state);
    spawn_background_chat_turn_for_job(app.clone(), conversation_id, persona_id, prompt, None);
    Ok(json!({"ok": true, "eventId": event_id}))
}

fn webhook_delivery_type(payload: &Value) -> Option<String> {
    payload
        .get("delivery")
        .and_then(|delivery| string_arg(delivery, &["deliver", "type"]))
        .or_else(|| {
            string_arg(
                payload,
                &["deliver", "delivery", "deliverType", "deliver_type"],
            )
        })
        .map(|value| normalize_platform_name(&value))
}

fn webhook_github_comment_delivery_extra(payload: &Value) -> Value {
    payload
        .get("delivery")
        .and_then(|delivery| {
            delivery
                .get("deliver_extra")
                .or_else(|| delivery.get("deliverExtra"))
                .or_else(|| delivery.get("extra"))
        })
        .cloned()
        .unwrap_or_else(|| payload.clone())
}

fn webhook_github_comment_content(payload: &Value) -> AppResult<String> {
    string_arg(
        payload,
        &["content", "message", "body", "text", "response", "comment"],
    )
    .or_else(|| {
        payload
            .get("delivery")
            .and_then(|delivery| string_arg(delivery, &["content", "message", "body", "text"]))
    })
    .map(|value| value.trim().to_string())
    .filter(|value| !value.is_empty())
    .ok_or_else(|| {
        AppError::BadRequest(
            "webhook github_comment delivery requires content/message/body/text".into(),
        )
    })
}

fn webhook_github_comment_should_execute(payload: &Value) -> bool {
    ["execute", "live", "apply"]
        .iter()
        .any(|key| payload.get(*key).and_then(Value::as_bool).unwrap_or(false))
        && payload
            .get("confirmGithubComment")
            .or_else(|| payload.get("confirm_github_comment"))
            .and_then(Value::as_bool)
            .unwrap_or(false)
}

pub(super) async fn webhook_deliver_github_comment(payload: &Value) -> AppResult<Value> {
    let extra = webhook_github_comment_delivery_extra(payload);
    let repo = string_arg(&extra, &["repo", "repository"])
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty())
        .ok_or_else(|| {
            AppError::BadRequest(
                "webhook github_comment delivery requires deliver_extra.repo".into(),
            )
        })?;
    let pr_number = string_arg(
        &extra,
        &[
            "pr_number",
            "prNumber",
            "pullRequest",
            "pull_request",
            "issue",
            "number",
        ],
    )
    .or_else(|| {
        [
            "pr_number",
            "prNumber",
            "pullRequest",
            "pull_request",
            "issue",
            "number",
        ]
        .iter()
        .find_map(|key| {
            extra
                .get(*key)
                .and_then(Value::as_i64)
                .map(|value| value.to_string())
        })
    })
    .map(|value| value.trim().to_string())
    .filter(|value| !value.is_empty())
    .ok_or_else(|| {
        AppError::BadRequest(
            "webhook github_comment delivery requires deliver_extra.pr_number".into(),
        )
    })?;
    let content = webhook_github_comment_content(payload)?;
    let args = vec![
        "pr".to_string(),
        "comment".to_string(),
        pr_number.clone(),
        "--repo".to_string(),
        repo.clone(),
        "--body".to_string(),
        content.clone(),
    ];
    let command = std::iter::once("gh".to_string())
        .chain(args.iter().cloned())
        .collect::<Vec<_>>()
        .join(" ");
    if !webhook_github_comment_should_execute(payload) {
        return Ok(json!({
            "ok": true,
            "success": true,
            "schema": "hermes_webhook_github_comment_delivery_desktop_v1",
            "delivery": "github_comment",
            "planned": true,
            "executed": false,
            "requiresConfirmation": true,
            "requires_confirmation": true,
            "confirmField": "confirmGithubComment",
            "confirm_field": "confirmGithubComment",
            "repo": repo,
            "prNumber": pr_number,
            "pr_number": pr_number,
            "command": command,
            "args": args,
            "managedProcessStartPayload": {
                "command": command,
                "cwd": ".",
                "background": false,
                "label": "Hermes webhook GitHub comment",
                "description": "Post a Hermes webhook response as a GitHub PR/issue comment through gh pr comment."
            },
            "managed_process_start_payload": {
                "command": command,
                "cwd": ".",
                "background": false,
                "label": "Hermes webhook GitHub comment",
                "description": "Post a Hermes webhook response as a GitHub PR/issue comment through gh pr comment."
            },
            "hermesReference": "gateway/platforms/webhook.py::_deliver_github_comment",
            "hermes_reference": "gateway/platforms/webhook.py::_deliver_github_comment"
        }));
    }

    let mut command = Command::new("gh");
    command.hide_window();
    let output = command.args(&args).output().await.map_err(|error| {
        if error.kind() == std::io::ErrorKind::NotFound {
            AppError::BadRequest("gh CLI not installed".into())
        } else {
            AppError::BadRequest(format!(
                "github_comment delivery failed to launch gh: {error}"
            ))
        }
    })?;
    let stdout = String::from_utf8_lossy(&output.stdout).trim().to_string();
    let stderr = String::from_utf8_lossy(&output.stderr).trim().to_string();
    Ok(json!({
        "ok": output.status.success(),
        "success": output.status.success(),
        "schema": "hermes_webhook_github_comment_delivery_desktop_v1",
        "delivery": "github_comment",
        "planned": false,
        "executed": true,
        "repo": repo,
        "prNumber": pr_number,
        "pr_number": pr_number,
        "exitCode": output.status.code(),
        "exit_code": output.status.code(),
        "stdout": truncate_output(&stdout, 4000),
        "stderr": truncate_output(&stderr, 4000),
        "hermesReference": "gateway/platforms/webhook.py::_deliver_github_comment",
        "hermes_reference": "gateway/platforms/webhook.py::_deliver_github_comment"
    }))
}

async fn apply_pre_gateway_dispatch_hooks(
    store: &AppStore,
    platform: &str,
    inbound: &Value,
    prompt: String,
) -> Option<String> {
    match run_pre_gateway_dispatch_hooks(store, platform, inbound, &prompt).await {
        PreGatewayDispatchDecision::Allow => Some(prompt),
        PreGatewayDispatchDecision::Rewrite(text) => Some(text),
        PreGatewayDispatchDecision::Skip(_) => None,
    }
}

fn webhook_inbound_prompt(inbound: &Value) -> String {
    let path = inbound
        .get("path")
        .and_then(Value::as_str)
        .unwrap_or_default();
    let event_id = inbound
        .get("eventId")
        .or_else(|| inbound.get("event_id"))
        .and_then(Value::as_str)
        .unwrap_or_default();
    let payload = inbound.get("payload").cloned().unwrap_or(Value::Null);
    let payload_text =
        serde_json::to_string_pretty(&payload).unwrap_or_else(|_| payload.to_string());
    format!("Webhook inbound event\npath: {path}\nevent_id: {event_id}\n\n{payload_text}")
}

fn webhook_inbound_conversation_id(store: &AppStore, config: &Value) -> AppResult<String> {
    if let Some(id) = string_arg(
        config,
        &[
            "inboundConversationId",
            "inbound_conversation_id",
            "conversationId",
            "conversation_id",
        ],
    ) {
        return Ok(id);
    }
    if let Some(existing) = store.conversations()?.into_iter().find(|conversation| {
        conversation
            .metadata
            .get("platform")
            .and_then(Value::as_str)
            == Some("webhook")
    }) {
        return Ok(existing.id);
    }
    let persona_id = webhook_inbound_persona_id(store, config)?;
    let conversation = store.create_conversation(Some("Webhook".into()), Some(persona_id))?;
    store.set_conversation_metadata_value(&conversation.id, "platform", json!("webhook"))?;
    Ok(conversation.id)
}

fn webhook_inbound_persona_id(store: &AppStore, config: &Value) -> AppResult<String> {
    if let Some(id) = string_arg(config, &["personaId", "persona_id", "inboundPersonaId"]) {
        return Ok(id);
    }
    Ok(store
        .personas()?
        .first()
        .map(|persona| persona.id.clone())
        .ok_or_else(|| AppError::NotFound("persona".into()))?)
}

async fn messaging_gateway_adapter_loop(
    app: AppHandle,
    store: AppStore,
    settings: MessagingGatewayReceiveSettings,
    listener: TcpListener,
    listen_url: String,
) {
    let mut ntfy_stream = messaging_gateway_ntfy_stream_future(
        app.clone(),
        store.clone(),
        settings.clone(),
        listen_url.clone(),
    );
    let mut simplex_stream = messaging_gateway_simplex_stream_future(
        app.clone(),
        store.clone(),
        settings.clone(),
        listen_url.clone(),
    );
    let mut irc_stream = messaging_gateway_irc_stream_future(
        app.clone(),
        store.clone(),
        settings.clone(),
        listen_url.clone(),
    );
    let mut google_chat_stream = messaging_gateway_google_chat_pubsub_future(
        app.clone(),
        store.clone(),
        settings.clone(),
        listen_url.clone(),
    );
    if let Ok(state) = store.update_messaging_gateway_adapter_state(
        Some("running"),
        Some(json!({"type": "listening", "listenUrl": listen_url, "nativeStreamingPlatforms": messaging_gateway_native_streaming_platforms(&settings)})),
        None,
        0,
        0,
    ) {
        emit_platform_adapter_event(&app, "connected", "messaging_gateway", &state);
    }
    loop {
        tokio::select! {
            accept_result = listener.accept() => {
                match accept_result {
                    Ok((stream, _addr)) => {
                        let app_for_task = app.clone();
                        let store_for_task = store.clone();
                        let settings_for_task = settings.clone();
                        tokio::spawn(async move {
                            let _ = messaging_gateway_handle_connection(
                                app_for_task,
                                store_for_task,
                                settings_for_task,
                                stream,
                            )
                            .await;
                        });
                    }
                    Err(error) => {
                        if let Ok(state) = store.update_messaging_gateway_adapter_state(
                            Some("reconnecting"),
                            None,
                            Some(format!("Messaging gateway webhook accept failed: {error}")),
                            0,
                            0,
                        ) {
                            emit_platform_adapter_event(&app, "reconnecting", "messaging_gateway", &state);
                        }
                        tokio::time::sleep(Duration::from_secs(1)).await;
                    }
                }
            }
            _ = &mut ntfy_stream, if settings.platforms.contains("ntfy") => {
                ntfy_stream = messaging_gateway_ntfy_stream_future(
                    app.clone(),
                    store.clone(),
                    settings.clone(),
                    listen_url.clone(),
                );
            }
            _ = &mut simplex_stream, if settings.platforms.contains("simplex") => {
                simplex_stream = messaging_gateway_simplex_stream_future(
                    app.clone(),
                    store.clone(),
                    settings.clone(),
                    listen_url.clone(),
                );
            }
            _ = &mut irc_stream, if settings.platforms.contains("irc") => {
                irc_stream = messaging_gateway_irc_stream_future(
                    app.clone(),
                    store.clone(),
                    settings.clone(),
                    listen_url.clone(),
                );
            }
            _ = &mut google_chat_stream, if settings.platforms.contains("google_chat") => {
                google_chat_stream = messaging_gateway_google_chat_pubsub_future(
                    app.clone(),
                    store.clone(),
                    settings.clone(),
                    listen_url.clone(),
                );
            }
        }
    }
}

fn messaging_gateway_native_streaming_platforms(
    settings: &MessagingGatewayReceiveSettings,
) -> Vec<&'static str> {
    let mut platforms = Vec::new();
    if settings.platforms.contains("ntfy") {
        platforms.push("ntfy");
    }
    if settings.platforms.contains("simplex") {
        platforms.push("simplex");
    }
    if settings.platforms.contains("irc") {
        platforms.push("irc");
    }
    if settings.platforms.contains("google_chat") {
        platforms.push("google_chat");
    }
    platforms
}

fn messaging_gateway_google_chat_pubsub_future(
    app: AppHandle,
    store: AppStore,
    settings: MessagingGatewayReceiveSettings,
    listen_url: String,
) -> Pin<Box<dyn Future<Output = ()> + Send>> {
    Box::pin(async move {
        if settings.platforms.contains("google_chat") {
            messaging_gateway_google_chat_pubsub_loop(app, store, settings, listen_url).await;
        } else {
            futures::future::pending::<()>().await;
        }
    })
}

fn messaging_gateway_ntfy_stream_future(
    app: AppHandle,
    store: AppStore,
    settings: MessagingGatewayReceiveSettings,
    listen_url: String,
) -> Pin<Box<dyn Future<Output = ()> + Send>> {
    Box::pin(async move {
        if settings.platforms.contains("ntfy") {
            messaging_gateway_ntfy_stream_loop(app, store, settings, listen_url).await;
        } else {
            futures::future::pending::<()>().await;
        }
    })
}

async fn messaging_gateway_ntfy_stream_loop(
    app: AppHandle,
    store: AppStore,
    settings: MessagingGatewayReceiveSettings,
    listen_url: String,
) {
    let mut backoff_seconds = 1_u64;
    loop {
        let result = messaging_gateway_ntfy_stream_once(&app, &store, &settings, &listen_url).await;
        match result {
            Ok(()) => {
                backoff_seconds = 1;
            }
            Err(error) => {
                let message = error.to_string();
                let fatal = message.contains("401") || message.contains("404");
                if let Ok(state) = store.update_messaging_gateway_adapter_state(
                    Some(if fatal { "error" } else { "reconnecting" }),
                    Some(json!({
                        "type": "ntfy_stream_error",
                        "platform": "ntfy",
                        "retryable": !fatal,
                        "listenUrl": listen_url,
                    })),
                    Some(format!("ntfy stream failed: {message}")),
                    0,
                    0,
                ) {
                    emit_platform_adapter_event(&app, "stream_error", "ntfy", &state);
                }
                if fatal {
                    return;
                }
            }
        }
        tokio::time::sleep(Duration::from_secs(backoff_seconds)).await;
        backoff_seconds = (backoff_seconds * 2).min(30);
    }
}

async fn messaging_gateway_google_chat_pubsub_loop(
    app: AppHandle,
    store: AppStore,
    settings: MessagingGatewayReceiveSettings,
    listen_url: String,
) {
    let mut backoff_seconds = 1_u64;
    loop {
        let result =
            messaging_gateway_google_chat_pubsub_once(&app, &store, &settings, &listen_url).await;
        match result {
            Ok(messages) => {
                backoff_seconds = if messages == 0 { 5 } else { 1 };
            }
            Err(error) => {
                let message = error.to_string();
                let fatal = message.contains("401")
                    || message.contains("403")
                    || message.contains("invalid Google Chat Pub/Sub");
                if let Ok(state) = store.update_messaging_gateway_adapter_state(
                    Some(if fatal { "error" } else { "reconnecting" }),
                    Some(json!({
                        "type": "google_chat_pubsub_error",
                        "platform": "google_chat",
                        "retryable": !fatal,
                        "listenUrl": listen_url,
                    })),
                    Some(format!("Google Chat Pub/Sub pull failed: {message}")),
                    0,
                    0,
                ) {
                    emit_platform_adapter_event(&app, "stream_error", "google_chat", &state);
                }
                if fatal {
                    return;
                }
                backoff_seconds = (backoff_seconds * 2).min(30);
            }
        }
        tokio::time::sleep(Duration::from_secs(backoff_seconds)).await;
    }
}

async fn messaging_gateway_google_chat_pubsub_once(
    app: &AppHandle,
    store: &AppStore,
    settings: &MessagingGatewayReceiveSettings,
    listen_url: &str,
) -> AppResult<usize> {
    let app_config = store.config()?;
    if !platform_config_enabled(&app_config.messaging_gateway)
        || !settings.platforms.contains("google_chat")
        || !messaging_gateway_platform_enabled(&app_config.messaging_gateway, "google_chat")
    {
        return Ok(0);
    }
    let google_settings = google_chat_settings(&app_config.google_chat)?;
    let subscription = google_chat_pubsub_subscription_name(&app_config.google_chat)?;
    let client = google_chat_client(&google_settings)?;
    let token = google_chat_access_token(&client, &google_settings).await?;
    let pull_url = google_chat_pubsub_url(&google_settings, &subscription, "pull")?;
    let max_messages = google_chat_pubsub_max_messages(&app_config.google_chat);
    let response = client
        .post(pull_url)
        .bearer_auth(&token)
        .json(&json!({
            "maxMessages": max_messages,
            "returnImmediately": true
        }))
        .send()
        .await
        .map_err(|error| {
            AppError::BadRequest(format!("Google Chat Pub/Sub pull request failed: {error}"))
        })?;
    let value = google_chat_response_json(response, "Google Chat Pub/Sub pull").await?;
    let received = value
        .get("receivedMessages")
        .or_else(|| value.get("received_messages"))
        .and_then(Value::as_array)
        .cloned()
        .unwrap_or_default();
    if received.is_empty() {
        if let Ok(state) = store.update_messaging_gateway_adapter_state(
            Some("running"),
            Some(json!({
                "type": "google_chat_pubsub_idle",
                "platform": "google_chat",
                "listenUrl": listen_url,
            })),
            None,
            0,
            0,
        ) {
            emit_platform_adapter_event(app, "stream_idle", "google_chat", &state);
        }
        return Ok(0);
    }
    let received_len = received.len();
    let mut ack_ids = Vec::new();
    let mut processed = 0_usize;
    for item in received {
        if let Some(ack_id) = item
            .get("ackId")
            .or_else(|| item.get("ack_id"))
            .and_then(Value::as_str)
        {
            ack_ids.push(ack_id.to_string());
        }
        let Some(envelope) = google_chat_pubsub_received_message_envelope(&item)? else {
            continue;
        };
        if let Some(inbound) = google_chat_inbound_event_from_pubsub_envelope(&envelope, None) {
            let payload = google_chat_pubsub_inbound_as_gateway_payload(inbound);
            messaging_gateway_process_payload(app, store, settings, payload).await?;
            processed += 1;
        }
    }
    let ack_count = ack_ids.len();
    if !ack_ids.is_empty() {
        let ack_url = google_chat_pubsub_url(&google_settings, &subscription, "acknowledge")?;
        let response = client
            .post(ack_url)
            .bearer_auth(&token)
            .json(&json!({ "ackIds": ack_ids }))
            .send()
            .await
            .map_err(|error| {
                AppError::BadRequest(format!("Google Chat Pub/Sub ack request failed: {error}"))
            })?;
        let _ = google_chat_response_json(response, "Google Chat Pub/Sub ack").await?;
    }
    if let Ok(state) = store.update_messaging_gateway_adapter_state(
        Some("running"),
        Some(json!({
            "type": "google_chat_pubsub_pull",
            "platform": "google_chat",
            "received": processed,
            "acknowledged": ack_count,
            "listenUrl": listen_url,
        })),
        None,
        received_len as u64,
        processed as u64,
    ) {
        emit_platform_adapter_event(app, "stream_message", "google_chat", &state);
    }
    Ok(processed)
}

async fn messaging_gateway_ntfy_stream_once(
    app: &AppHandle,
    store: &AppStore,
    settings: &MessagingGatewayReceiveSettings,
    listen_url: &str,
) -> AppResult<()> {
    let app_config = store.config()?;
    if !platform_config_enabled(&app_config.messaging_gateway)
        || !settings.platforms.contains("ntfy")
        || !messaging_gateway_platform_enabled(&app_config.messaging_gateway, "ntfy")
    {
        return Ok(());
    }
    let ntfy_settings = ntfy_settings(&app_config.ntfy)?;
    let Some(topic) = ntfy_subscribe_topic(&ntfy_settings) else {
        return Err(AppError::BadRequest(
            "ntfy streaming receive requires topic, subscribeTopic, homeChannel, or publishTopic"
                .into(),
        ));
    };
    let url = ntfy_subscribe_url(&ntfy_settings, &topic)?;
    let client = ntfy_stream_client()?;
    let mut request = client.get(url.clone()).query(&[("poll", "false")]);
    for (key, value) in ntfy_auth_headers(&ntfy_settings) {
        request = request.header(key, value);
    }
    let response = request
        .send()
        .await
        .map_err(|error| AppError::BadRequest(format!("ntfy stream connect failed: {error}")))?;
    let status = response.status();
    if status.as_u16() == 401 || status.as_u16() == 404 {
        return Err(AppError::BadRequest(format!(
            "ntfy stream returned HTTP {}",
            status.as_u16()
        )));
    }
    if !status.is_success() {
        return Err(AppError::BadRequest(format!(
            "ntfy stream returned HTTP {}",
            status.as_u16()
        )));
    }
    if let Ok(state) = store.update_messaging_gateway_adapter_state(
        Some("running"),
        Some(json!({
            "type": "ntfy_stream_connected",
            "platform": "ntfy",
            "topic": topic,
            "streamUrl": url.as_str(),
            "listenUrl": listen_url,
        })),
        None,
        0,
        0,
    ) {
        emit_platform_adapter_event(app, "stream_connected", "ntfy", &state);
    }
    let mut stream = response.bytes_stream();
    let mut buffer = String::new();
    while let Some(chunk) = stream.next().await {
        let chunk = chunk
            .map_err(|error| AppError::BadRequest(format!("ntfy stream read failed: {error}")))?;
        buffer.push_str(&String::from_utf8_lossy(&chunk));
        while let Some(index) = buffer.find('\n') {
            let line = buffer[..index].trim().to_string();
            buffer = buffer[index + 1..].to_string();
            messaging_gateway_process_ntfy_stream_line(app, store, settings, &line).await?;
        }
    }
    let trailing = buffer.trim().to_string();
    if !trailing.is_empty() {
        messaging_gateway_process_ntfy_stream_line(app, store, settings, &trailing).await?;
    }
    Ok(())
}

async fn messaging_gateway_process_ntfy_stream_line(
    app: &AppHandle,
    store: &AppStore,
    settings: &MessagingGatewayReceiveSettings,
    line: &str,
) -> AppResult<()> {
    if line.trim().is_empty() {
        return Ok(());
    }
    let payload = serde_json::from_str::<Value>(line)
        .map_err(|error| AppError::BadRequest(format!("invalid ntfy stream JSON: {error}")))?;
    if payload.get("event").and_then(Value::as_str) != Some("message") {
        let state = store.update_messaging_gateway_adapter_state(
            Some("running"),
            Some(json!({
                "type": "ntfy_stream_keepalive",
                "platform": "ntfy",
                "event": payload.get("event").cloned().unwrap_or(Value::Null),
            })),
            None,
            0,
            0,
        )?;
        emit_platform_adapter_event(app, "stream_keepalive", "ntfy", &state);
        return Ok(());
    }
    messaging_gateway_process_payload(app, store, settings, payload)
        .await
        .map(|_| ())
}

