async fn messaging_gateway_simplex_stream_loop(
    app: AppHandle,
    store: AppStore,
    settings: MessagingGatewayReceiveSettings,
    listen_url: String,
) {
    let mut backoff_seconds = 1_u64;
    loop {
        let result =
            messaging_gateway_simplex_stream_once(&app, &store, &settings, &listen_url).await;
        match result {
            Ok(()) => {
                backoff_seconds = 1;
            }
            Err(error) => {
                let message = error.to_string();
                if let Ok(state) = store.update_messaging_gateway_adapter_state(
                    Some("reconnecting"),
                    Some(json!({
                        "type": "simplex_stream_error",
                        "platform": "simplex",
                        "retryable": true,
                        "listenUrl": listen_url,
                    })),
                    Some(format!("SimpleX stream failed: {message}")),
                    0,
                    0,
                ) {
                    emit_platform_adapter_event(&app, "stream_error", "simplex", &state);
                }
            }
        }
        tokio::time::sleep(Duration::from_secs(backoff_seconds)).await;
        backoff_seconds = (backoff_seconds * 2).min(30);
    }
}

async fn messaging_gateway_simplex_stream_once(
    app: &AppHandle,
    store: &AppStore,
    settings: &MessagingGatewayReceiveSettings,
    listen_url: &str,
) -> AppResult<()> {
    let app_config = store.config()?;
    if !platform_config_enabled(&app_config.messaging_gateway)
        || !settings.platforms.contains("simplex")
        || !messaging_gateway_platform_enabled(&app_config.messaging_gateway, "simplex")
    {
        return Ok(());
    }
    let simplex_settings = simplex_settings(&app_config.simplex)?;
    let connect = connect_async(&simplex_settings.ws_url);
    let (mut ws, _) = tokio::time::timeout(
        Duration::from_secs(simplex_settings.timeout_seconds),
        connect,
    )
    .await
    .map_err(|_| AppError::BadRequest("SimpleX WebSocket listener connect timed out".into()))?
    .map_err(|error| {
        AppError::BadRequest(format!(
            "SimpleX WebSocket listener connect failed: {error}"
        ))
    })?;
    if let Ok(state) = store.update_messaging_gateway_adapter_state(
        Some("running"),
        Some(json!({
            "type": "simplex_stream_connected",
            "platform": "simplex",
            "wsUrl": simplex_settings.ws_url,
            "listenUrl": listen_url,
        })),
        None,
        0,
        0,
    ) {
        emit_platform_adapter_event(app, "stream_connected", "simplex", &state);
    }
    while let Some(message) = ws.next().await {
        let message = message.map_err(|error| {
            AppError::BadRequest(format!("SimpleX stream read failed: {error}"))
        })?;
        messaging_gateway_process_simplex_ws_message(app, store, settings, message).await?;
    }
    Ok(())
}

async fn messaging_gateway_process_simplex_ws_message(
    app: &AppHandle,
    store: &AppStore,
    settings: &MessagingGatewayReceiveSettings,
    message: WsMessage,
) -> AppResult<()> {
    let text = match message {
        WsMessage::Text(text) => text.to_string(),
        WsMessage::Binary(bytes) => String::from_utf8_lossy(&bytes).to_string(),
        WsMessage::Ping(_) | WsMessage::Pong(_) => {
            let state = store.update_messaging_gateway_adapter_state(
                Some("running"),
                Some(json!({
                    "type": "simplex_stream_keepalive",
                    "platform": "simplex",
                })),
                None,
                0,
                0,
            )?;
            emit_platform_adapter_event(app, "stream_keepalive", "simplex", &state);
            return Ok(());
        }
        WsMessage::Close(_) => return Ok(()),
        WsMessage::Frame(_) => return Ok(()),
    };
    let payload = serde_json::from_str::<Value>(&text)
        .map_err(|error| AppError::BadRequest(format!("invalid SimpleX stream JSON: {error}")))?;
    if messaging_gateway_simplex_payload_like(&payload) {
        messaging_gateway_process_payload(app, store, settings, payload)
            .await
            .map(|_| ())
    } else {
        let state = store.update_messaging_gateway_adapter_state(
            Some("running"),
            Some(json!({
                "type": "simplex_stream_ignored",
                "platform": "simplex",
                "event": payload.get("type").or_else(|| payload.get("resp").and_then(|resp| resp.get("type"))).cloned().unwrap_or(Value::Null),
            })),
            None,
            0,
            0,
        )?;
        emit_platform_adapter_event(app, "stream_ignored", "simplex", &state);
        Ok(())
    }
}

fn messaging_gateway_irc_stream_future(
    app: AppHandle,
    store: AppStore,
    settings: MessagingGatewayReceiveSettings,
    listen_url: String,
) -> Pin<Box<dyn Future<Output = ()> + Send>> {
    Box::pin(async move {
        if settings.platforms.contains("irc") {
            messaging_gateway_irc_stream_loop(app, store, settings, listen_url).await;
        } else {
            futures::future::pending::<()>().await;
        }
    })
}

async fn messaging_gateway_irc_stream_loop(
    app: AppHandle,
    store: AppStore,
    settings: MessagingGatewayReceiveSettings,
    listen_url: String,
) {
    let mut backoff_seconds = 1_u64;
    loop {
        let result = messaging_gateway_irc_stream_once(&app, &store, &settings, &listen_url).await;
        match result {
            Ok(()) => {
                backoff_seconds = 1;
            }
            Err(error) => {
                let message = error.to_string();
                if let Ok(state) = store.update_messaging_gateway_adapter_state(
                    Some("reconnecting"),
                    Some(json!({
                        "type": "irc_stream_error",
                        "platform": "irc",
                        "retryable": true,
                        "listenUrl": listen_url,
                    })),
                    Some(format!("IRC stream failed: {message}")),
                    0,
                    0,
                ) {
                    emit_platform_adapter_event(&app, "stream_error", "irc", &state);
                }
            }
        }
        tokio::time::sleep(Duration::from_secs(backoff_seconds)).await;
        backoff_seconds = (backoff_seconds * 2).min(30);
    }
}

async fn messaging_gateway_irc_stream_once(
    app: &AppHandle,
    store: &AppStore,
    settings: &MessagingGatewayReceiveSettings,
    listen_url: &str,
) -> AppResult<()> {
    let app_config = store.config()?;
    if !platform_config_enabled(&app_config.messaging_gateway)
        || !settings.platforms.contains("irc")
        || !messaging_gateway_platform_enabled(&app_config.messaging_gateway, "irc")
    {
        return Ok(());
    }
    let irc_settings = irc_settings(&app_config.irc)?;
    let timeout = Duration::from_secs(irc_settings.timeout_seconds);
    let tcp = tokio::time::timeout(
        timeout,
        TcpStream::connect((&*irc_settings.server, irc_settings.port)),
    )
    .await
    .map_err(|_| AppError::BadRequest("IRC listener connect timed out".into()))?
    .map_err(|error| AppError::BadRequest(format!("IRC listener connect failed: {error}")))?;
    let stream: Box<dyn IrcIo> = if irc_settings.use_tls {
        let connector = native_tls::TlsConnector::new()
            .map_err(|error| AppError::BadRequest(format!("IRC TLS setup failed: {error}")))?;
        let connector = TokioTlsConnector::from(connector);
        Box::new(
            tokio::time::timeout(timeout, connector.connect(&irc_settings.server, tcp))
                .await
                .map_err(|_| AppError::BadRequest("IRC TLS handshake timed out".into()))?
                .map_err(|error| {
                    AppError::BadRequest(format!("IRC TLS handshake failed: {error}"))
                })?,
        )
    } else {
        Box::new(tcp)
    };
    let (reader, mut writer) = tokio::io::split(stream);
    let mut reader = BufReader::new(reader);
    let mut current_nick = irc_settings.nickname.clone();
    messaging_gateway_irc_register(&mut reader, &mut writer, &irc_settings, &mut current_nick)
        .await?;
    if let Some(password) = irc_settings.nickserv_password.as_ref() {
        irc_write_raw(
            &mut writer,
            &format!(
                "PRIVMSG NickServ :IDENTIFY {}",
                irc_strip_control_chars(password)
            ),
        )
        .await?;
        tokio::time::sleep(Duration::from_millis(200)).await;
    }
    irc_write_raw(&mut writer, &format!("JOIN {}", irc_settings.channel)).await?;
    if let Ok(state) = store.update_messaging_gateway_adapter_state(
        Some("running"),
        Some(json!({
            "type": "irc_stream_connected",
            "platform": "irc",
            "server": irc_settings.server,
            "port": irc_settings.port,
            "nick": current_nick,
            "channel": irc_settings.channel,
            "listenUrl": listen_url,
        })),
        None,
        0,
        0,
    ) {
        emit_platform_adapter_event(app, "stream_connected", "irc", &state);
    }
    loop {
        let mut line = String::new();
        let bytes = reader
            .read_line(&mut line)
            .await
            .map_err(|error| AppError::BadRequest(format!("IRC stream read failed: {error}")))?;
        if bytes == 0 {
            return Ok(());
        }
        let line = line.trim_end_matches(['\r', '\n']).to_string();
        messaging_gateway_process_irc_line(app, store, settings, &mut writer, &current_nick, &line)
            .await?;
    }
}

async fn messaging_gateway_irc_register<R, W>(
    reader: &mut BufReader<R>,
    writer: &mut W,
    settings: &IrcSettings,
    current_nick: &mut String,
) -> AppResult<()>
where
    R: AsyncRead + Unpin,
    W: AsyncWrite + Unpin,
{
    if let Some(password) = settings.server_password.as_ref() {
        irc_write_raw(
            writer,
            &format!("PASS {}", irc_strip_control_chars(password)),
        )
        .await?;
    }
    irc_write_raw(writer, &format!("NICK {current_nick}")).await?;
    irc_write_raw(writer, &format!("USER {current_nick} 0 * :Hermes Agent")).await?;
    let mut nick_attempts = 0usize;
    let deadline = tokio::time::Instant::now() + Duration::from_secs(settings.timeout_seconds);
    loop {
        let Some(line) = irc_read_line_until(reader, deadline).await? else {
            return Err(AppError::BadRequest(
                "IRC listener: server closed connection during registration".into(),
            ));
        };
        let message = irc_parse_message(&line);
        match message.command.as_str() {
            "PING" => {
                let payload = message.params.first().cloned().unwrap_or_default();
                irc_write_raw(writer, &format!("PONG :{payload}")).await?;
            }
            "001" => {
                if let Some(nick) = message.params.first() {
                    *current_nick = nick.clone();
                }
                return Ok(());
            }
            "432" | "433" => {
                nick_attempts += 1;
                if nick_attempts > 5 {
                    return Err(AppError::BadRequest(
                        "IRC listener: too many nick collisions".into(),
                    ));
                }
                *current_nick = format!("{}_{nick_attempts}", irc_nick_base(&settings.nickname));
                current_nick.truncate(30);
                irc_write_raw(writer, &format!("NICK {current_nick}")).await?;
            }
            "464" | "465" => {
                return Err(AppError::BadRequest(format!(
                    "IRC listener: server rejected client ({})",
                    message.command
                )));
            }
            _ => {}
        }
    }
}

async fn messaging_gateway_process_irc_line<W>(
    app: &AppHandle,
    store: &AppStore,
    settings: &MessagingGatewayReceiveSettings,
    writer: &mut W,
    current_nick: &str,
    line: &str,
) -> AppResult<()>
where
    W: AsyncWrite + Unpin,
{
    let message = irc_parse_message(line);
    if message.command.eq_ignore_ascii_case("PING") {
        let payload = message.params.first().cloned().unwrap_or_default();
        irc_write_raw(writer, &format!("PONG :{payload}")).await?;
        let state = store.update_messaging_gateway_adapter_state(
            Some("running"),
            Some(json!({
                "type": "irc_stream_keepalive",
                "platform": "irc",
            })),
            None,
            0,
            0,
        )?;
        emit_platform_adapter_event(app, "stream_keepalive", "irc", &state);
        return Ok(());
    }
    if !message.command.eq_ignore_ascii_case("PRIVMSG") || message.params.len() < 2 {
        return Ok(());
    }
    let sender_nick = message
        .prefix
        .as_deref()
        .and_then(|prefix| prefix.split('!').next())
        .unwrap_or_default();
    if sender_nick.eq_ignore_ascii_case(current_nick) {
        return Ok(());
    }
    let target = message.params.first().cloned().unwrap_or_default();
    let mut text = message.params.get(1).cloned().unwrap_or_default();
    if text.starts_with('\u{1}') {
        if text.starts_with("\u{1}ACTION ") && text.ends_with('\u{1}') {
            text = format!(
                "* {sender_nick} {}",
                text[8..text.len().saturating_sub(1)].trim()
            );
        } else {
            return Ok(());
        }
    }
    let payload = json!({
        "platform": "irc",
        "raw": line,
        "command": "PRIVMSG",
        "nick": sender_nick,
        "target": target,
        "text": text,
    });
    messaging_gateway_process_payload(app, store, settings, payload)
        .await
        .map(|_| ())
}

async fn messaging_gateway_handle_connection(
    app: AppHandle,
    store: AppStore,
    settings: MessagingGatewayReceiveSettings,
    mut stream: TcpStream,
) -> AppResult<()> {
    let mut buffer = vec![0_u8; 1024 * 1024];
    let read = tokio::time::timeout(
        Duration::from_secs(settings.timeout_seconds),
        stream.read(&mut buffer),
    )
    .await
    .map_err(|_| AppError::BadRequest("Messaging gateway request read timed out".into()))?
    .map_err(|error| {
        AppError::BadRequest(format!("Messaging gateway request read failed: {error}"))
    })?;
    let request = String::from_utf8_lossy(&buffer[..read]).to_string();
    let parsed = webhook_parse_request(&request);
    let status = match parsed {
        Ok(parsed) => messaging_gateway_process_request(&app, &store, &settings, parsed).await,
        Err(error) => Err(error),
    };
    let (code, body) = match status {
        Ok(value) => (200, value),
        Err(error) => (400, json!({"ok": false, "error": error.to_string()})),
    };
    let body_text = body.to_string();
    let response = format!(
        "HTTP/1.1 {code} {}\r\nContent-Type: application/json\r\nContent-Length: {}\r\nConnection: close\r\n\r\n{}",
        if code == 200 { "OK" } else { "Bad Request" },
        body_text.len(),
        body_text
    );
    stream
        .write_all(response.as_bytes())
        .await
        .map_err(|error| {
            AppError::BadRequest(format!("Messaging gateway response write failed: {error}"))
        })?;
    Ok(())
}

async fn messaging_gateway_process_request(
    app: &AppHandle,
    store: &AppStore,
    settings: &MessagingGatewayReceiveSettings,
    request: ParsedWebhookRequest,
) -> AppResult<Value> {
    if request.method != "POST" {
        return Err(AppError::BadRequest(
            "Messaging gateway webhook only accepts POST".into(),
        ));
    }
    let request_path = request.path.split('?').next().unwrap_or(&request.path);
    if request_path != settings.path {
        return Err(AppError::BadRequest(format!(
            "Messaging gateway path mismatch: expected {}, got {}",
            settings.path, request_path
        )));
    }
    if let Some(secret) = settings.secret.as_deref() {
        let provided = request
            .headers
            .get("x-messaging-gateway-secret")
            .or_else(|| request.headers.get("x-synthchat-webhook-secret"))
            .or_else(|| request.headers.get("x-hermes-webhook-secret"))
            .or_else(|| request.headers.get("x-webhook-secret"))
            .map(String::as_str)
            .unwrap_or_default();
        if provided != secret {
            return Err(AppError::BadRequest(
                "Messaging gateway secret mismatch".into(),
            ));
        }
    }
    let payload = messaging_gateway_parse_inbound_body(&request)?;
    messaging_gateway_verify_line_signature(store, settings, &request, &payload)?;
    messaging_gateway_process_payload(app, store, settings, payload).await
}

async fn messaging_gateway_process_payload(
    app: &AppHandle,
    store: &AppStore,
    settings: &MessagingGatewayReceiveSettings,
    payload: Value,
) -> AppResult<Value> {
    let config = store.config()?.messaging_gateway;
    if let Some(result) =
        messaging_gateway_handle_qqbot_interaction(store, Some(app), &payload, &config, settings)
            .await?
    {
        return Ok(result);
    }
    if let Some(result) =
        messaging_gateway_handle_teams_invoke(store, Some(app), &payload, &config, settings).await?
    {
        return Ok(result);
    }
    let Some(inbound) = messaging_gateway_inbound_event_from_payload(&payload, &config, settings)
    else {
        let state = store.update_messaging_gateway_adapter_state(
            Some("running"),
            Some(json!({"type": "ignored_message"})),
            None,
            1,
            0,
        )?;
        emit_platform_adapter_event(app, "inbound_ignored", "messaging_gateway", &state);
        return Ok(json!({"ok": true, "ignored": "message"}));
    };
    let platform = inbound
        .get("platform")
        .and_then(Value::as_str)
        .unwrap_or("messaging_gateway")
        .to_string();
    let inbound_fallback = inbound.clone();
    let inbound = messaging_gateway_enrich_inbound_files(store, inbound)
        .await
        .unwrap_or_else(|error| {
            let mut fallback = inbound_fallback;
            fallback["fileDownloadError"] = json!(error.to_string());
            fallback["file_download_error"] = json!(error.to_string());
            fallback
        });
    if platform == "google_chat" {
        if let Some(result) =
            messaging_gateway_handle_google_chat_setup_files(store, Some(app), &inbound).await?
        {
            let state = store.update_messaging_gateway_adapter_state(
                Some("running"),
                Some(result.clone()),
                None,
                1,
                0,
            )?;
            emit_platform_adapter_event(app, "inbound_setup_files", &platform, &state);
            return Ok(json!({
                "ok": true,
                "platform": platform,
                "handled": "setup-files",
                "result": result,
            }));
        }
    }
    if platform == "line" {
        if let Some(result) =
            messaging_gateway_handle_line_postback(store, &payload, &inbound).await?
        {
            let state = store.update_messaging_gateway_adapter_state(
                Some("running"),
                Some(result.clone()),
                None,
                1,
                0,
            )?;
            emit_platform_adapter_event(app, "line_postback_handled", &platform, &state);
            return Ok(json!({
                "ok": true,
                "platform": platform,
                "handled": "line-postback",
                "result": result,
            }));
        }
    }
    if let Some(denial) = messaging_gateway_slash_access_denial(store, &config, &inbound)? {
        let state = store.update_messaging_gateway_adapter_state(
            Some("running"),
            Some(denial.clone()),
            None,
            1,
            0,
        )?;
        emit_platform_adapter_event(app, "inbound_denied", &platform, &state);
        return Ok(json!({
            "ok": true,
            "platform": platform,
            "skipped": true,
            "denied": "slash_access",
            "command": denial.get("command").cloned().unwrap_or(Value::Null),
        }));
    }
    let prompt = messaging_gateway_inbound_prompt(&inbound);
    let Some(prompt) = apply_pre_gateway_dispatch_hooks(store, &platform, &inbound, prompt).await
    else {
        let state = store.update_messaging_gateway_adapter_state(
            Some("running"),
            Some(inbound),
            None,
            1,
            0,
        )?;
        emit_platform_adapter_event(app, "inbound_ignored", &platform, &state);
        return Ok(json!({"ok": true, "platform": platform, "skipped": true}));
    };
    let conversation_id =
        messaging_gateway_inbound_conversation_id(store, &config, &platform, &inbound)?;
    record_messaging_gateway_origin_metadata(store, &conversation_id, &inbound)?;
    if platform == "line" {
        messaging_gateway_schedule_line_slow_postback(app, store, &conversation_id, &inbound);
    }
    let persona_id = messaging_gateway_inbound_persona_id(store, &config)?;
    let state =
        store.update_messaging_gateway_adapter_state(Some("running"), Some(inbound), None, 1, 1)?;
    emit_platform_adapter_event(app, "inbound_triggered", &platform, &state);
    spawn_background_chat_turn_for_job(app.clone(), conversation_id, persona_id, prompt, None);
    Ok(json!({"ok": true, "platform": platform}))
}

pub(super) fn messaging_gateway_slash_access_denial(
    store: &AppStore,
    config: &Value,
    inbound: &Value,
) -> AppResult<Option<Value>> {
    let text = inbound.get("text").and_then(Value::as_str).unwrap_or("");
    let Some(command) = messaging_gateway_registered_slash_command(store, text)? else {
        return Ok(None);
    };
    let platform = inbound
        .get("platform")
        .and_then(Value::as_str)
        .unwrap_or("messaging_gateway");
    let source = inbound.get("source").unwrap_or(&Value::Null);
    let chat_type = string_arg(source, &["chatType", "chat_type"]).unwrap_or_else(|| "dm".into());
    let user_id = string_arg(source, &["userId", "user_id"]);
    let policy = messaging_gateway_slash_access_policy(config, platform, &chat_type);
    if policy.can_run(user_id.as_deref(), &command) {
        return Ok(None);
    }
    Ok(Some(json!({
        "type": "slash_access_denied",
        "platform": platform,
        "command": command,
        "userId": user_id,
        "user_id": user_id,
        "chatType": chat_type,
        "chat_type": chat_type,
        "policy": policy.to_json(),
    })))
}

fn messaging_gateway_registered_slash_command(
    store: &AppStore,
    text: &str,
) -> AppResult<Option<String>> {
    let trimmed = text.trim_start();
    if !(trimmed.starts_with('/') || trimmed.starts_with('／')) {
        return Ok(None);
    }
    let raw = trimmed
        .trim_start_matches('/')
        .trim_start_matches('／')
        .split_whitespace()
        .next()
        .unwrap_or("");
    let token = messaging_gateway_normalize_slash_command(raw);
    if token.is_empty() {
        return Ok(None);
    }
    for command in list_agent_control_commands() {
        if command.name == token || command.aliases.iter().any(|alias| alias == &token) {
            return Ok(Some(command.name));
        }
    }
    let plugin_commands = list_python_plugin_commands(store)?;
    Ok(plugin_commands
        .into_iter()
        .find(|command| messaging_gateway_normalize_slash_command(&command.name) == token)
        .map(|command| messaging_gateway_normalize_slash_command(&command.name)))
}

fn messaging_gateway_normalize_slash_command(value: &str) -> String {
    value
        .trim()
        .trim_start_matches('/')
        .trim_start_matches('／')
        .split('@')
        .next()
        .unwrap_or("")
        .trim()
        .to_ascii_lowercase()
}

#[derive(Debug, Clone)]
pub(super) struct MessagingGatewaySlashAccessPolicy {
    enabled: bool,
    admin_user_ids: HashSet<String>,
    user_allowed_commands: HashSet<String>,
    scope: String,
}

impl MessagingGatewaySlashAccessPolicy {
    fn can_run(&self, user_id: Option<&str>, command: &str) -> bool {
        if !self.enabled {
            return true;
        }
        if user_id
            .map(|id| self.admin_user_ids.contains(id))
            .unwrap_or(false)
        {
            return true;
        }
        if matches!(command, "help" | "profile" | "doctor") {
            return true;
        }
        self.user_allowed_commands.contains(command)
    }

    pub(super) fn to_json(&self) -> Value {
        let mut admins = self.admin_user_ids.iter().cloned().collect::<Vec<_>>();
        admins.sort();
        let mut commands = self
            .user_allowed_commands
            .iter()
            .cloned()
            .collect::<Vec<_>>();
        commands.sort();
        json!({
            "enabled": self.enabled,
            "scope": self.scope,
            "adminUserCount": admins.len(),
            "adminUserIds": admins,
            "userAllowedCommands": commands,
            "alwaysAllowedForUsers": ["help", "profile", "doctor"],
        })
    }
}

pub(super) fn messaging_gateway_slash_access_policy(
    config: &Value,
    platform: &str,
    chat_type: &str,
) -> MessagingGatewaySlashAccessPolicy {
    let scope = if matches!(
        chat_type.to_ascii_lowercase().as_str(),
        "group" | "room" | "chat" | "channel" | "thread"
    ) {
        "group"
    } else {
        "dm"
    };
    let mut extra = messaging_gateway_platform_extra(config, platform);
    let admin_key = if scope == "group" {
        "group_allow_admin_from"
    } else {
        "allow_admin_from"
    };
    let command_key = if scope == "group" {
        "group_user_allowed_commands"
    } else {
        "user_allowed_commands"
    };
    let admin_user_ids = messaging_gateway_string_set(extra.remove(admin_key));
    let mut user_allowed_commands = messaging_gateway_command_set(extra.remove(command_key));
    if scope == "dm" && user_allowed_commands.is_empty() {
        user_allowed_commands =
            messaging_gateway_command_set(extra.remove("group_user_allowed_commands"));
    }
    MessagingGatewaySlashAccessPolicy {
        enabled: !admin_user_ids.is_empty(),
        admin_user_ids,
        user_allowed_commands,
        scope: scope.into(),
    }
}

fn messaging_gateway_platform_extra(
    config: &Value,
    platform: &str,
) -> serde_json::Map<String, Value> {
    let mut extra = serde_json::Map::new();
    if let Some(map) = config.as_object() {
        for (key, value) in map {
            if !matches!(
                key.as_str(),
                "platformConfigs" | "platform_configs" | "platformSettings" | "platform_settings"
            ) {
                extra.insert(key.clone(), value.clone());
            }
        }
    }
    for key in [
        "platformConfigs",
        "platform_configs",
        "platformSettings",
        "platform_settings",
        "platforms",
    ] {
        if let Some(value) = config
            .get(key)
            .and_then(Value::as_object)
            .and_then(|platforms| platforms.get(platform))
            .and_then(Value::as_object)
        {
            for (child_key, child_value) in value {
                extra.insert(child_key.clone(), child_value.clone());
            }
        }
    }
    if let Some(value) = config.get(platform).and_then(Value::as_object) {
        for (child_key, child_value) in value {
            extra.insert(child_key.clone(), child_value.clone());
        }
    }
    extra
}

fn messaging_gateway_string_set(value: Option<Value>) -> HashSet<String> {
    match value {
        Some(Value::Array(items)) => items
            .into_iter()
            .filter_map(|item| item.as_str().map(str::trim).map(str::to_string))
            .filter(|item| !item.is_empty())
            .collect(),
        Some(Value::String(value)) => value
            .split(',')
            .map(str::trim)
            .filter(|item| !item.is_empty())
            .map(str::to_string)
            .collect(),
        Some(other) => other
            .as_str()
            .map(str::trim)
            .filter(|item| !item.is_empty())
            .map(str::to_string)
            .into_iter()
            .collect(),
        None => HashSet::new(),
    }
}

fn messaging_gateway_command_set(value: Option<Value>) -> HashSet<String> {
    messaging_gateway_string_set(value)
        .into_iter()
        .filter_map(|command| {
            let token = messaging_gateway_normalize_slash_command(&command);
            list_agent_control_commands()
                .into_iter()
                .find(|registered| {
                    registered.name == token
                        || registered.aliases.iter().any(|alias| alias == &token)
                })
                .map(|registered| registered.name)
                .or_else(|| (!token.is_empty()).then_some(token))
        })
        .collect()
}

pub(super) async fn messaging_gateway_handle_qqbot_interaction(
    store: &AppStore,
    app: Option<&AppHandle>,
    payload: &Value,
    config: &Value,
    settings: &MessagingGatewayReceiveSettings,
) -> AppResult<Option<Value>> {
    if !settings.platforms.contains("qqbot") || !messaging_gateway_platform_enabled(config, "qqbot")
    {
        return Ok(None);
    }
    let Some(event) = messaging_gateway_qqbot_interaction_event(payload) else {
        return Ok(None);
    };
    let qqbot_settings = qqbot_settings(&store.config()?.qqbot)?;
    let client = qqbot_client(&qqbot_settings)?;
    let access_token = qqbot_access_token(&client, &qqbot_settings).await?;
    qqbot_ack_interaction(&client, &qqbot_settings, &access_token, &event.id).await?;
    let dispatch = messaging_gateway_dispatch_qqbot_interaction(store, app, &event).await?;
    let state = store.update_messaging_gateway_adapter_state(
        Some("running"),
        Some(json!({
            "type": "qqbot_interaction",
            "interactionId": event.id,
            "channelId": event.channel_id,
            "buttonData": event.button_data,
            "dispatch": dispatch,
        })),
        None,
        1,
        0,
    )?;
    if let Some(app) = app {
        emit_platform_adapter_event(app, "interaction_handled", "qqbot", &state);
    }
    Ok(Some(json!({
        "ok": true,
        "platform": "qqbot",
        "interactionId": event.id,
        "dispatch": dispatch,
    })))
}

pub(super) async fn messaging_gateway_handle_teams_invoke(
    store: &AppStore,
    app: Option<&AppHandle>,
    payload: &Value,
    config: &Value,
    settings: &MessagingGatewayReceiveSettings,
) -> AppResult<Option<Value>> {
    if !settings.platforms.contains("teams") || !messaging_gateway_platform_enabled(config, "teams")
    {
        return Ok(None);
    }
    let Some(event) = messaging_gateway_teams_invoke_event(payload) else {
        return Ok(None);
    };
    let dispatch = messaging_gateway_dispatch_teams_invoke(store, app, config, &event).await?;
    let state = store.update_messaging_gateway_adapter_state(
        Some("running"),
        Some(json!({
            "type": "teams_invoke",
            "platform": "teams",
            "activityId": event.activity_id,
            "conversationId": event.conversation_id,
            "userId": event.user_id,
            "dispatch": dispatch,
        })),
        None,
        1,
        0,
    )?;
    if let Some(app) = app {
        emit_platform_adapter_event(app, "interaction_handled", "teams", &state);
    }
    let text = messaging_gateway_teams_invoke_response_text(&dispatch);
    Ok(Some(json!({
        "ok": true,
        "platform": "teams",
        "activityId": event.activity_id,
        "dispatch": dispatch,
        "invokeResponse": messaging_gateway_teams_invoke_response(&text),
    })))
}

async fn messaging_gateway_dispatch_teams_invoke(
    store: &AppStore,
    app: Option<&AppHandle>,
    config: &Value,
    event: &TeamsInvokeEvent,
) -> AppResult<Value> {
    let action = match event.hermes_action.as_str() {
        "approve_once" | "allow_once" | "once" => "once",
        "approve_session" | "allow_session" | "session" => "session",
        "approve_always" | "allow_always" | "always" => "always",
        "deny" => "deny",
        "" => {
            return Ok(json!({
                "handled": false,
                "reason": "missing_hermes_action",
            }));
        }
        other => {
            return Ok(json!({
                "handled": false,
                "reason": "unknown_approval_action",
                "hermesAction": other,
            }));
        }
    };
    if event.session_key.trim().is_empty() {
        return Ok(json!({
            "handled": false,
            "action": "approval",
            "reason": "missing_session_key",
        }));
    }
    if !messaging_gateway_teams_invoke_authorized(config, event) {
        return Ok(json!({
            "handled": false,
            "action": "approval",
            "reason": "unauthorized",
            "sessionKey": event.session_key,
            "userId": event.user_id,
        }));
    }
    let approval_ids = qqbot_pending_approval_ids_for_session(store, &event.session_key)?;
    if approval_ids.is_empty() {
        return Ok(json!({
            "handled": false,
            "action": "approval",
            "reason": "no_pending_approval",
            "sessionKey": event.session_key,
        }));
    }
    let mut resolved = Vec::new();
    for approval_id in approval_ids {
        if matches!(action, "once" | "session" | "always") {
            let approval = store.tool_approval(&approval_id)?;
            teams_spawn_approval_resolution(
                store.clone(),
                app.cloned(),
                approval_id.clone(),
                action.to_string(),
            );
            resolved.push(json!({
                "approvalId": approval.id,
                "status": approval.status,
                "serverId": approval.server_id,
                "toolName": approval.tool_name,
                "deferred": true,
            }));
            continue;
        }
        let approval = deny_tool_call_and_update_run(
            store,
            approval_id.clone(),
            Some("Denied from Teams Adaptive Card.".into()),
            app,
        )?;
        resolved.push(json!({
            "approvalId": approval.id,
            "status": approval.status,
            "serverId": approval.server_id,
            "toolName": approval.tool_name,
        }));
    }
    Ok(json!({
        "handled": true,
        "action": "approval",
        "choice": action,
        "sessionKey": event.session_key,
        "count": resolved.len(),
        "resolved": resolved,
    }))
}

fn teams_spawn_approval_resolution(
    store: AppStore,
    app: Option<AppHandle>,
    approval_id: String,
    action: String,
) {
    std::thread::spawn(move || {
        let Ok(runtime) = tokio::runtime::Builder::new_current_thread()
            .enable_all()
            .build()
        else {
            return;
        };
        let _ = runtime.block_on(async move {
            match action.as_str() {
                "once" | "session" => {
                    approve_tool_call_and_resume(&store, approval_id, None, app.as_ref())
                        .await
                        .map(|_| ())
                }
                "always" => {
                    approve_tool_call_always_and_resume(&store, approval_id, None, app.as_ref())
                        .await
                        .map(|_| ())
                }
                _ => Ok(()),
            }
        });
    });
}

#[derive(Debug, Clone)]
struct TeamsInvokeEvent {
    activity_id: String,
    conversation_id: String,
    user_id: String,
    hermes_action: String,
    session_key: String,
}

fn messaging_gateway_teams_invoke_event(payload: &Value) -> Option<TeamsInvokeEvent> {
    let activity = payload
        .get("activity")
        .or_else(|| payload.get("message"))
        .or_else(|| payload.get("event"))
        .filter(|value| value.is_object())
        .unwrap_or(payload);
    let activity_type = string_arg(activity, &["type"])
        .or_else(|| string_arg(payload, &["type"]))?
        .trim()
        .to_ascii_lowercase();
    if activity_type != "invoke" {
        return None;
    }
    let value = activity.get("value").or_else(|| payload.get("value"))?;
    let action = value.get("action").unwrap_or(value);
    let data = action.get("data").unwrap_or(action);
    Some(TeamsInvokeEvent {
        activity_id: string_arg(activity, &["id", "activityId", "activity_id"])
            .unwrap_or_else(|| new_id("teams-invoke")),
        conversation_id: activity
            .get("conversation")
            .and_then(|conversation| string_arg(conversation, &["id"]))
            .or_else(|| string_arg(activity, &["conversationId", "conversation_id", "chatId"]))
            .unwrap_or_default(),
        user_id: activity
            .get("from")
            .and_then(|from| {
                string_arg(
                    from,
                    &[
                        "aadObjectId",
                        "aad_object_id",
                        "userPrincipalName",
                        "user_principal_name",
                        "id",
                    ],
                )
            })
            .or_else(|| string_arg(activity, &["userId", "user_id", "from"]))
            .unwrap_or_default(),
        hermes_action: string_arg(data, &["hermes_action", "hermesAction", "action", "choice"])
            .unwrap_or_default()
            .trim()
            .to_ascii_lowercase(),
        session_key: string_arg(
            data,
            &["session_key", "sessionKey", "approval_id", "approvalId"],
        )
        .unwrap_or_default(),
    })
}

fn messaging_gateway_teams_invoke_authorized(config: &Value, event: &TeamsInvokeEvent) -> bool {
    if event.user_id.trim().is_empty() {
        return false;
    }
    let mut allowed = telegram_string_set(
        config,
        &["allowedUsers", "allowed_users"],
        "TEAMS_ALLOWED_USERS",
    );
    allowed.extend(messaging_gateway_string_set(
        messaging_gateway_platform_extra(config, "teams")
            .get("allowedUsers")
            .cloned(),
    ));
    allowed.extend(messaging_gateway_string_set(
        messaging_gateway_platform_extra(config, "teams")
            .get("allowed_users")
            .cloned(),
    ));
    if allowed.is_empty() {
        return false;
    }
    allowed.contains("*") || allowed.contains(&event.user_id)
}

fn messaging_gateway_teams_invoke_response_text(dispatch: &Value) -> String {
    match (
        dispatch.get("handled").and_then(Value::as_bool),
        dispatch.get("reason").and_then(Value::as_str),
        dispatch.get("choice").and_then(Value::as_str),
    ) {
        (Some(true), _, Some("deny")) => "Denied.".into(),
        (Some(true), _, Some("always")) => "Always allowed.".into(),
        (Some(true), _, Some("session")) => "Allowed for this session.".into(),
        (Some(true), _, Some(_)) => "Allowed once.".into(),
        (_, Some("unauthorized"), _) => "Not authorized.".into(),
        (_, Some("no_pending_approval"), _) => "Approval already resolved or expired.".into(),
        (_, Some(reason), _) => format!("Unable to resolve approval: {reason}."),
        _ => "Unknown action.".into(),
    }
}

fn messaging_gateway_teams_invoke_response(text: &str) -> Value {
    json!({
        "status": 200,
        "body": {
            "type": "application/vnd.microsoft.card.adaptive",
            "value": {
                "$schema": "http://adaptivecards.io/schemas/adaptive-card.json",
                "type": "AdaptiveCard",
                "version": "1.4",
                "body": [{
                    "type": "TextBlock",
                    "text": text,
                    "wrap": true,
                    "weight": "Bolder",
                }],
            },
        },
    })
}

async fn messaging_gateway_dispatch_qqbot_interaction(
    store: &AppStore,
    app: Option<&AppHandle>,
    event: &QqBotInteractionEvent,
) -> AppResult<Value> {
    if event.button_data.trim().is_empty() {
        return Ok(json!({"handled": false, "reason": "missing_button_data"}));
    }
    if let Some((session_key, decision)) = qqbot_parse_approval_button_data(&event.button_data) {
        let action = match decision.as_str() {
            "allow-once" => "once",
            "allow-always" => "always",
            "deny" => "deny",
            _ => {
                return Ok(json!({
                    "handled": false,
                    "reason": "unknown_approval_decision",
                    "decision": decision,
                }));
            }
        };
        if !qqbot_interaction_authorized_for_session(store, event, &session_key)? {
            return Ok(json!({
                "handled": false,
                "action": "approval",
                "reason": "unauthorized",
                "sessionKey": session_key,
                "operatorOpenid": event.operator_openid(),
            }));
        }
        let approval_ids = qqbot_pending_approval_ids_for_session(store, &session_key)?;
        if approval_ids.is_empty() {
            return Ok(json!({
                "handled": false,
                "action": "approval",
                "reason": "no_pending_approval",
                "sessionKey": session_key,
            }));
        }
        let mut resolved = Vec::new();
        for approval_id in approval_ids {
            if matches!(action, "once" | "always") {
                let approval = store.tool_approval(&approval_id)?;
                qqbot_spawn_approval_resolution(
                    store.clone(),
                    app.cloned(),
                    approval_id.clone(),
                    action.to_string(),
                );
                resolved.push(json!({
                    "approvalId": approval.id,
                    "status": approval.status,
                    "serverId": approval.server_id,
                    "toolName": approval.tool_name,
                    "deferred": true,
                }));
                continue;
            }
            let approval = match action {
                "once" => {
                    unreachable!()
                }
                "always" => {
                    unreachable!()
                }
                "deny" => deny_tool_call_and_update_run(
                    store,
                    approval_id.clone(),
                    Some("Denied from QQBot interaction.".into()),
                    app,
                )?,
                _ => unreachable!(),
            };
            resolved.push(json!({
                "approvalId": approval.id,
                "status": approval.status,
                "serverId": approval.server_id,
                "toolName": approval.tool_name,
            }));
        }
        return Ok(json!({
            "handled": true,
            "action": "approval",
            "choice": action,
            "sessionKey": session_key,
            "count": resolved.len(),
            "resolved": resolved,
        }));
    }
    if let Some(answer) = qqbot_parse_update_prompt_button_data(&event.button_data) {
        if event.operator_openid().trim().is_empty() {
            return Ok(json!({
                "handled": false,
                "action": "update_prompt",
                "reason": "missing_operator",
            }));
        }
        let path = qqbot_write_update_response(store, &answer)?;
        return Ok(json!({
            "handled": true,
            "action": "update_prompt",
            "answer": answer,
            "operatorOpenid": event.operator_openid(),
            "path": path.to_string_lossy(),
        }));
    }
    Ok(json!({
        "handled": false,
        "reason": "unrecognized_button_data",
        "buttonData": event.button_data,
    }))
}

fn qqbot_spawn_approval_resolution(
    store: AppStore,
    app: Option<AppHandle>,
    approval_id: String,
    action: String,
) {
    std::thread::spawn(move || {
        let Ok(runtime) = tokio::runtime::Builder::new_current_thread()
            .enable_all()
            .build()
        else {
            return;
        };
        let _ = runtime.block_on(async move {
            match action.as_str() {
                "once" => approve_tool_call_and_resume(&store, approval_id, None, app.as_ref())
                    .await
                    .map(|_| ()),
                "always" => {
                    approve_tool_call_always_and_resume(&store, approval_id, None, app.as_ref())
                        .await
                        .map(|_| ())
                }
                _ => Ok(()),
            }
        });
    });
}

#[derive(Debug, Clone)]
struct QqBotInteractionEvent {
    id: String,
    scene: String,
    group_openid: String,
    group_member_openid: String,
    user_openid: String,
    guild_id: String,
    channel_id: String,
    button_data: String,
    resolver_user_id: String,
}

impl QqBotInteractionEvent {
    fn operator_openid(&self) -> String {
        [
            &self.group_member_openid,
            &self.user_openid,
            &self.resolver_user_id,
        ]
        .into_iter()
        .find(|value| !value.trim().is_empty())
        .cloned()
        .unwrap_or_default()
    }

    fn chat_id(&self) -> String {
        match self.scene.as_str() {
            "c2c" => self.user_openid.clone(),
            "group" => self.group_openid.clone(),
            "guild" => self.guild_id.clone(),
            _ => self
                .group_openid
                .clone()
                .if_empty(self.guild_id.clone())
                .if_empty(self.user_openid.clone()),
        }
    }
}

trait IfEmpty {
    fn if_empty(self, fallback: String) -> String;
}

impl IfEmpty for String {
    fn if_empty(self, fallback: String) -> String {
        if self.trim().is_empty() {
            fallback
        } else {
            self
        }
    }
}

fn messaging_gateway_qqbot_interaction_event(payload: &Value) -> Option<QqBotInteractionEvent> {
    let event_type = string_arg(payload, &["t", "eventType", "event_type", "type"])?
        .trim()
        .to_ascii_uppercase();
    if event_type != "INTERACTION_CREATE" {
        return None;
    }
    let raw = payload
        .get("d")
        .or_else(|| payload.get("data").and_then(|data| data.get("d")))
        .filter(|value| value.is_object())
        .unwrap_or(payload);
    let null = Value::Null;
    let data = raw.get("data").unwrap_or(&null);
    let resolved = data.get("resolved").unwrap_or(&null);
    let chat_type = raw.get("chat_type").and_then(Value::as_i64).unwrap_or(0);
    let scene = string_arg(raw, &["scene"]).unwrap_or_else(|| match chat_type {
        1 => "group".into(),
        2 => "c2c".into(),
        _ => "guild".into(),
    });
    Some(QqBotInteractionEvent {
        id: string_arg(raw, &["id", "interaction_id", "interactionId"])?,
        scene,
        group_openid: string_arg(raw, &["group_openid", "groupOpenid"]).unwrap_or_default(),
        group_member_openid: string_arg(raw, &["group_member_openid", "groupMemberOpenid"])
            .unwrap_or_default(),
        user_openid: string_arg(raw, &["user_openid", "userOpenid"]).unwrap_or_default(),
        guild_id: string_arg(raw, &["guild_id", "guildId"]).unwrap_or_default(),
        channel_id: string_arg(raw, &["channel_id", "channelId"]).unwrap_or_default(),
        button_data: string_arg(resolved, &["button_data", "buttonData", "data"])
            .unwrap_or_default(),
        resolver_user_id: string_arg(resolved, &["user_id", "userId"]).unwrap_or_default(),
    })
}

async fn qqbot_ack_interaction(
    client: &reqwest::Client,
    settings: &QqBotSettings,
    access_token: &str,
    interaction_id: &str,
) -> AppResult<()> {
    let response = client
        .put(qqbot_interaction_url(settings, interaction_id)?)
        .header("Authorization", format!("QQBot {access_token}"))
        .header(reqwest::header::CONTENT_TYPE, "application/json")
        .json(&json!({ "code": 0 }))
        .send()
        .await
        .map_err(|error| AppError::BadRequest(format!("QQBot interaction ACK failed: {error}")))?;
    let status = response.status();
    let text = response.text().await.map_err(|error| {
        AppError::BadRequest(format!(
            "failed to read QQBot interaction ACK response: {error}"
        ))
    })?;
    if status.is_success() {
        Ok(())
    } else {
        Err(AppError::BadRequest(format!(
            "QQBot interaction ACK failed ({}): {}",
            status.as_u16(),
            truncate_output(&text, 500)
        )))
    }
}

fn qqbot_interaction_url(
    settings: &QqBotSettings,
    interaction_id: &str,
) -> AppResult<reqwest::Url> {
    reqwest::Url::parse(&format!(
        "{}/interactions/{}",
        settings.api_base_url,
        percent_encode_path_segment(interaction_id)
    ))
    .map_err(|error| AppError::BadRequest(format!("invalid QQBot interaction URL: {error}")))
}

fn qqbot_interaction_authorized_for_session(
    store: &AppStore,
    event: &QqBotInteractionEvent,
    session_key: &str,
) -> AppResult<bool> {
    let operator = event.operator_openid();
    if operator.trim().is_empty() {
        return Ok(false);
    }
    let Some(session) = qqbot_parse_gateway_session_key(session_key) else {
        return Ok(store
            .tool_approval(session_key)
            .map(|approval| approval.status == "pending")
            .unwrap_or(false));
    };
    if session.platform != "qqbot" {
        return Ok(false);
    }
    match session.chat_type.as_str() {
        "c2c" | "dm" => Ok(!session.chat_id.is_empty() && operator == session.chat_id),
        "group" | "guild" => {
            let event_chat = event.chat_id();
            Ok(!event_chat.is_empty()
                && event_chat == session.chat_id
                && session
                    .user_id
                    .as_deref()
                    .map(|user_id| user_id == operator)
                    .unwrap_or(false))
        }
        _ => Ok(false),
    }
}

#[derive(Debug, Clone)]
struct QqBotGatewaySessionKey {
    platform: String,
    chat_type: String,
    chat_id: String,
    user_id: Option<String>,
}

fn qqbot_parse_gateway_session_key(session_key: &str) -> Option<QqBotGatewaySessionKey> {
    let parts = session_key.split(':').collect::<Vec<_>>();
    if parts.len() < 5 || parts[0] != "agent" || parts[1] != "main" {
        return None;
    }
    Some(QqBotGatewaySessionKey {
        platform: parts[2].to_ascii_lowercase(),
        chat_type: parts[3].to_ascii_lowercase(),
        chat_id: parts[4].to_string(),
        user_id: parts.get(5).map(|value| value.to_string()),
    })
}

fn qqbot_pending_approval_ids_for_session(
    store: &AppStore,
    session_key: &str,
) -> AppResult<Vec<String>> {
    if let Ok(approval) = store.tool_approval(session_key) {
        if approval.status == "pending" {
            return Ok(vec![approval.id]);
        }
    }
    let pending = store
        .tool_approvals()?
        .into_iter()
        .filter(|approval| approval.status == "pending")
        .collect::<Vec<_>>();
    let explicit = pending
        .iter()
        .filter(|approval| {
            approval.id == session_key
                || approval
                    .conversation_id
                    .as_deref()
                    .map(|value| value == session_key)
                    .unwrap_or(false)
                || approval.reason.contains(session_key)
                || approval.payload.to_string().contains(session_key)
        })
        .map(|approval| approval.id.clone())
        .collect::<Vec<_>>();
    if !explicit.is_empty() {
        return Ok(explicit);
    }
    if qqbot_parse_gateway_session_key(session_key).is_some() && pending.len() == 1 {
        return Ok(vec![pending[0].id.clone()]);
    }
    Ok(Vec::new())
}

fn qqbot_write_update_response(store: &AppStore, answer: &str) -> AppResult<PathBuf> {
    let home = std::env::var_os("HERMES_HOME")
        .filter(|value| !value.is_empty())
        .map(PathBuf::from)
        .or_else(|| {
            std::env::var_os("USERPROFILE")
                .filter(|value| !value.is_empty())
                .map(|home| PathBuf::from(home).join(".hermes"))
        })
        .or_else(|| {
            std::env::var_os("HOME")
                .filter(|value| !value.is_empty())
                .map(|home| PathBuf::from(home).join(".hermes"))
        })
        .unwrap_or_else(|| store.data_dir().join(".hermes"));
    fs::create_dir_all(&home)?;
    let response_path = home.join(".update_response");
    let tmp = response_path.with_extension("tmp");
    fs::write(&tmp, answer)?;
    fs::rename(&tmp, &response_path)?;
    Ok(response_path)
}

pub(super) fn messaging_gateway_inbound_event_from_payload(
    payload: &Value,
    config: &Value,
    settings: &MessagingGatewayReceiveSettings,
) -> Option<Value> {
    let message = payload
        .get("data")
        .or_else(|| payload.get("message"))
        .or_else(|| payload.get("event"))
        .or_else(|| payload.get("body"))
        .unwrap_or(payload);
    let platform = string_arg(message, &["platform"])
        .or_else(|| string_arg(payload, &["platform"]))
        .or_else(|| messaging_gateway_platform_from_raw_payload(payload))?
        .trim()
        .to_ascii_lowercase();
    let message = messaging_gateway_message_from_payload(payload, message, &platform);
    if !matches!(
        platform.as_str(),
        "wecom"
            | "weixin"
            | "yuanbao"
            | "whatsapp"
            | "qqbot"
            | "bluebubbles"
            | "sms"
            | "homeassistant"
            | "msgraph_webhook"
            | "ntfy"
            | "simplex"
            | "irc"
            | "teams"
            | "google_chat"
            | "line"
    ) || !settings.platforms.contains(&platform)
    {
        return None;
    }
    if platform == "bluebubbles" && messaging_gateway_bluebubbles_ignored(message, payload) {
        return None;
    }
    if platform == "ntfy" && messaging_gateway_ntfy_echo_event(message) {
        return None;
    }
    if platform == "simplex" && messaging_gateway_simplex_self_event(message, payload) {
        return None;
    }
    let chat_id = string_arg(
        message,
        &[
            "chatId",
            "chat_id",
            "chatGuid",
            "chat_guid",
            "chatIdentifier",
            "chat_identifier",
            "conversationId",
            "conversation_id",
            "groupCode",
            "group_code",
            "GroupId",
            "group_id",
            "roomId",
            "room_id",
            "chatid",
            "roomid",
            "chat_room_id",
        ],
    )
    .or_else(|| messaging_gateway_weixin_chat_id(message, config))
    .or_else(|| messaging_gateway_qqbot_chat_id(message, payload))
    .or_else(|| messaging_gateway_sms_chat_id(message))
    .or_else(|| messaging_gateway_homeassistant_chat_id(message, payload))
    .or_else(|| messaging_gateway_msgraph_chat_id(message))
    .or_else(|| messaging_gateway_bluebubbles_chat_id(message, payload))
    .or_else(|| {
        if platform == "ntfy" {
            messaging_gateway_ntfy_chat_id(message, payload)
        } else {
            None
        }
    })
    .or_else(|| {
        if platform == "simplex" {
            messaging_gateway_simplex_chat_id(message, payload)
        } else {
            None
        }
    })
    .or_else(|| {
        if platform == "irc" {
            messaging_gateway_irc_chat_id(message, payload, config)
        } else {
            None
        }
    })
    .or_else(|| {
        if platform == "teams" {
            messaging_gateway_teams_chat_id(message, payload)
        } else {
            None
        }
    })
    .or_else(|| {
        if platform == "line" {
            messaging_gateway_line_chat_id(message, payload)
        } else {
            None
        }
    })
    .or_else(|| string_arg(payload, &["chatId", "chat_id", "chatid"]))?;
    if platform == "whatsapp" && messaging_gateway_whatsapp_is_broadcast_chat(&chat_id) {
        return None;
    }
    if !messaging_gateway_allowed(
        config,
        &platform,
        &["allowedChats", "allowed_chats"],
        "HERMES_MESSAGING_GATEWAY_ALLOWED_CHATS",
        &chat_id,
    ) {
        return None;
    }
    let user_id = string_arg(
        message,
        &[
            "userId",
            "user_id",
            "senderId",
            "sender_id",
            "from_user_id",
            "from",
            "sender",
            "address",
            "openid",
            "From_Account",
            "from_account",
        ],
    )
    .or_else(|| {
        message
            .get("handle")
            .and_then(|handle| string_arg(handle, &["address", "id"]))
    })
    .or_else(|| {
        if platform == "teams" {
            messaging_gateway_teams_user_id(message, payload)
        } else {
            None
        }
    })
    .or_else(|| {
        message
            .get("from")
            .and_then(|from| string_arg(from, &["userid", "userId", "user_id", "id"]))
    })
    .or_else(|| {
        message
            .get("sender")
            .and_then(|sender| string_arg(sender, &["userid", "userId", "user_id", "id"]))
    })
    .or_else(|| messaging_gateway_qqbot_user_id(message, payload))
    .or_else(|| messaging_gateway_sms_user_id(message))
    .or_else(|| messaging_gateway_homeassistant_user_id(message, payload))
    .or_else(|| messaging_gateway_msgraph_user_id(message))
    .or_else(|| {
        if platform == "ntfy" {
            messaging_gateway_ntfy_user_id(message, payload)
        } else {
            None
        }
    })
    .or_else(|| {
        if platform == "simplex" {
            messaging_gateway_simplex_user_id(message, payload, &chat_id)
        } else {
            None
        }
    })
    .or_else(|| {
        if platform == "irc" {
            messaging_gateway_irc_user_id(message, payload)
        } else {
            None
        }
    })
    .or_else(|| {
        if platform == "line" {
            messaging_gateway_line_user_id(message, payload)
        } else {
            None
        }
    })
    .or_else(|| string_arg(payload, &["userId", "user_id", "senderId", "sender_id"]))
    .unwrap_or_else(|| "unknown".into());
    if !messaging_gateway_allowed(
        config,
        &platform,
        &["allowedUsers", "allowed_users"],
        "HERMES_MESSAGING_GATEWAY_ALLOWED_USERS",
        &user_id,
    ) {
        return None;
    }
    let chat_type = string_arg(message, &["chatType", "chat_type", "conversationType"])
        .or_else(|| messaging_gateway_weixin_chat_type(message, config))
        .or_else(|| messaging_gateway_qqbot_chat_type(message, payload))
        .or_else(|| messaging_gateway_sms_chat_type(message))
        .or_else(|| messaging_gateway_homeassistant_chat_type(message, payload))
        .or_else(|| messaging_gateway_msgraph_chat_type(message))
        .or_else(|| messaging_gateway_bluebubbles_chat_type(message))
        .or_else(|| {
            if platform == "ntfy" {
                messaging_gateway_ntfy_chat_type(message, payload)
            } else {
                None
            }
        })
        .or_else(|| {
            if platform == "simplex" {
                messaging_gateway_simplex_chat_type(message, payload)
            } else {
                None
            }
        })
        .or_else(|| {
            if platform == "irc" {
                messaging_gateway_irc_chat_type(message, payload)
            } else {
                None
            }
        })
        .or_else(|| {
            if platform == "teams" {
                messaging_gateway_teams_chat_type(message, payload)
            } else {
                None
            }
        })
        .or_else(|| {
            if platform == "line" {
                messaging_gateway_line_chat_type(message, payload)
            } else {
                None
            }
        })
        .unwrap_or_else(|| {
            if platform == "yuanbao"
                || message.get("isGroup").and_then(Value::as_bool) == Some(true)
                || message.get("is_group").and_then(Value::as_bool) == Some(true)
                || message.get("chatid").is_some()
                || message.get("room_id").is_some()
                || message.get("chat_room_id").is_some()
            {
                "group".into()
            } else {
                "dm".into()
            }
        });
    let is_group = matches!(
        chat_type.to_ascii_lowercase().as_str(),
        "group" | "room" | "chat"
    );
    let mut text = if platform == "qqbot" {
        messaging_gateway_qqbot_extract_text(message, payload)
    } else if platform == "yuanbao" {
        messaging_gateway_yuanbao_extract_text(message)
    } else if platform == "sms" {
        messaging_gateway_sms_extract_text(message)
    } else if platform == "homeassistant" {
        messaging_gateway_homeassistant_extract_text(message, payload)
    } else if platform == "msgraph_webhook" {
        messaging_gateway_msgraph_extract_text(message, config)
    } else if platform == "ntfy" {
        messaging_gateway_ntfy_extract_text(message, payload)
    } else if platform == "simplex" {
        messaging_gateway_simplex_extract_text(message, payload)
    } else if platform == "irc" {
        messaging_gateway_irc_extract_text(message, payload)
    } else if platform == "teams" {
        messaging_gateway_teams_extract_text(message, payload)
    } else if platform == "line" {
        messaging_gateway_line_extract_text(message, payload)
    } else {
        messaging_gateway_extract_text(message)
    };
    if is_group
        && !messaging_gateway_qqbot_event_is_group_at(payload)
        && messaging_gateway_require_mention(config, message, &chat_id, &text)
    {
        return None;
    }
    let attachments = messaging_gateway_attachment_metadata(message, settings);
    if platform == "bluebubbles" && text.trim().is_empty() && !attachments.is_empty() {
        text = "(attachment)".into();
    }
    if text.trim().is_empty() && attachments.is_empty() {
        return None;
    }
    let message_id = string_arg(
        message,
        &[
            "messageId",
            "message_id",
            "messageGuid",
            "message_guid",
            "MessageSid",
            "SmsSid",
            "msgId",
            "msg_id",
            "msgid",
            "guid",
            "id",
            "MsgKey",
            "msg_key",
        ],
    )
    .or_else(|| {
        if platform == "simplex" {
            messaging_gateway_simplex_message_id(message, payload)
        } else if platform == "line" {
            messaging_gateway_line_message_id(message, payload)
        } else {
            None
        }
    })
    .unwrap_or_else(|| new_id("messaging-gateway-message"));
    let message_type = string_arg(message, &["messageType", "message_type", "msgtype", "type"])
        .unwrap_or_else(|| {
            if attachments.is_empty() {
                "text".into()
            } else {
                "document".into()
            }
        });
    let user_name = string_arg(
        message,
        &[
            "userName",
            "user_name",
            "senderName",
            "sender_name",
            "sender_nickname",
            "nick_name",
            "name",
            "nickname",
        ],
    )
    .or_else(|| {
        if platform == "simplex" {
            Some(messaging_gateway_simplex_sender_name(
                message, payload, &user_id,
            ))
        } else if platform == "teams" {
            Some(messaging_gateway_teams_user_name(
                message, payload, &user_id,
            ))
        } else {
            None
        }
    })
    .unwrap_or_else(|| user_id.clone());
    let source_chat_type = if is_group {
        "group"
    } else if chat_type.eq_ignore_ascii_case("channel") {
        "channel"
    } else if chat_type.eq_ignore_ascii_case("webhook") {
        "webhook"
    } else {
        "dm"
    };
    let mut inbound = json!({
        "platform": platform,
        "messageId": message_id,
        "message_id": message_id,
        "text": text,
        "messageType": message_type,
        "message_type": message_type,
        "source": {
            "platform": platform,
            "chatId": chat_id,
            "chat_id": chat_id,
            "serviceUrl": if platform == "teams" { messaging_gateway_teams_service_url(message, payload).map(Value::String).unwrap_or(Value::Null) } else { Value::Null },
            "service_url": if platform == "teams" { messaging_gateway_teams_service_url(message, payload).map(Value::String).unwrap_or(Value::Null) } else { Value::Null },
            "chatType": source_chat_type,
            "chat_type": source_chat_type,
            "chatTitle": string_arg(message, &["chatTitle", "chat_title", "roomName", "room_name", "group_name", "GroupName"]).map(Value::String).unwrap_or(Value::Null),
            "chat_title": string_arg(message, &["chatTitle", "chat_title", "roomName", "room_name", "group_name", "GroupName"]).map(Value::String).unwrap_or(Value::Null),
            "userId": user_id,
            "user_id": user_id,
            "userName": user_name,
            "user_name": user_name,
        },
        "raw": payload,
    });
    if !attachments.is_empty() {
        inbound["attachments"] = json!(attachments);
        inbound["skippedAttachments"] = inbound["attachments"].clone();
        inbound["skipped_attachments"] = inbound["attachments"].clone();
    }
    if platform == "line" {
        if let Some(reply_token) = messaging_gateway_line_reply_token(message, payload) {
            inbound["replyToken"] = json!(reply_token);
            inbound["reply_token"] = inbound["replyToken"].clone();
        }
        if let Some(postback) = messaging_gateway_line_postback_value(message, payload) {
            inbound["postback"] = postback;
        }
    }
    if let Some(context_token) = string_arg(message, &["contextToken", "context_token"]) {
        inbound["contextToken"] = json!(context_token);
        inbound["context_token"] = json!(context_token);
    }
    Some(inbound)
}

fn messaging_gateway_allowed(
    config: &Value,
    platform: &str,
    keys: &[&str],
    env_key: &str,
    value: &str,
) -> bool {
    let allowed = telegram_string_set(config, keys, env_key);
    if allowed.is_empty() || allowed.contains("*") || allowed.contains(value) {
        return true;
    }
    if keys
        .iter()
        .any(|key| matches!(*key, "allowedUsers" | "allowed_users"))
    {
        return messaging_gateway_paired_user_set(config, platform).contains(value);
    }
    false
}

pub(super) fn messaging_gateway_paired_user_set(config: &Value, platform: &str) -> HashSet<String> {
    let mut users = HashSet::new();
    for key in [
        "pairedUsers",
        "paired_users",
        "approvedUsers",
        "approved_users",
    ] {
        users.extend(
            telegram_string_set(config, &[key], "")
                .into_iter()
                .map(|value| value.to_ascii_lowercase()),
        );
    }
    let extra = messaging_gateway_platform_extra(config, platform);
    for key in [
        "pairedUsers",
        "paired_users",
        "approvedUsers",
        "approved_users",
    ] {
        users.extend(
            messaging_gateway_string_set(extra.get(key).cloned())
                .into_iter()
                .map(|value| value.to_ascii_lowercase()),
        );
    }
    users
}

pub(super) fn messaging_gateway_parse_inbound_body(
    request: &ParsedWebhookRequest,
) -> AppResult<Value> {
    let content_type = request
        .headers
        .get("content-type")
        .map(|value| value.to_ascii_lowercase())
        .unwrap_or_default();
    if content_type.contains("application/x-www-form-urlencoded") {
        return Ok(messaging_gateway_parse_form_urlencoded(&request.body));
    }
    serde_json::from_str::<Value>(&request.body).map_err(|error| {
        AppError::BadRequest(format!("invalid messaging gateway webhook JSON: {error}"))
    })
}

fn messaging_gateway_verify_line_signature(
    store: &AppStore,
    settings: &MessagingGatewayReceiveSettings,
    request: &ParsedWebhookRequest,
    payload: &Value,
) -> AppResult<()> {
    if !settings.platforms.contains("line") || !messaging_gateway_line_payload_like(payload) {
        return Ok(());
    }
    let line_config = store.config()?.line;
    let line_settings = match line_settings(&line_config) {
        Ok(settings) => settings,
        Err(_) => return Ok(()),
    };
    let Some(secret) = line_settings.channel_secret.as_deref() else {
        return Ok(());
    };
    let provided = request
        .headers
        .get("x-line-signature")
        .or_else(|| request.headers.get("x_line_signature"))
        .map(String::as_str)
        .unwrap_or_default();
    if !line_verify_signature(request.body.as_bytes(), provided, secret) {
        return Err(AppError::BadRequest(
            "LINE webhook signature mismatch".into(),
        ));
    }
    Ok(())
}

pub(super) fn line_verify_signature(body: &[u8], signature: &str, secret: &str) -> bool {
    use base64::{engine::general_purpose::STANDARD, Engine as _};
    use hmac::{Hmac, Mac};
    use sha2::Sha256;

    if body.is_empty() || signature.trim().is_empty() || secret.trim().is_empty() {
        return false;
    }
    let Ok(mut mac) = Hmac::<Sha256>::new_from_slice(secret.as_bytes()) else {
        return false;
    };
    mac.update(body);
    let expected = STANDARD.encode(mac.finalize().into_bytes());
    constant_time_eq(expected.as_bytes(), signature.trim().as_bytes())
}

fn constant_time_eq(left: &[u8], right: &[u8]) -> bool {
    if left.len() != right.len() {
        return false;
    }
    let mut diff = 0u8;
    for (a, b) in left.iter().zip(right.iter()) {
        diff |= a ^ b;
    }
    diff == 0
}

fn messaging_gateway_parse_form_urlencoded(body: &str) -> Value {
    let mut map = serde_json::Map::new();
    for pair in body.split('&') {
        if pair.is_empty() {
            continue;
        }
        let (key, value) = pair.split_once('=').unwrap_or((pair, ""));
        let key = messaging_gateway_url_decode(key);
        if key.is_empty() {
            continue;
        }
        map.insert(key, Value::String(messaging_gateway_url_decode(value)));
    }
    Value::Object(map)
}

fn messaging_gateway_url_decode(value: &str) -> String {
    let bytes = value.as_bytes();
    let mut output = Vec::with_capacity(bytes.len());
    let mut index = 0;
    while index < bytes.len() {
        match bytes[index] {
            b'+' => {
                output.push(b' ');
                index += 1;
            }
            b'%' if index + 2 < bytes.len() => {
                let hi = (bytes[index + 1] as char).to_digit(16);
                let lo = (bytes[index + 2] as char).to_digit(16);
                if let (Some(hi), Some(lo)) = (hi, lo) {
                    output.push(((hi << 4) | lo) as u8);
                    index += 3;
                } else {
                    output.push(bytes[index]);
                    index += 1;
                }
            }
            byte => {
                output.push(byte);
                index += 1;
            }
        }
    }
    String::from_utf8_lossy(&output).to_string()
}

pub(super) fn messaging_gateway_platform_from_raw_payload(payload: &Value) -> Option<String> {
    if let Some(cmd) =
        string_arg(payload, &["cmd", "command"]).map(|value| value.to_ascii_lowercase())
    {
        if matches!(
            cmd.as_str(),
            "aibot_msg_callback" | "aibot_callback" | "aibot_event_callback"
        ) {
            return Some("wecom".into());
        }
        if cmd.contains("weixin") || cmd.contains("wechat") || cmd.contains("ilink") {
            return Some("weixin".into());
        }
        if cmd.contains("whatsapp") {
            return Some("whatsapp".into());
        }
        if cmd.contains("bluebubbles") || cmd.contains("blue_bubbles") {
            return Some("bluebubbles".into());
        }
        if cmd.contains("qqbot") || cmd.contains("qq_bot") {
            return Some("qqbot".into());
        }
        if cmd.contains("sms") || cmd.contains("twilio") {
            return Some("sms".into());
        }
        if cmd.contains("homeassistant") || cmd.contains("home_assistant") || cmd.contains("hass") {
            return Some("homeassistant".into());
        }
        if cmd.contains("msgraph") || cmd.contains("microsoft_graph") {
            return Some("msgraph_webhook".into());
        }
        if cmd.contains("ntfy") {
            return Some("ntfy".into());
        }
        if cmd.contains("simplex") || cmd.contains("simple_x") {
            return Some("simplex".into());
        }
        if cmd.contains("irc") || cmd == "privmsg" {
            return Some("irc".into());
        }
        if cmd.contains("teams") || cmd.contains("botframework") || cmd.contains("bot_framework") {
            return Some("teams".into());
        }
        if cmd.contains("line") {
            return Some("line".into());
        }
        if cmd.contains("yuanbao") {
            return Some("yuanbao".into());
        }
    }
    if messaging_gateway_qqbot_event_type(payload).is_some() {
        return Some("qqbot".into());
    }
    if messaging_gateway_sms_payload_like(payload) {
        return Some("sms".into());
    }
    if messaging_gateway_homeassistant_payload_like(payload) {
        return Some("homeassistant".into());
    }
    if messaging_gateway_msgraph_payload_like(payload) {
        return Some("msgraph_webhook".into());
    }
    if messaging_gateway_ntfy_payload_like(payload) {
        return Some("ntfy".into());
    }
    if messaging_gateway_simplex_payload_like(payload) {
        return Some("simplex".into());
    }
    if messaging_gateway_irc_payload_like(payload) {
        return Some("irc".into());
    }
    if messaging_gateway_teams_payload_like(payload) {
        return Some("teams".into());
    }
    if messaging_gateway_line_payload_like(payload) {
        return Some("line".into());
    }
    let candidates = [
        Some(payload),
        payload.get("data"),
        payload.get("message"),
        payload.get("body"),
    ];
    if candidates.into_iter().flatten().any(|value| {
        value.get("msgs").and_then(Value::as_array).is_some()
            || value.get("get_updates_buf").is_some()
            || (value.get("from_user_id").is_some() && value.get("item_list").is_some())
    }) {
        return Some("weixin".into());
    }
    let candidates = [
        Some(payload),
        payload.get("data"),
        payload.get("message"),
        payload.get("body"),
    ];
    if candidates.into_iter().flatten().any(|value| {
        value.get("callback_command").is_some()
            || value.get("CallbackCommand").is_some()
            || value.get("MsgBody").is_some()
            || value.get("msg_body").is_some()
            || (value.get("From_Account").is_some() && value.get("MsgSeq").is_some())
    }) {
        return Some("yuanbao".into());
    }
    let candidates = [
        Some(payload),
        payload.get("data"),
        payload.get("message"),
        payload.get("body"),
    ];
    if candidates.into_iter().flatten().any(|value| {
        value.get("chatId").is_some()
            && (value.get("senderId").is_some()
                || value.get("body").is_some()
                || value.get("mediaUrls").is_some())
    }) {
        return Some("whatsapp".into());
    }
    let candidates = [
        Some(payload),
        payload.get("data"),
        payload.get("message"),
        payload.get("body"),
    ];
    if candidates.into_iter().flatten().any(|value| {
        value.get("chatGuid").is_some()
            || value.get("chatIdentifier").is_some()
            || value.get("handle").is_some()
            || value.get("attachments").is_some()
    }) {
        return Some("bluebubbles".into());
    }
    None
}

fn messaging_gateway_message_from_payload<'a>(
    payload: &'a Value,
    default_message: &'a Value,
    platform: &str,
) -> &'a Value {
    if platform == "bluebubbles" {
        return messaging_gateway_bluebubbles_message_from_payload(payload, default_message);
    }
    if platform == "qqbot" {
        return messaging_gateway_qqbot_message_from_payload(payload, default_message);
    }
    if platform == "msgraph_webhook" {
        return messaging_gateway_msgraph_message_from_payload(payload, default_message);
    }
    if platform == "ntfy" && !default_message.is_object() {
        return payload;
    }
    if platform == "simplex" {
        return messaging_gateway_simplex_message_from_payload(payload, default_message);
    }
    if platform == "irc" && !default_message.is_object() {
        return payload;
    }
    if platform == "teams" {
        return messaging_gateway_teams_message_from_payload(payload, default_message);
    }
    if platform == "line" {
        return messaging_gateway_line_message_from_payload(payload, default_message);
    }
    if !default_message.is_object() {
        return payload;
    }
    if platform != "weixin" {
        return default_message;
    }
    let containers = [
        Some(default_message),
        Some(payload),
        payload.get("data"),
        payload.get("body"),
    ];
    for value in containers.into_iter().flatten() {
        if let Some(first) = value
            .get("msgs")
            .and_then(Value::as_array)
            .and_then(|items| items.first())
        {
            return first;
        }
        if value.get("from_user_id").is_some() && value.get("item_list").is_some() {
            return value;
        }
    }
    default_message
}

fn messaging_gateway_ntfy_payload_like(payload: &Value) -> bool {
    let candidates = [
        Some(payload),
        payload.get("data"),
        payload.get("message"),
        payload.get("event"),
        payload.get("body"),
    ];
    candidates.into_iter().flatten().any(|value| {
        let event = string_arg(value, &["event", "type"])
            .map(|value| value.to_ascii_lowercase())
            .unwrap_or_default();
        event == "message"
            && string_arg(value, &["topic", "channel", "chatId", "chat_id"]).is_some()
            && string_arg(value, &["message", "text", "body", "title"]).is_some()
    })
}

