fn messaging_gateway_ntfy_extract_text(message: &Value, payload: &Value) -> String {
    let title = string_arg(message, &["title"])
        .or_else(|| string_arg(payload, &["title"]))
        .unwrap_or_default();
    let body = string_arg(message, &["message", "text", "body", "content"])
        .or_else(|| string_arg(payload, &["message", "text", "body", "content"]))
        .unwrap_or_default();
    match (title.trim(), body.trim()) {
        ("", "") => String::new(),
        ("", body) => body.to_string(),
        (title, "") => title.to_string(),
        (title, body) if title == body => body.to_string(),
        (title, body) => format!("{title}: {body}"),
    }
}

fn messaging_gateway_ntfy_echo_event(message: &Value) -> bool {
    message
        .get("tags")
        .and_then(Value::as_array)
        .map(|tags| {
            tags.iter().any(|tag| {
                tag.as_str()
                    .map(|tag| tag.eq_ignore_ascii_case(NTFY_ECHO_TAG))
                    .unwrap_or(false)
            })
        })
        .unwrap_or(false)
}

fn messaging_gateway_simplex_payload_like(payload: &Value) -> bool {
    let candidates = [
        Some(payload),
        payload.get("data"),
        payload.get("message"),
        payload.get("event"),
        payload.get("body"),
    ];
    candidates.into_iter().flatten().any(|value| {
        let event_type = string_arg(value, &["type"])
            .or_else(|| {
                value
                    .get("resp")
                    .and_then(|resp| string_arg(resp, &["type"]))
            })
            .unwrap_or_default();
        matches!(event_type.as_str(), "newChatItem" | "newChatItems")
            || value.get("chatInfo").is_some()
            || value.get("chatItem").is_some()
            || value.get("chatItems").and_then(Value::as_array).is_some()
    })
}

fn messaging_gateway_simplex_message_from_payload<'a>(
    payload: &'a Value,
    default_message: &'a Value,
) -> &'a Value {
    let candidates = [
        Some(default_message),
        Some(payload),
        payload.get("data"),
        payload.get("message"),
        payload.get("event"),
        payload.get("body"),
    ];
    for value in candidates.into_iter().flatten() {
        if value.get("chatInfo").is_some() || value.get("chatItem").is_some() {
            return value;
        }
        if let Some(first) = value
            .get("chatItems")
            .and_then(Value::as_array)
            .and_then(|items| items.first())
        {
            return first;
        }
    }
    default_message
}

fn messaging_gateway_simplex_chat_id(message: &Value, payload: &Value) -> Option<String> {
    string_arg(message, &["chatId", "chat_id"])
        .or_else(|| string_arg(payload, &["chatId", "chat_id", "target"]))
        .or_else(|| {
            let chat_info = messaging_gateway_simplex_chat_info(message, payload)?;
            let chat_type = string_arg(chat_info, &["type"]).unwrap_or_default();
            if matches!(chat_type.as_str(), "group" | "groupInfo") {
                chat_info
                    .get("groupInfo")
                    .or_else(|| chat_info.get("group"))
                    .and_then(|group| string_arg(group, &["groupId", "id"]))
                    .map(|group_id| format!("group:{group_id}"))
            } else {
                chat_info
                    .get("contact")
                    .and_then(|contact| string_arg(contact, &["contactId", "id"]))
            }
        })
}

