fn hermes_typing_lifecycle_for_platform(platform: &str) -> Value {
    let supported = hermes_typing_platform_supported(platform);
    json!({
        "schema": "hermes_gateway_typing_lifecycle_desktop_v1",
        "platform": platform,
        "typingSupported": supported,
        "typing_supported": supported,
        "refreshIntervalSeconds": 2.0,
        "refresh_interval_seconds": 2.0,
        "sendTimeoutSeconds": 1.5,
        "send_timeout_seconds": 1.5,
        "pauseDuringApproval": supported,
        "pause_during_approval": supported,
        "pauseDuringClarify": supported,
        "pause_during_clarify": supported,
        "resumeAfterApproval": supported,
        "resume_after_approval": supported,
        "resumeAfterClarify": supported,
        "resume_after_clarify": supported,
        "stopOnCompletion": supported,
        "stop_on_completion": supported,
        "stopOnError": supported,
        "stop_on_error": supported,
        "interruptStopsTyping": supported,
        "interrupt_stops_typing": supported,
        "clearsPausedSetOnStop": supported,
        "clears_paused_set_on_stop": supported,
        "desktopAdaptation": true,
        "bridgeRequired": matches!(platform, "whatsapp" | "bluebubbles" | "wecom" | "weixin" | "yuanbao"),
        "bridge_required": matches!(platform, "whatsapp" | "bluebubbles" | "wecom" | "weixin" | "yuanbao"),
        "source": if supported {
            "Hermes platform adapter exposes send_typing/stop_typing or inherits the base lifecycle; SynthChat surfaces the lifecycle contract in desktop status."
        } else {
            "Hermes platform has no useful typing indicator for this desktop adapter surface."
        }
    })
}

fn hermes_typing_platform_supported(platform: &str) -> bool {
    matches!(
        platform,
        "telegram"
            | "slack"
            | "mattermost"
            | "matrix"
            | "signal"
            | "feishu"
            | "dingtalk"
            | "qqbot"
            | "teams"
            | "google_chat"
            | "wecom"
            | "weixin"
            | "whatsapp"
            | "bluebubbles"
            | "yuanbao"
    )
}

fn hermes_display_config_for_platform(config: &crate::models::AppConfig, platform: &str) -> Value {
    let tier = hermes_display_platform_tier(platform);
    let mut effective = hermes_display_tier_defaults(tier, config);
    if platform == "telegram" {
        effective["toolProgress"] = json!("off");
        effective["tool_progress"] = json!("off");
        effective["busyAckDetail"] = json!(false);
        effective["busy_ack_detail"] = json!(false);
    } else if platform == "slack" {
        effective["toolProgress"] = json!("off");
        effective["tool_progress"] = json!("off");
    } else if platform == "api_server" {
        effective["toolPreviewLength"] = json!(0);
        effective["tool_preview_length"] = json!(0);
    }
    json!({
        "schema": "hermes_gateway_display_config_desktop_v1",
        "platform": platform,
        "tier": tier,
        "effective": effective,
        "resolutionOrder": [
            "display.platforms.<platform>.<key>",
            "display.<key>",
            "platform_defaults",
            "global_defaults"
        ],
        "desktopAdaptation": true,
        "source": {
            "toolProgress": "Hermes platform default unless SynthChat desktop chat.tool_progress_display is used by local UI",
            "statusbarEnabled": config.chat.statusbar_enabled,
            "runtimeFooterEnabled": config.chat.runtime_footer_enabled,
            "displayPlatforms": "diagnostic defaults; Python gateway YAML overrides are not embedded"
        }
    })
}

fn hermes_display_platform_tier(platform: &str) -> &'static str {
    match platform {
        "telegram" | "discord" | "api_server" => "high",
        "slack" | "mattermost" | "matrix" | "feishu" | "whatsapp" => "medium",
        "signal" | "bluebubbles" | "weixin" | "wecom" | "wecom_callback" | "dingtalk" => "low",
        "email" | "sms" | "webhook" | "homeassistant" | "msgraph_webhook" => "minimal",
        _ => "global",
    }
}

fn hermes_display_tier_defaults(tier: &str, config: &crate::models::AppConfig) -> Value {
    let (
        tool_progress,
        tool_preview_length,
        streaming,
        interim_assistant_messages,
        long_running_notifications,
        busy_ack_detail,
    ) = match tier {
        "high" => ("all", 40, Value::Null, true, true, true),
        "medium" => ("new", 40, Value::Null, true, true, true),
        "low" => ("off", 40, json!(false), false, false, false),
        "minimal" => ("off", 0, json!(false), false, false, false),
        _ => (
            config.chat.tool_progress_display.as_str(),
            if config.chat.statusbar_enabled { 40 } else { 0 },
            Value::Null,
            true,
            true,
            true,
        ),
    };
    json!({
        "toolProgress": tool_progress,
        "tool_progress": tool_progress,
        "showReasoning": false,
        "show_reasoning": false,
        "toolPreviewLength": tool_preview_length,
        "tool_preview_length": tool_preview_length,
        "streaming": streaming,
        "interimAssistantMessages": interim_assistant_messages,
        "interim_assistant_messages": interim_assistant_messages,
        "longRunningNotifications": long_running_notifications,
        "long_running_notifications": long_running_notifications,
        "busyAckDetail": busy_ack_detail,
        "busy_ack_detail": busy_ack_detail,
        "cleanupProgress": false,
        "cleanup_progress": false,
    })
}

fn platform_adapter_state(store: &AppStore, platform: &str) -> AppResult<Value> {
    let config = store.config()?;
    match platform {
        "mattermost" => Ok(enrich_runtime_adapter_state(
            store.mattermost_adapter_state()?,
            platform_config_enabled(&config.mattermost),
            mattermost_configured(&config.mattermost),
            true,
            "websocket",
        )),
        "discord" => Ok(enrich_runtime_adapter_state(
            store.discord_adapter_state()?,
            platform_config_enabled(&config.discord),
            discord_runtime_configured(&config.discord),
            true,
            "gateway",
        )),
        "feishu" => Ok(enrich_runtime_adapter_state(
            store.feishu_adapter_state()?,
            platform_config_enabled(&config.feishu),
            feishu_webhook_configured(&config.feishu),
            true,
            "webhook_openapi",
        )),
        "feishu_comment" => feishu_comment_adapter_state(store, &config),
        "webhook" => webhook_adapter_state(store, &config),
        "telegram" => Ok(enrich_runtime_adapter_state(
            store.telegram_adapter_state()?,
            platform_config_enabled(&config.telegram),
            telegram_configured(&config.telegram),
            true,
            "bot_api",
        )),
        "slack" => Ok(enrich_runtime_adapter_state(
            store.slack_adapter_state()?,
            platform_config_enabled(&config.slack),
            slack_runtime_configured(&config.slack),
            true,
            "socket_mode",
        )),
        "matrix" => Ok(enrich_runtime_adapter_state(
            store.matrix_adapter_state()?,
            platform_config_enabled(&config.matrix),
            matrix_configured(&config.matrix),
            true,
            "client_server_api",
        )),
        "signal" => Ok(enrich_runtime_adapter_state(
            store.signal_adapter_state()?,
            platform_config_enabled(&config.signal),
            signal_configured(&config.signal),
            true,
            "sse_json_rpc",
        )),
        "email" => Ok(enrich_runtime_adapter_state(
            store.email_adapter_state()?,
            platform_config_enabled(&config.email),
            email_runtime_configured(&config.email),
            true,
            "imap_smtp",
        )),
        "sms" => sms_adapter_state(store, &config),
        "dingtalk" => Ok(enrich_runtime_adapter_state(
            store.dingtalk_adapter_state()?,
            platform_config_enabled(&config.dingtalk),
            dingtalk_webhook_configured(&config.dingtalk),
            true,
            "bridge_webhook_robot",
        )),
        "teams" => teams_adapter_state(store, &config),
        "ntfy" => ntfy_adapter_state(store, &config),
        "simplex" => simplex_adapter_state(store, &config),
        "irc" => irc_adapter_state(store, &config),
        "line" => line_adapter_state(store, &config),
        "google_chat" => google_chat_adapter_state(store, &config),
        "whatsapp" => whatsapp_adapter_state(store, &config),
        "qqbot" => qqbot_adapter_state(store, &config),
        "homeassistant" => homeassistant_adapter_state(store, &config),
        "bluebubbles" => bluebubbles_adapter_state(store, &config),
        "api_server" => api_server_adapter_state(store, &config),
        "wecom" | "weixin" | "yuanbao" | "msgraph_webhook" => {
            Ok(messaging_gateway_adapter_state_for_platform(
                store.messaging_gateway_adapter_state()?,
                platform_config_enabled(&config.messaging_gateway)
                    && messaging_gateway_platform_enabled(&config.messaging_gateway, platform),
                messaging_gateway_runtime_configured(&config.messaging_gateway)
                    && messaging_gateway_platform_enabled(&config.messaging_gateway, platform),
                platform,
            ))
        }
        "messaging_gateway" => Ok(enrich_runtime_adapter_state(
            store.messaging_gateway_adapter_state()?,
            platform_config_enabled(&config.messaging_gateway),
            messaging_gateway_runtime_configured(&config.messaging_gateway),
            true,
            "bridge_webhook",
        )),
        other => Ok(json!({
            "platform": other,
            "status": "unsupported",
            "runtime": false,
            "configured": false,
            "enabled": false,
            "updatedAt": now_iso(),
        })),
    }
}

fn webhook_adapter_state(store: &AppStore, config: &crate::models::AppConfig) -> AppResult<Value> {
    let mut state = enrich_runtime_adapter_state(
        store.webhook_adapter_state()?,
        platform_config_enabled(&config.webhook),
        webhook_configured(&config.webhook),
        true,
        "http_listener",
    );
    state["schema"] = json!("hermes_webhook_adapter_status_desktop_v1");
    state["deliveryModes"] = json!(["background_agent", "github_comment"]);
    state["delivery_modes"] = state["deliveryModes"].clone();
    state["githubCommentDelivery"] = json!({
        "schema": "hermes_webhook_github_comment_delivery_desktop_v1",
        "supported": true,
        "deliver": "github_comment",
        "hermesReference": "gateway/platforms/webhook.py::_deliver_github_comment",
        "requestShape": {
            "delivery.deliver": "github_comment",
            "delivery.deliver_extra.repo": "owner/repo",
            "delivery.deliver_extra.pr_number": 123,
            "content": "comment body"
        },
        "execution": {
            "default": "plan",
            "executeFields": ["execute", "live", "apply"],
            "confirmationField": "confirmGithubComment",
            "command": "gh pr comment <pr_number> --repo <repo> --body <content>",
            "timeoutSeconds": 30
        },
        "boundary": "Default webhook handling returns a Hermes-shaped gh CLI execution plan. Live posting requires execute/live/apply plus confirmGithubComment:true so the normal command approval/logging path can remain visible."
    });
    state["github_comment_delivery"] = state["githubCommentDelivery"].clone();
    state["capabilityMatrix"]["webhook_ingress"] = json!(true);
    state["capabilityMatrix"]["background_agent_dispatch"] = json!(true);
    state["capabilityMatrix"]["github_comment_delivery"] = json!(true);
    Ok(state)
}

fn enrich_runtime_adapter_state(
    mut state: Value,
    enabled: bool,
    configured: bool,
    runtime: bool,
    transport: &str,
) -> Value {
    if !state.is_object() {
        state = json!({});
    }
    state["enabled"] = json!(enabled);
    state["configured"] = json!(configured);
    state["runtime"] = json!(runtime);
    state["transport"] = json!(transport);
    state["capabilities"] = json!(["send", "receive", "lifecycle", "attachments"]);
    state["mode"] = json!(if runtime { "runtime" } else { "send_only" });
    state["runtimeAdapter"] = json!(runtime);
    state["runtime_adapter"] = json!(runtime);
    state["messagingGateway"] = json!(false);
    state["messaging_gateway"] = json!(false);
    state["externalDaemon"] = json!(false);
    state["external_daemon"] = json!(false);
    state["capabilityMatrix"] = json!({
        "send": true,
        "receive": runtime,
        "lifecycle": runtime,
        "attachments": true,
        "directory": false,
    });
    state["capability_matrix"] = state["capabilityMatrix"].clone();
    state
}

