fn feishu_comment_rules_effective_enabled(rules: &Value, config: &Value) -> bool {
    rules
        .get("enabled")
        .and_then(Value::as_bool)
        .or_else(|| {
            config
                .get("commentRules")
                .or_else(|| config.get("comment_rules"))
                .and_then(|value| value.get("enabled"))
                .and_then(Value::as_bool)
        })
        .or_else(|| config.get("commentRulesEnabled").and_then(Value::as_bool))
        .or_else(|| config.get("comment_rules_enabled").and_then(Value::as_bool))
        .unwrap_or(true)
}

pub(super) fn messaging_gateway_adapter_state_for_platform(
    state: Value,
    enabled: bool,
    configured: bool,
    platform: &str,
) -> Value {
    let mut state =
        enrich_runtime_adapter_state(state, enabled, configured, true, "bridge_webhook");
    state["platform"] = json!(platform);
    state["gatewayPlatform"] = json!("messaging_gateway");
    state["gateway_platform"] = json!("messaging_gateway");
    state["mode"] = json!("messaging_gateway");
    state["messagingGateway"] = json!(true);
    state["messaging_gateway"] = json!(true);
    state["externalDaemon"] = json!(true);
    state["external_daemon"] = json!(true);
    state["capabilityMatrix"] = json!({
        "send": true,
        "receive": true,
        "lifecycle": true,
        "attachments": true,
        "directory": false,
    });
    if platform == "msgraph_webhook" {
        state["nativeApiServerIngress"] = json!(true);
        state["native_api_server_ingress"] = json!(true);
        state["nativeApiServerIngressRoute"] = json!("/msgraph/webhook");
        state["native_api_server_ingress_route"] = state["nativeApiServerIngressRoute"].clone();
        state["capabilityMatrix"]["msgraphWebhookIngress"] = json!(true);
        state["capabilityMatrix"]["msgraph_webhook_ingress"] = json!(true);
        state["capabilityMatrix"]["msgraphValidationTokenEcho"] = json!(true);
        state["capabilityMatrix"]["msgraph_validation_token_echo"] = json!(true);
        state["capabilityMatrix"]["msgraphNotificationDedupe"] = json!(true);
        state["capabilityMatrix"]["msgraph_notification_dedupe"] = json!(true);
        state["capabilityMatrix"]["msgraphWebhookAutoSchedule"] = json!(true);
        state["capabilityMatrix"]["msgraph_webhook_auto_schedule"] = json!(true);
        state["capabilityMatrix"]["msgraphWebhookAgentQueueBridge"] = json!(true);
        state["capabilityMatrix"]["msgraph_webhook_agent_queue_bridge"] = json!(true);
        state["endpoints"] = json!({
            "msgraph_webhook": {
                "method": "GET/POST",
                "path": "/msgraph/webhook",
                "native": true,
                "public": true,
                "validationTokenTextPlain": true
            }
        });
    }
    state["capability_matrix"] = state["capabilityMatrix"].clone();
    state
}

