pub(super) fn hermes_api_server_daemon_managed_process_plan() -> Value {
    let command = if std::env::consts::OS == "windows" {
        "$env:API_SERVER_ENABLED='true'; hermes gateway run"
    } else {
        "API_SERVER_ENABLED=true hermes gateway run"
    };
    json!({
        "schema": "hermes_api_server_daemon_managed_process_plan_desktop_v1",
        "taskId": "hermes-api-server-daemon",
        "task_id": "hermes-api-server-daemon",
        "command": command,
        "hermesCommand": "hermes gateway run",
        "hermes_command": "hermes gateway run",
        "requiredEnv": ["API_SERVER_ENABLED=true"],
        "required_env": ["API_SERVER_ENABLED=true"],
        "optionalEnv": ["API_SERVER_HOST", "API_SERVER_PORT", "API_SERVER_KEY", "API_SERVER_CORS_ORIGINS", "API_SERVER_MODEL_NAME"],
        "optional_env": ["API_SERVER_HOST", "API_SERVER_PORT", "API_SERVER_KEY", "API_SERVER_CORS_ORIGINS", "API_SERVER_MODEL_NAME"],
        "managedProcessStartPayload": {
            "action": "start",
            "label": "Hermes API server daemon",
            "command": command,
            "taskId": "hermes-api-server-daemon",
            "notifyOnComplete": true,
            "watchPatterns": ["API server", "aiohttp", "Listening", "Started", "error"]
        },
        "managedProcessStopPayload": {
            "action": "stop_all",
            "taskId": "hermes-api-server-daemon",
            "forget": false
        },
        "boundary": "This plan lets SynthChat's existing managed-process tool start the external Hermes Python gateway with API_SERVER_ENABLED=true. It is not an embedded Python api_server.py runtime and does not apply OS service-manager changes."
    })
}

