fn hermes_api_server_daemon_service_manager_plan() -> Value {
    json!({
        "schema": "hermes_api_server_daemon_service_manager_plan_desktop_v1",
        "serviceName": "hermes-gateway",
        "service_name": "hermes-gateway",
        "serviceManagerTarget": "gateway",
        "service_manager_target": "gateway",
        "apiServerEnabledByEnv": true,
        "api_server_enabled_by_env": true,
        "requiredEnv": ["API_SERVER_ENABLED=true"],
        "required_env": ["API_SERVER_ENABLED=true"],
        "optionalEnv": ["API_SERVER_HOST", "API_SERVER_PORT", "API_SERVER_KEY", "API_SERVER_CORS_ORIGINS", "API_SERVER_MODEL_NAME"],
        "optional_env": ["API_SERVER_HOST", "API_SERVER_PORT", "API_SERVER_KEY", "API_SERVER_CORS_ORIGINS", "API_SERVER_MODEL_NAME"],
        "commands": {
            "install": "API_SERVER_ENABLED=true hermes gateway install",
            "start": "hermes gateway start",
            "stop": "hermes gateway stop",
            "restart": "hermes gateway restart",
            "status": "hermes gateway status",
            "uninstall": "hermes gateway uninstall"
        },
        "windows": {
            "manager": "schtasks/startup-folder",
            "install": "$env:API_SERVER_ENABLED='true'; hermes gateway install",
            "start": "hermes gateway start",
            "status": "hermes gateway status"
        },
        "systemd": {
            "manager": "systemd",
            "userInstall": "API_SERVER_ENABLED=true hermes gateway install",
            "systemInstall": "sudo API_SERVER_ENABLED=true hermes gateway install --system",
            "status": "systemctl --user status hermes-gateway"
        },
        "launchd": {
            "manager": "launchd",
            "install": "API_SERVER_ENABLED=true hermes gateway install",
            "status": "launchctl list ai.hermes.gateway"
        },
        "s6": {
            "manager": "s6-overlay",
            "register": "API_SERVER_ENABLED=true hermes gateway install",
            "start": "s6-svc -u /run/service/gateway-default",
            "status": "s6-svstat /run/service/gateway-default"
        },
        "osServiceManagerApplied": false,
        "os_service_manager_applied": false,
        "boundary": "Hermes API server daemon runs inside the gateway process when API_SERVER_ENABLED=true; OS service-manager parity is therefore a gateway service install with API_SERVER_ENABLED in the service environment, not a separate api_server.py service registered by SynthChat."
    })
}

