pub(super) fn api_server_daemon_tool(payload: &Value) -> AppResult<String> {
    let action = payload
        .get("action")
        .or_else(|| payload.get("subcommand"))
        .or_else(|| payload.get("commandAction"))
        .and_then(Value::as_str)
        .unwrap_or("status")
        .trim()
        .to_ascii_lowercase()
        .replace('_', "-");
    if !matches!(
        action.as_str(),
        "status" | "plan" | "daemon" | "managed-process" | "run" | "start" | "stop" | "restart"
    ) {
        return Err(AppError::BadRequest(format!(
            "unsupported api_server_daemon action: {action}"
        )));
    }

    let execute_requested = payload
        .get("execute")
        .or_else(|| payload.get("live"))
        .or_else(|| payload.get("apply"))
        .and_then(Value::as_bool)
        .unwrap_or(false);
    let command_override = payload
        .get("apiServerCommand")
        .or_else(|| payload.get("api_server_command"))
        .or_else(|| payload.get("gatewayCommand"))
        .or_else(|| payload.get("gateway_command"))
        .or_else(|| payload.get("command"))
        .and_then(Value::as_str)
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(str::to_string);

    let mut managed_process_plan = hermes_api_server_daemon_managed_process_plan();
    let mut managed_process_plan_snake = hermes_api_server_daemon_managed_process_plan_snake();
    if let Some(command) = command_override {
        managed_process_plan["command"] = json!(command.clone());
        managed_process_plan["managedProcessStartPayload"]["command"] = json!(command.clone());
        managed_process_plan_snake["command"] = json!(command.clone());
        managed_process_plan_snake["managed_process_start_payload"]["command"] = json!(command);
    }
    let service_manager_plan = hermes_api_server_daemon_service_manager_plan();
    let service_manager_plan_snake = hermes_api_server_daemon_service_manager_plan_snake();
    let lifecycle = json!({
        "schema": "hermes_api_server_daemon_lifecycle_desktop_v1",
        "desktopAdaptation": true,
        "desktop_adaptation": true,
        "nativeHttpSurface": true,
        "native_http_surface": true,
        "nativeSseStreaming": true,
        "native_sse_streaming": true,
        "nativeRunLifecycle": true,
        "native_run_lifecycle": true,
        "nativeDashboardRoutes": true,
        "native_dashboard_routes": true,
        "pythonApiServerDaemonEmbedded": false,
        "python_api_server_daemon_embedded": false,
        "pythonDaemonProcessManaged": false,
        "python_daemon_process_managed": false,
        "managedProcessPlanReady": true,
        "managed_process_plan_ready": true,
        "serviceManagerPlanReady": true,
        "service_manager_plan_ready": true,
        "externalServiceManagerApplied": false,
        "external_service_manager_applied": false,
        "serviceInstallAppliesOsManager": false,
        "service_install_applies_os_manager": false,
        "statusSource": "api_server_daemon internal tool",
        "status_source": "api_server_daemon internal tool",
        "hermesReference": "gateway/platforms/api_server.py and hermes_cli gateway process with API_SERVER_ENABLED=true",
        "hermes_reference": "gateway/platforms/api_server.py and hermes_cli gateway process with API_SERVER_ENABLED=true",
    });
    let result = json!({
        "schema": "hermes_api_server_daemon_action_desktop_v1",
        "action": action,
        "status": if execute_requested { "managed_process_execution_requested" } else { "api_server_daemon_plan" },
        "executeRequested": execute_requested,
        "execute_requested": execute_requested,
        "lifecycle": lifecycle,
        "managedProcessPlan": managed_process_plan.clone(),
        "managed_process_plan": managed_process_plan_snake,
        "serviceManagerPlan": service_manager_plan,
        "service_manager_plan": service_manager_plan_snake,
        "boundary": "This action exposes the Hermes API server daemon launch/stop contract directly. Starting the external Hermes gateway process should go through the async managed-process path so approvals, logs, and stop controls remain visible; OS service-manager changes remain an operator-applied boundary."
    });
    serde_json::to_string_pretty(&result).map_err(AppError::from)
}

