pub(super) fn sms_client(settings: &SmsSettings) -> AppResult<reqwest::Client> {
    reqwest::Client::builder()
        .timeout(Duration::from_secs(settings.timeout_seconds))
        .user_agent("SynthChat-agent/1.0")
        .build()
        .map_err(|error| AppError::BadRequest(format!("failed to build SMS client: {error}")))
}

pub(super) fn sms_url(settings: &SmsSettings) -> AppResult<reqwest::Url> {
    reqwest::Url::parse(&format!(
        "{}/2010-04-01/Accounts/{}/Messages.json",
        settings.api_base_url, settings.account_sid
    ))
    .map_err(|error| AppError::BadRequest(format!("invalid SMS URL: {error}")))
}

async fn sms_request(
    client: &reqwest::Client,
    settings: &SmsSettings,
    to: &str,
    message: &str,
    media_urls: &[String],
) -> AppResult<Value> {
    let mut form = vec![
        ("From".to_string(), settings.from_number.clone()),
        ("To".to_string(), to.to_string()),
        ("Body".to_string(), message.to_string()),
    ];
    for media_url in media_urls {
        form.push(("MediaUrl".to_string(), media_url.to_string()));
    }
    let response = client
        .post(sms_url(settings)?)
        .basic_auth(&settings.account_sid, Some(&settings.auth_token))
        .form(&form)
        .send()
        .await
        .map_err(|error| AppError::BadRequest(format!("SMS send failed: {error}")))?;
    sms_response_json(response).await
}

fn sms_media_urls(payload: &Value) -> AppResult<Vec<String>> {
    let values = if let Some(values) = json_array_arg(
        payload,
        &["media_urls", "mediaUrls", "media_files", "mediaFiles"],
    ) {
        values
    } else if let Some(value) = payload.get("media_url").or_else(|| payload.get("mediaUrl")) {
        vec![value.clone()]
    } else {
        return Ok(Vec::new());
    };
    values
        .into_iter()
        .filter_map(|value| {
            let raw = value.as_str().map(str::to_string).or_else(|| {
                string_arg(
                    &value,
                    &["url", "media_url", "mediaUrl", "path", "file", "file_path"],
                )
            })?;
            let trimmed = raw.trim();
            if trimmed.is_empty() {
                None
            } else {
                Some(trimmed.to_string())
            }
        })
        .map(|url| {
            let parsed = reqwest::Url::parse(&url).map_err(|_| {
                AppError::BadRequest(
                    "SMS media_urls entries must be public http(s) URLs for Twilio MediaUrl".into(),
                )
            })?;
            if !matches!(parsed.scheme(), "http" | "https") {
                return Err(AppError::BadRequest(
                    "SMS media_urls entries must be public http(s) URLs for Twilio MediaUrl".into(),
                ));
            }
            Ok(url)
        })
        .collect()
}

async fn sms_response_json(response: reqwest::Response) -> AppResult<Value> {
    let status = response.status();
    let text = response
        .text()
        .await
        .map_err(|error| AppError::BadRequest(format!("failed to read SMS response: {error}")))?;
    let value = serde_json::from_str::<Value>(&text)
        .map_err(|error| AppError::BadRequest(format!("invalid SMS JSON: {error}")))?;
    if !status.is_success() {
        let message = value
            .get("message")
            .and_then(Value::as_str)
            .unwrap_or(&text);
        return Err(AppError::BadRequest(format!(
            "Twilio API error ({}): {}",
            status.as_u16(),
            truncate_output(message, 2000)
        )));
    }
    Ok(value)
}

pub(super) fn sms_strip_markdown(message: &str) -> String {
    let mut text = message.replace("```", "");
    text = text.replace("**", "");
    text = text.replace("__", "");
    text = text.replace('*', "");
    text = text.replace('_', "");
    let mut output = String::new();
    let mut in_inline_code = false;
    for ch in text.chars() {
        if ch == '`' {
            in_inline_code = !in_inline_code;
            continue;
        }
        output.push(ch);
    }
    let output = sms_strip_markdown_links(&output);
    let mut compact = String::new();
    let mut blank_lines = 0usize;
    for line in output.lines() {
        if line.trim().is_empty() {
            blank_lines += 1;
            if blank_lines <= 2 {
                compact.push('\n');
            }
            continue;
        }
        blank_lines = 0;
        compact.push_str(line);
        compact.push('\n');
    }
    compact
        .lines()
        .map(|line| line.trim_start_matches('#').trim_start())
        .collect::<Vec<_>>()
        .join("\n")
        .trim()
        .to_string()
}

fn sms_strip_markdown_links(message: &str) -> String {
    let chars = message.chars().collect::<Vec<_>>();
    let mut output = String::new();
    let mut index = 0usize;
    while index < chars.len() {
        if chars[index] == '[' {
            if let Some(close) = chars[index + 1..].iter().position(|ch| *ch == ']') {
                let close = index + 1 + close;
                if chars.get(close + 1) == Some(&'(') {
                    if let Some(end) = chars[close + 2..].iter().position(|ch| *ch == ')') {
                        output.extend(chars[index + 1..close].iter());
                        index = close + 2 + end + 1;
                        continue;
                    }
                }
            }
        }
        output.push(chars[index]);
        index += 1;
    }
    output
}

