fn email_send_smtp(
    settings: &EmailSettings,
    to: &str,
    subject: &str,
    body: &str,
    media_files: &[String],
) -> AppResult<()> {
    let message = email_build_message(settings, to, subject, body, media_files)?;
    let credentials = Credentials::new(settings.address.clone(), settings.password.clone());
    let mailer = SmtpTransport::starttls_relay(&settings.smtp_host)
        .map_err(|error| AppError::BadRequest(format!("failed to configure SMTP relay: {error}")))?
        .port(settings.smtp_port)
        .credentials(credentials)
        .timeout(Some(Duration::from_secs(settings.timeout_seconds)))
        .build();
    mailer
        .send(&message)
        .map_err(|error| AppError::BadRequest(format!("Email send failed: {error}")))?;
    Ok(())
}

pub(super) fn email_build_message(
    settings: &EmailSettings,
    to: &str,
    subject: &str,
    body: &str,
    media_files: &[String],
) -> AppResult<Message> {
    let from_mailbox = settings
        .address
        .parse::<Mailbox>()
        .map_err(|error| AppError::BadRequest(format!("invalid Email from address: {error}")))?;
    let to_mailbox = to.parse::<Mailbox>().map_err(|error| {
        AppError::BadRequest(format!("invalid Email recipient address: {error}"))
    })?;
    let builder = Message::builder()
        .from(from_mailbox)
        .to(to_mailbox)
        .subject(subject);
    if media_files.is_empty() {
        return builder.body(body.to_string()).map_err(|error| {
            AppError::BadRequest(format!("failed to build Email message: {error}"))
        });
    }
    let mut multipart = MultiPart::mixed().singlepart(SinglePart::plain(body.to_string()));
    for file_path in media_files {
        let bytes = fs::read(file_path).map_err(|error| {
            AppError::BadRequest(format!(
                "failed to read Email media file {file_path}: {error}"
            ))
        })?;
        let file_name = Path::new(file_path)
            .file_name()
            .and_then(|value| value.to_str())
            .filter(|value| !value.trim().is_empty())
            .unwrap_or("attachment")
            .to_string();
        let content_type = email_attachment_content_type(file_path)?;
        multipart = multipart.singlepart(Attachment::new(file_name).body(bytes, content_type));
    }
    builder
        .multipart(multipart)
        .map_err(|error| AppError::BadRequest(format!("failed to build Email message: {error}")))
}

fn email_media_file_paths(payload: &Value) -> AppResult<Vec<String>> {
    platform_media_file_paths(payload, "Email")
}

fn email_attachment_content_type(file_path: &str) -> AppResult<ContentType> {
    let mime = match Path::new(file_path)
        .extension()
        .and_then(|value| value.to_str())
        .unwrap_or_default()
        .to_ascii_lowercase()
        .as_str()
    {
        "txt" | "log" | "md" => "text/plain",
        "html" | "htm" => "text/html",
        "json" => "application/json",
        "csv" => "text/csv",
        "pdf" => "application/pdf",
        "png" => "image/png",
        "jpg" | "jpeg" => "image/jpeg",
        "gif" => "image/gif",
        "webp" => "image/webp",
        "mp3" => "audio/mpeg",
        "wav" => "audio/wav",
        "mp4" => "video/mp4",
        "zip" => "application/zip",
        _ => "application/octet-stream",
    };
    ContentType::parse(mime).map_err(|error| {
        AppError::BadRequest(format!(
            "invalid Email attachment content type {mime}: {error}"
        ))
    })
}

